INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('an-giang', 'mekong-delta', 'An Giang', 'An Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.1802, 10.5135, 'Miền đất Bảy Núi linh thiêng với rừng tràm Trà Sư, miếu Bà Chúa Xứ và mùa nước nổi trù phú.', 'An Giang là vùng đất đầu nguồn sông Cửu Long, nơi có vùng Bảy Núi (Thất Sơn) huyền bí và những cánh đồng lúa bát ngát. Rừng tràm Trà Sư xanh mướt mùa nước nổi, miếu Bà Chúa Xứ Núi Sam linh thiêng thu hút hàng triệu khách hành hương. Đây cũng là nơi giao thoa văn hóa của người Kinh, Khmer, Chăm và Hoa, tạo nên bản sắc đa dạng và những lễ hội đặc sắc.', 'Tháng 9–11, mùa nước nổi', '["Bún cá Châu Đốc","Mắm Châu Đốc","Bò bảy món Núi Sam","Đường thốt nốt","Bánh bò thốt nốt"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ba-ria-vung-tau', 'southeast', 'Bà Rịa - Vũng Tàu', 'Ba Ria - Vung Tau', 'Đông Nam Bộ', '#b07a4a', 107.2803, 10.5857, 'Tỉnh ven biển miền Đông với thành phố biển Vũng Tàu sầm uất và quần đảo Côn Đảo hoang sơ huyền thoại.', 'Bà Rịa – Vũng Tàu là cửa ngõ biển của miền Đông Nam Bộ, nơi thành phố Vũng Tàu hào sảng đón du khách bằng những bãi tắm dài, hải sản tươi ngon và tượng Chúa Kitô sừng sững trên núi. Ngoài khơi, quần đảo Côn Đảo vừa thiêng liêng với di tích lịch sử, vừa nguyên sơ với biển xanh và rùa biển. Đây là vùng đất của biển cả, dầu khí và những chuyến nghỉ dưỡng cuối tuần thân quen của người phương Nam.', 'Tháng 11 đến tháng 4 (mùa khô, biển êm)', '["Bánh khọt Vũng Tàu","Hải sản tươi sống","Mứt hạt bàng Côn Đảo"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('bac-giang', 'northeast', 'Bắc Giang', 'Bac Giang', 'Đông Bắc', '#4f7b6a', 106.4785, 21.3589, 'Vùng đất giàu di sản tâm linh với Tây Yên Tử, chùa Vĩnh Nghiêm chốn tổ Trúc Lâm và những vườn vải thiều Lục Ngạn trứ danh.', 'Bắc Giang là tỉnh trung du Đông Bắc giàu giá trị lịch sử và tâm linh. Nơi đây có Khu du lịch Tây Yên Tử gắn với con đường hoằng dương Phật pháp của Phật hoàng Trần Nhân Tông, chùa Vĩnh Nghiêm chốn tổ Thiền phái Trúc Lâm lưu giữ mộc bản được UNESCO ghi danh. Bắc Giang còn nổi tiếng với vải thiều Lục Ngạn ngọt lịm, những vườn cây trĩu quả và các lễ hội truyền thống đặc sắc, là điểm đến của hành trình về nguồn cội văn hóa.', 'Tháng 1 đến tháng 3 âm lịch', '["Vải thiều Lục Ngạn","Mỳ Chũ","Bánh đa Kế","Rượu làng Vân"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('bac-kan', 'northeast', 'Bắc Kạn', 'Bac Kan', 'Đông Bắc', '#4f7b6a', 105.825, 22.2621, 'Tỉnh núi rừng yên bình với Hồ Ba Bể - hồ nước ngọt tự nhiên lớn nhất Việt Nam và Vườn quốc gia nguyên sinh.', 'Bắc Kạn là tỉnh miền núi Đông Bắc nổi bật với Hồ Ba Bể - viên ngọc xanh giữa đại ngàn và là hồ nước ngọt tự nhiên trên núi lớn nhất nước. Vườn quốc gia Ba Bể với rừng nguyên sinh, hang động, thác nước cùng văn hóa người Tày tạo nên điểm đến sinh thái hấp dẫn. Đến Bắc Kạn, du khách được hòa mình vào thiên nhiên trong lành, ngồi thuyền độc mộc và trải nghiệm cuộc sống bản làng bình dị.', 'Tháng 4 đến tháng 11', '["Cá nướng Ba Bể","Tôm chua","Bánh trứng kiến","Miến dong Bắc Kạn"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('bac-lieu', 'mekong-delta', 'Bạc Liêu', 'Bac Lieu', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.4876, 9.3129, 'Quê hương bản Dạ cổ hoài lang và giai thoại Công tử Bạc Liêu, với cánh đồng điện gió ven biển độc đáo.', 'Bạc Liêu là vùng đất ven biển giàu bản sắc văn hóa, được biết đến là cái nôi của bản Dạ cổ hoài lang, khởi nguồn của nghệ thuật đờn ca tài tử và cải lương Nam Bộ. Tỉnh gắn liền với giai thoại nổi tiếng về Công tử Bạc Liêu ăn chơi khét tiếng một thời, cùng dinh thự cổ tráng lệ còn lưu giữ. Bạc Liêu ngày nay còn nổi bật với cánh đồng điện gió ven biển hùng vĩ, biểu tượng cho năng lượng xanh. Đến đây, du khách được hòa mình vào không gian văn hóa nghệ thuật và vẻ đẹp hiện đại đan xen truyền thống.', 'Tháng 11 đến tháng 4, mùa khô trời trong gió đẹp', '["Bún bò cay","Bánh tằm Ngan Dừa","Ba khía muối","Nhãn Bạc Liêu"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('bac-ninh', 'red-river-delta', 'Bắc Ninh', 'Bac Ninh', 'Đồng bằng sông Hồng', '#c7993f', 106.1056, 21.1104, 'Cái nôi của dân ca quan họ và vương triều Lý, vùng đất Kinh Bắc giàu di sản văn hóa và làng nghề.', 'Bắc Ninh là vùng đất Kinh Bắc địa linh nhân kiệt, quê hương của những làn điệu quan họ ngọt ngào đã được UNESCO ghi danh. Đây cũng là đất phát tích vương triều Lý với Đền Đô uy nghi thờ tám đời vua. Bắc Ninh còn nổi danh với những làng nghề truyền thống như tranh Đông Hồ, gốm Phù Lãng, đúc đồng Đại Bái. Về Bắc Ninh, du khách được đắm mình trong không gian văn hóa đậm đà bản sắc và nghe các liền anh liền chị say sưa hát canh.', 'Tháng 1 đến tháng 4 (mùa lễ hội)', '["Bánh phu thê Đình Bảng","Tranh Đông Hồ","Nem Bùi","Dân ca quan họ"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ben-tre', 'mekong-delta', 'Bến Tre', 'Ben Tre', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.4676, 10.1203, 'Xứ dừa của miền Tây với những cù lao xanh mát, làng nghề thủ công từ dừa và đặc sản kẹo dừa nức tiếng.', 'Bến Tre được mệnh danh là xứ dừa, nơi những rặng dừa xanh trải dài bất tận trên ba cù lao lớn giữa các nhánh sông Tiền. Cây dừa gắn bó mật thiết với đời sống người dân, từ nước dừa, kẹo dừa đến đồ thủ công mỹ nghệ tinh xảo làm từ thân, lá và xơ dừa. Du khách đến Bến Tre để đi xuồng qua rạch dừa nước, thăm các lò kẹo dừa thơm lừng và cảm nhận hồn quê mộc mạc, nghĩa tình của vùng đất ba dải cù lao Bảo, Minh và An Hóa.', 'Tháng 11 đến tháng 4, mùa khô mát mẻ', '["Kẹo dừa Bến Tre","Bánh tráng Mỹ Lồng","Bánh phồng Sơn Đốc","Đuông dừa"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('binh-dinh', 'south-central-coast', 'Bình Định', 'Binh Dinh', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.947, 14.1238, 'Đất võ trời văn với biển Quy Nhơn tuyệt đẹp, những tháp Chăm cổ kính và tinh thần thượng võ Tây Sơn.', 'Bình Định là vùng đất giàu truyền thống thượng võ, quê hương của người anh hùng áo vải Quang Trung - Nguyễn Huệ. Tỉnh sở hữu bờ biển Quy Nhơn quyến rũ với Kỳ Co, Eo Gió và hệ thống tháp Chăm cổ kính như Bánh Ít, Dương Long. Nơi đây còn nổi tiếng với hát bội, võ cổ truyền Tây Sơn và ẩm thực phong phú, đậm đà hương vị xứ Nẫu.', 'Tháng 3 đến tháng 9', '["Bánh ít lá gai","Bún chả cá Quy Nhơn","Nem chợ Huyện","Rượu Bàu Đá","Bánh hỏi cháo lòng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('binh-duong', 'southeast', 'Bình Dương', 'Binh Duong', 'Đông Nam Bộ', '#b07a4a', 106.6563, 11.2181, 'Thủ phủ công nghiệp miền Đông với lễ hội chùa Bà Thiên Hậu sôi động và khu du lịch Đại Nam khổng lồ.', 'Bình Dương là một trong những trung tâm công nghiệp và đô thị phát triển nhanh nhất Việt Nam, nhưng vẫn đậm chất văn hóa truyền thống. Thủ Dầu Một nổi tiếng với nghề gốm sứ, sơn mài lâu đời và miếu Bà Thiên Hậu, nơi diễn ra lễ rước kiệu rằm tháng Giêng tưng bừng nhất miền Đông. Khu du lịch Đại Nam quy mô khổng lồ là điểm vui chơi giải trí gia đình hấp dẫn, hòa quyện giữa tâm linh, thiên nhiên và giải trí hiện đại.', 'Tháng 11 đến tháng 4 (mùa khô) và rằm tháng Giêng', '["Gốm sứ Lái Thiêu","Sơn mài truyền thống","Trái cây Lái Thiêu"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('binh-phuoc', 'southeast', 'Bình Phước', 'Binh Phuoc', 'Đông Nam Bộ', '#b07a4a', 106.9061, 11.7562, 'Tỉnh biên giới với rừng nguyên sinh Bù Gia Mập, những trảng cỏ kỳ thú và văn hóa S''tiêng, M''nông đậm đà.', 'Bình Phước nằm ở vùng biên giới Tây Nam, là cửa ngõ nối Đông Nam Bộ với Tây Nguyên và Campuchia. Đây là xứ sở của những đồi điều, vườn tiêu bạt ngàn và những cánh rừng nguyên sinh quý giá như Bù Gia Mập. Thiên nhiên hoang sơ với trảng cỏ Bù Lạch, thác ghềnh, suối rừng cùng đời sống văn hóa cồng chiêng của đồng bào S''tiêng, M''nông tạo nên bản sắc riêng cho vùng đất biên cương trầm mặc mà cuốn hút này.', 'Tháng 11 đến tháng 4 (mùa khô)', '["Hạt điều rang muối","Tiêu Lộc Ninh","Cơm lam, rượu cần S''tiêng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('binh-thuan', 'south-central-coast', 'Bình Thuận', 'Binh Thuan', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.0446, 11.12, 'Xứ sở nắng gió với đồi cát Mũi Né, biển xanh và những làng chài đậm chất Nam Trung Bộ.', 'Bình Thuận là vùng đất của nắng, gió và biển xanh. Mũi Né nổi tiếng với những đồi cát vàng, cát đỏ uốn lượn như sa mạc, cùng làng chài Mũi Né đầy sắc màu và bãi biển trải dài. Đây là thiên đường của các môn thể thao biển như lướt ván diều. Bình Thuận còn có tháp Chăm Po Sah Inư cổ kính và đặc sản hải sản tươi ngon, nước mắm Phan Thiết trứ danh.', 'Tháng 11–4, mùa khô ít mưa', '["Nước mắm Phan Thiết","Bánh canh chả cá","Gỏi cá mai","Mực một nắng","Thanh long"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ca-mau', 'mekong-delta', 'Cà Mau', 'Ca Mau', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.0388, 9.0515, 'Vùng đất cực Nam thiêng liêng của Tổ quốc với rừng ngập mặn bạt ngàn, hải sản trù phú và đời sống sông nước mộc mạc.', 'Cà Mau là tỉnh cực Nam của Tổ quốc, vùng đất ba mặt giáp biển với hệ sinh thái rừng ngập mặn và rừng tràm độc đáo bậc nhất Việt Nam. Mũi Cà Mau thiêng liêng, vườn quốc gia U Minh Hạ và những cánh rừng đước, rừng mắm xanh thẳm tạo nên cảnh quan hoang sơ kỳ vĩ, được công nhận là khu dự trữ sinh quyển thế giới. Đất Mũi trù phú với cua, ba khía, tôm cá tươi rói cùng mật ong rừng U Minh nức tiếng. Con người Cà Mau chân chất, phóng khoáng, gắn bó với rừng, với biển nơi chót cùng đất nước.', 'Tháng 12 đến tháng 4, mùa khô biển êm thuận tiện đi lại', '["Cua Cà Mau","Ba khía muối","Mật ong rừng U Minh","Cá thòi lòi","Tôm khô Rạch Gốc"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('can-tho', 'mekong-delta', 'Cần Thơ', 'Can Tho', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.5284, 10.1156, 'Thủ phủ miền Tây sông nước với chợ nổi Cái Răng, vườn trái cây trĩu quả và nhịp sống miệt vườn.', 'Cần Thơ — ''Tây Đô'' của Đồng bằng sông Cửu Long — là nơi nhịp sống sông nước hiện lên rõ nét nhất. Chợ nổi Cái Răng nhộn nhịp từ tinh mơ, bến Ninh Kiều thơ mộng bên dòng sông Hậu, những vườn trái cây trĩu quả và nhà cổ Bình Thủy trăm tuổi. Người miền Tây phóng khoáng, hiếu khách, đờn ca tài tử ngọt ngào trong đêm — tất cả tạo nên một Cần Thơ trù phú và đậm tình.', 'Quanh năm; mùa nước nổi tháng 9–11 đẹp nhất', '["Bánh xèo","Lẩu mắm","Bánh cống","Nem nướng Cái Răng","Trái cây miệt vườn"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('cao-bang', 'northeast', 'Cao Bằng', 'Cao Bang', 'Đông Bắc', '#4f7b6a', 106.0851, 22.7465, 'Vùng non nước biên cương với công viên địa chất toàn cầu, thác hùng vĩ, hang động kỳ ảo và bản làng Tày, Nùng.', 'Cao Bằng là miền đất địa đầu Tổ quốc nổi tiếng với Công viên địa chất toàn cầu UNESCO Non nước Cao Bằng. Nơi đây có Thác Bản Giốc hùng vĩ bậc nhất Đông Nam Á, Động Ngườm Ngao huyền bí cùng vô số núi đá vôi, hồ nước và bản làng dân tộc Tày, Nùng yên bình. Cao Bằng còn là cái nôi cách mạng với di tích Pác Bó lịch sử, mảnh đất giàu bản sắc văn hóa và cảnh quan thiên nhiên tươi đẹp.', 'Tháng 9 đến tháng 10', '["Bánh cuốn Cao Bằng","Hạt dẻ Trùng Khánh","Vịt quay 7 vị","Bánh khảo"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('da-nang', 'south-central-coast', 'Đà Nẵng', 'Da Nang', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.0578, 16.0683, 'Thành phố biển đáng sống với bãi Mỹ Khê, bán đảo Sơn Trà và Bà Nà Hills trên mây.', 'Đà Nẵng năng động và hiện đại, nhưng vẫn giữ được sự thư thái của một thành phố biển. Bãi biển Mỹ Khê trải dài cát trắng, cầu Rồng phun lửa cuối tuần, và Bà Nà Hills với Cầu Vàng nổi tiếng thế giới. Đây là điểm trung chuyển lý tưởng để khám phá miền Trung.', 'Tháng 3–8, biển đẹp và ít mưa', '["Mì Quảng","Bánh tráng cuốn thịt heo","Bún chả cá","Hải sản"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('dak-lak', 'central-highlands', 'Đắk Lắk', 'Dak Lak', 'Tây Nguyên', '#8a6e4b', 108.206, 12.826, 'Thủ phủ cà phê Tây Nguyên với những buôn làng, thác nước hùng vĩ và văn hóa cồng chiêng.', 'Đắk Lắk là trái tim của vùng đất đỏ bazan Tây Nguyên, thủ phủ cà phê của Việt Nam. Những đồi cà phê bạt ngàn, thác nước Dray Nur, Dray Sáp hùng vĩ, buôn làng Ê Đê, M''Nông với nhà sàn dài và tiếng cồng chiêng vang vọng. Đến với Buôn Ma Thuột và Buôn Đôn, bạn sẽ được sống trong không gian văn hóa cồng chiêng — Di sản của nhân loại — và cảm nhận sự hào sảng của con người đại ngàn.', 'Tháng 11–4, mùa khô Tây Nguyên', '["Cà phê Buôn Ma Thuột","Bún đỏ","Gà nướng cơm lam","Rượu cần","Bơ sáp"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('dak-nong', 'central-highlands', 'Đắk Nông', 'Dak Nong', 'Tây Nguyên', '#8a6e4b', 107.6861, 12.2292, 'Vùng đất công viên địa chất toàn cầu UNESCO với hang động núi lửa, thác nước hùng vĩ và rừng nguyên sinh.', 'Đắk Nông là tỉnh phía nam Tây Nguyên, tự hào sở hữu Công viên địa chất toàn cầu UNESCO với hệ thống hang động núi lửa dài nhất Đông Nam Á. Vùng đất đỏ bazan này có nhiều thác nước hùng vĩ như Dray Sáp, Gia Long, cùng những hồ nước trong xanh và cánh rừng nguyên sinh trù phú. Nơi đây còn lưu giữ kho tàng văn hóa đặc sắc của đồng bào M''Nông, Mạ với cồng chiêng, sử thi và nghề dệt thổ cẩm truyền thống.', 'Tháng 11 đến tháng 4', '["Cà phê Đắk Nông","Hồ tiêu","Bơ sáp","Cơm lam","Rượu cần M''Nông"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('dien-bien', 'northwest', 'Điện Biên', 'Dien Bien', 'Tây Bắc', '#6e8c5a', 103.0216, 21.7106, 'Vùng đất lịch sử Tây Bắc với chiến trường Điện Biên Phủ lừng lẫy và cảnh sắc núi rừng hùng vĩ.', 'Điện Biên là vùng đất ghi dấu chiến thắng Điện Biên Phủ ''lừng lẫy năm châu, chấn động địa cầu'' năm 1954. Quần thể di tích chiến trường xưa — Đồi A1, Hầm De Castries, Bảo tàng Chiến thắng — là điểm đến thiêng liêng. Bên cạnh đó, Điện Biên còn có cánh đồng Mường Thanh rộng lớn, đèo Pha Đin hùng vĩ và sắc màu văn hóa của người Thái, Mông giữa núi rừng Tây Bắc.', 'Tháng 3–5; dịp 7/5 lễ kỷ niệm chiến thắng', '["Xôi nếp nương","Gạo Điện Biên","Pa pỉnh tộp (cá nướng)","Thịt trâu gác bếp","Rượu sâu chít"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('dong-nai', 'southeast', 'Đồng Nai', 'Dong Nai', 'Đông Nam Bộ', '#b07a4a', 107.1829, 11.0581, 'Vùng đất công nghiệp năng động bên sông Đồng Nai, ẩn chứa rừng quốc gia Cát Tiên và những thác nước sinh thái xanh mát.', 'Đồng Nai là tỉnh công nghiệp sầm uất bậc nhất phía Nam, nhưng vẫn giữ được những mảng xanh quý giá. Vườn quốc gia Cát Tiên với rừng nguyên sinh và khu dự trữ sinh quyển là điểm đến hàng đầu cho người yêu thiên nhiên. Bên cạnh đó, những thác nước như Giang Điền, các khu du lịch sinh thái và dòng sông Đồng Nai hiền hòa tạo nên không gian dã ngoại lý tưởng cho người dân Sài Gòn mỗi dịp cuối tuần.', 'Tháng 12 đến tháng 5 (mùa khô)', '["Bưởi Tân Triều","Chôm chôm Long Khánh","Gỏi cá Biên Hòa"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('dong-thap', 'mekong-delta', 'Đồng Tháp', 'Dong Thap', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.6062, 10.5656, 'Đất sen hồng của miền Tây với vườn quốc gia Tràm Chim, làng hoa Sa Đéc rực rỡ và những cánh đồng sen bát ngát.', 'Đồng Tháp được mệnh danh là đất sen hồng, vùng đất thuần khiết với những cánh đồng sen bát ngát và hệ sinh thái Đồng Tháp Mười nổi tiếng. Tỉnh sở hữu vườn quốc gia Tràm Chim, ngôi nhà của sếu đầu đỏ quý hiếm, cùng làng hoa Sa Đéc trăm năm tuổi rực rỡ sắc màu. Con người Đồng Tháp chân chất, nghĩa tình, gắn bó với ruộng đồng và hoa sen. Đến đây, du khách được hòa mình vào thiên nhiên trong lành, thưởng thức ẩm thực từ sen và cảm nhận vẻ đẹp bình yên của miền sông nước.', 'Tháng 9 đến tháng 11 mùa nước nổi, hoặc tháng 12-4 mùa sếu về', '["Hủ tiếu Sa Đéc","Các món từ sen","Nem Lai Vung","Quýt hồng Lai Vung","Khô cá lóc"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('gia-lai', 'central-highlands', 'Gia Lai', 'Gia Lai', 'Tây Nguyên', '#8a6e4b', 108.2393, 13.7988, 'Cao nguyên đại ngàn với Biển Hồ T''Nưng xanh thẳm, đồi chè, thác nước và không gian văn hóa cồng chiêng.', 'Gia Lai là vùng cao nguyên bazan màu mỡ giữa Tây Nguyên, nổi tiếng với Biển Hồ T''Nưng được ví như đôi mắt Pleiku, những đồi chè, đồi cà phê bạt ngàn và các con thác hùng vĩ. Tỉnh là cái nôi của Không gian văn hóa cồng chiêng - di sản thế giới, với đời sống tinh thần phong phú của người Gia Rai, Ba Na. Cảnh sắc thiên nhiên trù phú cùng cà phê thơm ngon là niềm tự hào của phố núi Pleiku.', 'Tháng 11 đến tháng 4', '["Phở khô Gia Lai","Bún mắm cua","Cà phê Pleiku","Muối kiến vàng","Bò một nắng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ha-giang', 'northeast', 'Hà Giang', 'Ha Giang', 'Đông Bắc', '#4f7b6a', 104.9753, 22.7658, 'Vùng địa đầu Tổ quốc với cao nguyên đá hùng vĩ, những cung đèo huyền thoại và sắc màu văn hóa vùng cao.', 'Hà Giang là nơi đất trời gặp nhau ở tận cùng phía Bắc. Cao nguyên đá Đồng Văn — công viên địa chất toàn cầu — trải dài những dãy núi tai mèo trùng điệp. Mùa thu, hoa tam giác mạch phủ hồng các triền đồi; mùa lúa chín, ruộng bậc thang vàng rực. Đây là vùng đất của những con đường đẹp đến nghẹt thở và những con người mộc mạc, hiếu khách.', 'Tháng 9 (lúa chín) và tháng 10–12 (hoa tam giác mạch)', '["Thắng cố","Cháo ấu tẩu","Rượu ngô","Bánh tam giác mạch"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ha-nam', 'red-river-delta', 'Hà Nam', 'Ha Nam', 'Đồng bằng sông Hồng', '#c7993f', 105.965, 20.5424, 'Vùng đất tâm linh với chùa Tam Chúc kỳ vĩ, non nước hữu tình và những làng nghề truyền thống lâu đời.', 'Hà Nam là cửa ngõ phía nam đồng bằng Bắc Bộ, vùng đất của núi non, sông nước và những công trình tâm linh đồ sộ. Nổi bật nhất là quần thể chùa Tam Chúc được mệnh danh ngôi chùa lớn nhất thế giới, tựa lưng vào núi mặt hướng ra hồ mênh mông. Hà Nam còn có những làng nghề trống Đọi Tam, lụa Nha Xá và đặc sản cá kho làng Vũ Đại nức tiếng. Phong cảnh hữu tình hòa quyện với chiều sâu văn hóa khiến Hà Nam ngày càng hấp dẫn du khách hành hương.', 'Tháng 1 đến tháng 3 (mùa lễ hội)', '["Cá kho làng Vũ Đại","Bánh cuốn Phủ Lý","Chuối ngự Đại Hoàng","Trống Đọi Tam"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ha-noi', 'red-river-delta', 'Hà Nội', 'Hanoi', 'Đồng bằng sông Hồng', '#c7993f', 105.6994, 20.9988, 'Thủ đô ngàn năm văn hiến, nơi giao thoa giữa nét cổ kính và nhịp sống hiện đại.', 'Hà Nội là nơi thời gian như chậm lại. Phố cổ rêu phong, hồ Hoàn Kiếm thơ mộng, những hàng cây cổ thụ và mùi hương hoa sữa mỗi độ thu về. Ẩm thực Hà Nội tinh tế với phở, bún chả, cà phê trứng. Mỗi góc phố đều có một câu chuyện đáng để lắng nghe.', 'Mùa thu (tháng 9–11), tiết trời mát dịu', '["Phở","Bún chả","Cà phê trứng","Bánh cuốn","Chả cá Lã Vọng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ha-tinh', 'north-central-coast', 'Hà Tĩnh', 'Ha Tinh', 'Bắc Trung Bộ', '#5a8aa6', 105.735, 18.2917, 'Miền quê núi Hồng sông La, nơi giao hòa giữa danh lam cổ tự, biển hoang sơ và những trang sử bi tráng.', 'Hà Tĩnh là dải đất hẹp miền Trung gắn liền với núi Hồng Lĩnh và dòng sông La thơ mộng. Vùng đất hiếu học này tự hào với chùa Hương Tích linh thiêng, bãi biển Thiên Cầm êm đềm và ngã ba Đồng Lộc thấm đẫm những trang sử bi hùng. Người Hà Tĩnh chân chất, mến khách, gìn giữ kho tàng dân ca ví giặm được UNESCO vinh danh, làm say lòng bao du khách phương xa.', 'Tháng 4 đến tháng 8', '["Kẹo cu đơ","Bưởi Phúc Trạch","Mực một nắng Thiên Cầm","Bánh đa vừng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('hai-duong', 'red-river-delta', 'Hải Dương', 'Hai Duong', 'Đồng bằng sông Hồng', '#c7993f', 106.3572, 20.9298, 'Xứ Đông với quần thể Côn Sơn - Kiếp Bạc linh thiêng, đảo cò sinh thái và đặc sản bánh đậu xanh trứ danh.', 'Hải Dương là vùng đất xứ Đông giàu truyền thống lịch sử và văn hóa, nơi lưu dấu hai vị anh hùng Trần Hưng Đạo và Nguyễn Trãi qua quần thể Côn Sơn - Kiếp Bạc. Vùng đất này còn có Đảo Cò Chi Lăng Nam, điểm sinh thái độc đáo giữa đồng bằng. Hải Dương nổi tiếng với bánh đậu xanh thơm bùi, vải thiều Thanh Hà ngọt lịm và bánh gai Ninh Giang dẻo thơm. Sự kết hợp giữa di sản tâm linh, thiên nhiên trong lành và ẩm thực đặc sắc làm nên sức hút riêng của vùng quê này.', 'Tháng 1 đến tháng 4', '["Bánh đậu xanh","Vải thiều Thanh Hà","Bánh gai Ninh Giang","Bánh đa Kẻ Sặt"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('hai-phong', 'red-river-delta', 'Hải Phòng', 'Hai Phong', 'Đồng bằng sông Hồng', '#c7993f', 106.6156, 20.8033, 'Thành phố cảng năng động với đảo Cát Bà, vịnh Lan Hạ và những bãi biển truyền thống bên hoa phượng đỏ.', 'Hải Phòng là thành phố hoa phượng đỏ, cửa ngõ ra biển lớn của miền Bắc với cảng biển sầm uất bậc nhất cả nước. Nơi đây hội tụ vẻ đẹp của biển đảo Cát Bà, vịnh Lan Hạ thơ mộng cùng những bãi tắm Đồ Sơn quen thuộc. Ẩm thực đường phố Hải Phòng nức tiếng với bánh đa cua, bánh mì cay, nem cua bể khiến thực khách say lòng. Người dân đất Cảng phóng khoáng, mến khách, tạo nên nét duyên riêng cho thành phố biển sôi động này.', 'Tháng 4 đến tháng 9', '["Bánh đa cua","Bánh mì cay","Nem cua bể","Hải sản Cát Bà"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('hau-giang', 'mekong-delta', 'Hậu Giang', 'Hau Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.6223, 9.7849, 'Vùng đất sông nước trù phú với chợ nổi Ngã Bảy huyền thoại, khu bảo tồn Lung Ngọc Hoàng và những vườn cây xanh mát.', 'Hậu Giang là tỉnh nằm ở trung tâm vùng Tây sông Hậu, mang đậm nét đẹp sông nước miệt vườn đồng bằng. Nơi đây có chợ nổi Ngã Bảy huyền thoại đi vào câu vọng cổ, khu bảo tồn thiên nhiên Lung Ngọc Hoàng được ví như lá phổi xanh và những vườn khóm, vườn cây trái xanh ngút ngàn. Người dân Hậu Giang phóng khoáng, nghĩa tình, gắn bó với nghề nông và sông nước. Đến Hậu Giang, du khách được trải nghiệm văn hóa thương hồ, ẩm thực đồng quê và vẻ đẹp yên bình của vùng đất phương Nam.', 'Tháng 11 đến tháng 4, mùa khô thuận tiện du lịch', '["Khóm Cầu Đúc","Cá thát lát Hậu Giang","Bưởi Năm Roi Phú Hữu","Đọt choại"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ho-chi-minh', 'southeast', 'TP. Hồ Chí Minh', 'Ho Chi Minh City', 'Đông Nam Bộ', '#b07a4a', 106.6954, 10.7405, 'Đầu tàu kinh tế sôi động, hào sảng và không bao giờ ngủ — nơi cũ và mới đan xen.', 'Sài Gòn — TP. Hồ Chí Minh là thành phố của năng lượng. Từ những tòa nhà chọc trời đến con hẻm nhỏ thơm mùi cà phê, từ chợ Bến Thành nhộn nhịp đến những quán ăn vỉa hè hấp dẫn. Người Sài Gòn phóng khoáng, hiếu khách. Đây là nơi mọi ước mơ đều có chỗ đứng.', 'Mùa khô tháng 12–4', '["Cơm tấm","Hủ tiếu","Bánh mì","Phá lấu","Cà phê sữa đá"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('hoa-binh', 'northwest', 'Hòa Bình', 'Hoa Binh', 'Tây Bắc', '#6e8c5a', 105.3417, 20.6856, 'Cửa ngõ Tây Bắc với thung lũng Mai Châu thơ mộng, hồ Hòa Bình kỳ vĩ và cái nôi của nền Văn hóa Hòa Bình cổ.', 'Hòa Bình là cửa ngõ vùng Tây Bắc, quê hương của đồng bào Mường cùng nền Văn hóa Hòa Bình nổi tiếng trong khảo cổ học. Nơi đây có thung lũng Mai Châu thanh bình với bản làng người Thái, nhà sàn và điệu xòe say đắm; hồ Hòa Bình rộng lớn được ví như ''Hạ Long thu nhỏ'' cùng đền Thác Bờ linh thiêng. Hòa Bình hấp dẫn du khách bởi cảnh sắc núi rừng, suối khoáng nóng Kim Bôi và bản sắc văn hóa Mường, Thái đậm đà.', 'Tháng 9 đến tháng 12', '["Cơm lam","Thịt lợn mán","Cá nướng sông Đà","Rượu cần Mường"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('hung-yen', 'red-river-delta', 'Hưng Yên', 'Hung Yen', 'Đồng bằng sông Hồng', '#c7993f', 106.0584, 20.8151, 'Vùng đất Phố Hiến vang bóng một thời, quê hương nhãn lồng tiến vua với nhiều di tích cổ kính.', 'Hưng Yên là vùng đất giàu trầm tích lịch sử, từng có thương cảng Phố Hiến sầm uất với câu Thứ nhất Kinh Kỳ, thứ nhì Phố Hiến. Ngày nay, Hưng Yên lưu giữ quần thể di tích Phố Hiến với hàng trăm đền chùa cổ kính cùng những nét văn hóa giao thoa Đông Tây độc đáo. Đặc biệt, nhãn lồng Hưng Yên từng được chọn tiến vua, vị ngọt thanh khó quên. Về Hưng Yên, du khách như ngược dòng thời gian tìm về một đô thị cổ trầm mặc bên dòng sông Hồng.', 'Tháng 7 đến tháng 8 (mùa nhãn)', '["Nhãn lồng Hưng Yên","Tương Bần","Bún thang lươn","Ếch om Phượng Tường"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('khanh-hoa', 'south-central-coast', 'Khánh Hòa', 'Khanh Hoa', 'Duyên hải Nam Trung Bộ', '#3e92a8', 109.0244, 12.3333, 'Thiên đường biển đảo miền Trung với vịnh Nha Trang trong xanh và những rạn san hô rực rỡ.', 'Khánh Hòa được thiên nhiên ưu ái ban tặng đường bờ biển dài tuyệt đẹp cùng vịnh Nha Trang thuộc hàng đẹp nhất thế giới. Làn nước xanh ngọc, bãi cát trắng mịn, những hòn đảo hoang sơ và rạn san hô đa sắc là thiên đường nghỉ dưỡng và lặn biển. Bên cạnh đó, Khánh Hòa còn có tháp Bà Ponagar cổ kính, suối khoáng nóng và nền ẩm thực hải sản phong phú.', 'Tháng 3–9, biển êm và nắng đẹp', '["Bún cá","Bún sứa","Nem nướng Ninh Hòa","Yến sào","Hải sản"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('kien-giang', 'mekong-delta', 'Kiên Giang', 'Kien Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.0421, 9.9743, 'Vùng biển đảo Tây Nam với đảo Ngọc Phú Quốc, quần đảo Nam Du và những bãi biển hoang sơ.', 'Kiên Giang là tỉnh có biển đảo trù phú nhất miền Tây Nam Bộ. Nổi bật là đảo Phú Quốc — hòn đảo lớn nhất Việt Nam với bãi biển tuyệt đẹp, rừng nguyên sinh và nước mắm trứ danh. Ngoài ra còn có quần đảo Nam Du hoang sơ, Hà Tiên thơ mộng với ''Hà Tiên thập cảnh''. Vùng đất này hội tụ vẻ đẹp biển trời cùng nền văn hóa giao thoa Kinh - Khmer - Hoa độc đáo.', 'Tháng 11–4, mùa khô biển đẹp', '["Nước mắm Phú Quốc","Hồ tiêu","Bún cá Kiên Giang","Hải sản","Gỏi cá trích"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('kon-tum', 'central-highlands', 'Kon Tum', 'Kon Tum', 'Tây Nguyên', '#8a6e4b', 107.8744, 14.6489, 'Phố núi Bắc Tây Nguyên với nhà thờ gỗ trăm tuổi, Măng Đen mát lạnh và văn hóa bản địa đặc sắc.', 'Kon Tum là tỉnh cực bắc Tây Nguyên, nơi đại ngàn hùng vĩ giao hòa với những giá trị văn hóa độc đáo của đồng bào Ba Na, Xơ Đăng, Gia Rai. Tỉnh nổi tiếng với nhà thờ gỗ trăm tuổi, cầu treo Kon Klor, nhà rông truyền thống và khu du lịch Măng Đen được ví như Đà Lạt thứ hai. Vùng đất này quyến rũ bởi khí hậu mát mẻ, thiên nhiên trong lành và những nét văn hóa cồng chiêng nguyên sơ.', 'Tháng 11 đến tháng 4', '["Gỏi lá","Cá chua","Rượu cần","Cà phê","Heo quay Măng Đen"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('lai-chau', 'northwest', 'Lai Châu', 'Lai Chau', 'Tây Bắc', '#6e8c5a', 103.1866, 22.3171, 'Vùng biên viễn hoang sơ với tứ đại đỉnh đèo Ô Quy Hồ, bản du lịch cộng đồng Sin Suối Hồ và những đỉnh núi cao chót vót.', 'Lai Châu là tỉnh biên giới Tây Bắc còn giữ nét hoang sơ, hùng vĩ với những dãy núi cao và bản làng dân tộc thiểu số. Nơi đây có Đèo Ô Quy Hồ - một trong tứ đại đỉnh đèo, bản Sin Suối Hồ xanh sạch đẹp của người Mông, cùng những đỉnh núi Pu Ta Leng, Bạch Mộc Lương Tử hấp dẫn dân leo núi. Văn hóa các dân tộc Thái, Mông, Dao, Hà Nhì với chợ phiên, lễ hội đặc sắc làm nên sức hút riêng của miền đất biên viễn này.', 'Tháng 9 đến tháng 4', '["Lam nhọ","Cá bống vùi tro","Xôi tím","Rượu ngô Sùng Phài"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('lam-dong', 'central-highlands', 'Lâm Đồng', 'Lam Dong', 'Tây Nguyên', '#8a6e4b', 108.0942, 11.7521, 'Cao nguyên Đà Lạt ngàn hoa trong sương, lãng mạn với rừng thông và khí hậu mát quanh năm.', 'Lâm Đồng là xứ sở của Đà Lạt mộng mơ — thành phố ngàn hoa, ngàn thông trên cao nguyên Lang Biang. Khí hậu mát mẻ quanh năm, những đồi chè, vườn dâu, thác nước và hồ trong xanh khiến nơi đây trở thành điểm hẹn của những tâm hồn yêu sự lãng mạn và bình yên.', 'Quanh năm; đẹp nhất tháng 10–12 mùa dã quỳ', '["Bánh tráng nướng","Lẩu gà lá é","Dâu tây","Cà phê","Atisô"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('lang-son', 'northeast', 'Lạng Sơn', 'Lang Son', 'Đông Bắc', '#4f7b6a', 106.6205, 21.8398, 'Xứ Lạng biên cương với động đá linh thiêng, đỉnh Mẫu Sơn mây phủ, chợ cửa khẩu sầm uất và bản sắc dân tộc đậm đà.', 'Lạng Sơn là tỉnh biên giới Đông Bắc với phong cảnh hữu tình và bề dày lịch sử. Vùng đất xứ Lạng nổi tiếng với Động Tam Thanh, nàng Tô Thị, thành nhà Mạc cùng đỉnh Mẫu Sơn mây mù quanh năm có băng tuyết mùa đông. Các chợ cửa khẩu Tân Thanh, Đông Kinh sầm uất thu hút du khách mua sắm. Văn hóa Tày, Nùng, Dao với những làn điệu sli, lượn làm nên nét quyến rũ riêng của xứ Lạng.', 'Tháng 9 đến tháng 12', '["Vịt quay lá mắc mật","Phở chua Lạng Sơn","Khâu nhục","Bánh cuốn trứng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('lao-cai', 'northeast', 'Lào Cai', 'Lao Cai', 'Đông Bắc', '#4f7b6a', 104.1103, 22.3663, 'Quê hương của Sa Pa mờ sương và đỉnh Fansipan — nóc nhà Đông Dương.', 'Lào Cai là vùng núi non hùng vĩ nơi Tây Bắc, nổi danh với thị trấn Sa Pa trong mây và những thửa ruộng bậc thang được xem là đẹp bậc nhất thế giới. Văn hóa của người Mông, Dao, Tày tạo nên bức tranh đa sắc, ấm áp giữa đại ngàn Hoàng Liên Sơn.', 'Tháng 9 (lúa chín) và tháng 3–5 (trời trong)', '["Thắng cố","Cá hồi Sa Pa","Đồ nướng","Rượu táo mèo"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('long-an', 'mekong-delta', 'Long An', 'Long An', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.1694, 10.7307, 'Cửa ngõ miền Tây giáp Sài Gòn, nổi tiếng với vùng Đồng Tháp Mười, rừng tràm và những cánh đồng lúa trải dài.', 'Long An là tỉnh cửa ngõ nối Thành phố Hồ Chí Minh với đồng bằng sông Cửu Long, mang đặc trưng vùng Đồng Tháp Mười với rừng tràm, đất ngập nước và đồng lúa bát ngát. Nơi đây có làng nổi Tân Lập thơ mộng và khu bảo tồn Láng Sen hoang sơ, là điểm đến lý tưởng cho du lịch sinh thái. Người Long An hiền hòa, mến khách, gìn giữ nếp sống nông nghiệp đậm chất miền Tây giữa nhịp phát triển hối hả của vùng kinh tế trọng điểm phía Nam.', 'Tháng 9 đến tháng 11, mùa nước nổi rừng tràm xanh tốt', '["Gạo nàng thơm Chợ Đào","Rượu đế Gò Đen","Lạp xưởng Cần Đước","Đậu phộng Đức Hòa"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('nam-dinh', 'red-river-delta', 'Nam Định', 'Nam Dinh', 'Đồng bằng sông Hồng', '#c7993f', 106.2077, 20.2672, 'Đất học thành Nam với Đền Trần lịch sử, nhà thờ đổ ven biển nên thơ và món phở bò trứ danh.', 'Nam Định là vùng đất thành Nam giàu truyền thống khoa bảng và là quê hương phát tích vương triều Trần hiển hách. Đền Trần với lễ khai ấn đầu xuân thu hút hàng vạn người về cầu may. Vùng ven biển Nam Định còn nổi tiếng với nhà thờ đổ Hải Lý hoang hoải và những giáo đường nguy nga mang dáng dấp châu Âu. Đặc biệt, Nam Định được xem là cái nôi của phở bò Việt Nam với hương vị đậm đà, tinh tế làm say lòng bao thực khách gần xa.', 'Tháng Giêng âm lịch (mùa lễ hội)', '["Phở bò Nam Định","Bánh xíu páo","Nem nắm Giao Thủy","Kẹo Sìu Châu"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('nghe-an', 'north-central-coast', 'Nghệ An', 'Nghe An', 'Bắc Trung Bộ', '#5a8aa6', 104.9449, 19.2366, 'Quê hương Bác Hồ kính yêu, vùng đất nắng gió ân tình với biển Cửa Lò và đại ngàn Pù Mát hùng vĩ.', 'Nghệ An là vùng đất rộng lớn, đậm chất ân tình của con người xứ Nghệ. Tự hào là quê hương Chủ tịch Hồ Chí Minh, nơi đây gìn giữ khu di tích Kim Liên thiêng liêng. Từ bãi biển Cửa Lò sầm uất với mực nhảy trứ danh đến rừng nguyên sinh Pù Mát đa dạng sinh học, Nghệ An mang trong mình cả chiều sâu lịch sử lẫn vẻ đẹp thiên nhiên khoáng đạt, mời gọi bước chân lữ khách.', 'Tháng 4 đến tháng 8', '["Cháo lươn Vinh","Mực nhảy Cửa Lò","Cam Vinh","Bánh mướt"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ninh-binh', 'red-river-delta', 'Ninh Bình', 'Ninh Binh', 'Đồng bằng sông Hồng', '#c7993f', 105.9, 20.2234, '‘Hạ Long trên cạn’ với non nước hữu tình, cố đô Hoa Lư và những hang động kỳ vĩ.', 'Ninh Bình mê hoặc bằng vẻ đẹp của núi đá vôi soi bóng xuống những dòng sông lặng lờ. Tràng An, Tam Cốc, Hang Múa là những bức tranh thủy mặc sống động. Đây từng là kinh đô đầu tiên của nước Đại Cồ Việt, mang trong mình bề dày lịch sử ngàn năm.', 'Tháng 1–3 và mùa lúa chín tháng 5–6', '["Thịt dê núi","Cơm cháy","Ốc núi","Rượu Kim Sơn"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('ninh-thuan', 'south-central-coast', 'Ninh Thuận', 'Ninh Thuan', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.8675, 11.7061, 'Nắng gió đặc trưng với vịnh Vĩnh Hy tuyệt mỹ, tháp Chăm cổ, vườn nho trĩu quả và những đàn cừu.', 'Ninh Thuận mang vẻ đẹp riêng của vùng đất đầy nắng và gió, nơi hội tụ vịnh Vĩnh Hy trong xanh, vườn quốc gia Núi Chúa hoang dã và những cánh đồng nho, đồng cừu độc đáo. Đây cũng là trung tâm văn hóa Chăm với các đền tháp cổ như Po Klong Garai và lễ hội Katê đặc sắc. Khí hậu khô nóng tạo nên đặc sản nho, táo, dê cừu trứ danh của xứ này.', 'Tháng 1 đến tháng 8', '["Nho Ninh Thuận","Thịt dê, cừu","Bánh canh chả cá","Táo xanh","Nước mắm Cà Ná"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('phu-tho', 'northeast', 'Phú Thọ', 'Phu Tho', 'Đông Bắc', '#4f7b6a', 105.1151, 21.3199, 'Vùng đất Tổ cội nguồn dân tộc với Đền Hùng linh thiêng, hát Xoan di sản và những đồi cọ, đồi chè trung du.', 'Phú Thọ là vùng đất Tổ thiêng liêng, cội nguồn của dân tộc Việt Nam với Khu di tích Đền Hùng nơi thờ các Vua Hùng dựng nước. Hằng năm, hàng triệu người con đất Việt hành hương về dự Giỗ Tổ Hùng Vương. Phú Thọ còn lưu giữ hát Xoan - di sản văn hóa phi vật thể của nhân loại, cùng cảnh sắc trung du với đồi cọ, đồi chè và những lễ hội truyền thống đậm đà bản sắc. Đây là điểm đến gắn với hành trình tìm về nguồn cội.', 'Tháng 3 âm lịch', '["Bưởi Đoan Hùng","Thịt chua Thanh Sơn","Bánh tai","Cọ ỏm"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('phu-yen', 'south-central-coast', 'Phú Yên', 'Phu Yen', 'Duyên hải Nam Trung Bộ', '#3e92a8', 109.0553, 13.1695, 'Xứ sở hoa vàng cỏ xanh với Gành Đá Đĩa kỳ vĩ, Bãi Xép thơ mộng và những bãi biển hoang sơ.', 'Phú Yên được mệnh danh là ''xứ hoa vàng trên cỏ xanh'', mảnh đất bình yên với cảnh sắc thiên nhiên tuyệt đẹp và còn nhiều nét hoang sơ. Tỉnh nổi tiếng với kỳ quan địa chất Gành Đá Đĩa, Bãi Xép thơ mộng, hải đăng Mũi Điện đón ánh bình minh đầu tiên trên đất liền. Người Phú Yên hiền hòa, chân chất, cùng nền ẩm thực biển tươi ngon làm say lòng du khách.', 'Tháng 1 đến tháng 8', '["Mắt cá ngừ đại dương","Sò huyết Ô Loan","Bánh canh hẹ","Bò một nắng","Ghẹ Sông Cầu"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('quang-binh', 'north-central-coast', 'Quảng Bình', 'Quang Binh', 'Bắc Trung Bộ', '#5a8aa6', 106.2914, 17.5332, 'Vương quốc hang động của thế giới với Phong Nha - Kẻ Bàng và hang Sơn Đoòng kỳ vĩ.', 'Quảng Bình là miền đất của những kỳ quan dưới lòng đất. Vườn quốc gia Phong Nha - Kẻ Bàng ẩn giấu hàng trăm hang động đá vôi tráng lệ, trong đó Sơn Đoòng là hang lớn nhất hành tinh. Bên cạnh đó là bãi biển Nhật Lệ cát trắng, sông Son trong xanh và những làng quê yên bình. Vùng đất khắc nghiệt nắng gió này đã sản sinh ra nhiều con người kiên cường, hiếu khách.', 'Tháng 2–8, mùa khô ráo', '["Cháo canh","Bánh bột lọc","Khoai deo","Hải sản Nhật Lệ"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('quang-nam', 'south-central-coast', 'Quảng Nam', 'Quang Nam', 'Duyên hải Nam Trung Bộ', '#3e92a8', 107.9562, 15.5904, 'Vùng đất di sản với phố cổ Hội An và thánh địa Mỹ Sơn, đậm đà văn hóa và ẩm thực.', 'Quảng Nam là nơi hội tụ hai di sản văn hóa thế giới: phố cổ Hội An lung linh đèn lồng và thánh địa Mỹ Sơn của vương quốc Chăm Pa cổ. Những làng nghề, bãi biển An Bàng và đồng quê yên ả tạo nên một Quảng Nam vừa cổ kính vừa thanh bình.', 'Tháng 2–4, khô ráo dễ chịu', '["Cao lầu","Mì Quảng","Bánh mì Hội An","Cơm gà"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('quang-ngai', 'south-central-coast', 'Quảng Ngãi', 'Quang Ngai', 'Duyên hải Nam Trung Bộ', '#3e92a8', 108.6473, 14.9927, 'Vùng đất miền Trung với đảo núi lửa Lý Sơn, biển Sa Huỳnh và cội nguồn văn hóa Sa Huỳnh cổ.', 'Quảng Ngãi là dải đất ven biển miền Trung mang trong mình bề dày lịch sử và vẻ đẹp thiên nhiên hoang sơ. Nơi đây có đảo Lý Sơn được kiến tạo từ núi lửa, nổi danh với tỏi và hùng binh Hoàng Sa, cùng biển Sa Huỳnh gắn với nền văn hóa cổ rực rỡ. Người dân cần cù, mến khách, gìn giữ những giá trị truyền thống quý báu qua bao thế hệ.', 'Tháng 5 đến tháng 9', '["Tỏi Lý Sơn","Cá bống sông Trà","Don","Quế Trà Bồng","Mạch nha"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('quang-ninh', 'northeast', 'Quảng Ninh', 'Quang Ninh', 'Đông Bắc', '#4f7b6a', 107.2152, 21.2645, 'Nơi có kỳ quan thiên nhiên thế giới Vịnh Hạ Long và những bãi biển, hải đảo tuyệt đẹp.', 'Quảng Ninh là vùng đất của biển và đảo. Vịnh Hạ Long với hàng nghìn hòn đảo đá vôi là niềm tự hào của cả Việt Nam. Bên cạnh đó là Bái Tử Long hoang sơ, đảo Cô Tô cát trắng và nền văn hóa vùng mỏ giàu bản sắc.', 'Tháng 10–12, biển êm và trời trong', '["Chả mực Hạ Long","Sá sùng","Ngán","Bánh gật gù"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('quang-tri', 'north-central-coast', 'Quảng Trị', 'Quang Tri', 'Bắc Trung Bộ', '#5a8aa6', 106.928, 16.7475, 'Mảnh đất thiêng của những chứng tích chiến tranh hào hùng, từ Thành cổ, địa đạo đến đảo tiền tiêu Cồn Cỏ.', 'Quảng Trị là vùng đất thiêng liêng, nơi ghi dấu biết bao trang sử bi tráng và hào hùng của dân tộc. Từ Thành cổ với 81 ngày đêm rực lửa, làng hầm Vịnh Mốc kỳ vĩ đến hòn đảo anh hùng Cồn Cỏ, mỗi địa danh đều là một bản hùng ca. Vượt lên đau thương, người Quảng Trị hôm nay kiên cường dựng xây cuộc sống mới, biến mảnh đất lửa năm xưa thành điểm đến tri ân đầy xúc động và ý nghĩa.', 'Tháng 2 đến tháng 8', '["Bún hến Mai Xá","Cháo bột Kẻ Diên","Cua đá Cồn Cỏ","Tiêu Cùa"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('soc-trang', 'mekong-delta', 'Sóc Trăng', 'Soc Trang', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.9218, 9.5599, 'Vùng đất giao thoa văn hóa Kinh, Khmer, Hoa với những ngôi chùa độc đáo, lễ hội đua ghe ngo và đặc sản trứ danh.', 'Sóc Trăng là tỉnh ven biển nổi tiếng với sự giao thoa đặc sắc của ba dân tộc Kinh, Khmer và Hoa, thể hiện rõ qua hệ thống chùa chiền độc đáo bậc nhất miền Tây. Nơi đây có Chùa Dơi với hàng nghìn con dơi quạ, Chùa Đất Sét kỳ lạ cùng nhiều ngôi chùa Khmer rực rỡ. Lễ hội đua ghe ngo dịp Ok Om Bok thu hút đông đảo du khách mỗi năm. Sóc Trăng còn nổi tiếng với những đặc sản trứ danh như bánh pía, lạp xưởng, mang đến hành trình khám phá văn hóa và ẩm thực đầy thú vị.', 'Tháng 11 đến tháng 1, dịp lễ Ok Om Bok và đua ghe ngo', '["Bánh pía Sóc Trăng","Bún nước lèo","Lạp xưởng","Mè láo","Bánh cống"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('son-la', 'northwest', 'Sơn La', 'Son La', 'Tây Bắc', '#6e8c5a', 104.0702, 21.1945, 'Cao nguyên Tây Bắc với thảo nguyên Mộc Châu xanh mướt, đồi chè và những mùa hoa nối tiếp.', 'Sơn La là vùng cao nguyên rộng lớn của Tây Bắc, nổi tiếng nhất với cao nguyên Mộc Châu — thảo nguyên xanh mênh mông với đồi chè, rừng mận và các mùa hoa rực rỡ quanh năm. Khí hậu mát mẻ, cảnh sắc nên thơ cùng văn hóa các dân tộc Thái, Mông tạo nên sức hút đặc biệt. Đây cũng là vùng đất của những bản làng yên bình và đặc sản núi rừng độc đáo.', 'Tháng 11–2 (mùa hoa mận, hoa cải)', '["Bê chao Mộc Châu","Sữa tươi","Bắp cải mèo","Cá hồi, cá tầm","Thịt trâu gác bếp"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('tay-ninh', 'southeast', 'Tây Ninh', 'Tay Ninh', 'Đông Nam Bộ', '#b07a4a', 106.1602, 11.4041, 'Vùng đất tâm linh miền Đông với ''nóc nhà Nam Bộ'' Núi Bà Đen và Tòa Thánh Cao Đài rực rỡ độc đáo.', 'Tây Ninh là tỉnh biên giới Tây Nam nổi danh là trung tâm tâm linh của miền Đông Nam Bộ. Núi Bà Đen – đỉnh cao nhất Nam Bộ – thu hút hàng triệu lượt hành hương và du khách mỗi năm với chùa chiền linh thiêng và cáp treo hiện đại. Tòa Thánh Cao Đài, trung tâm của một tôn giáo bản địa độc đáo, mang vẻ đẹp kiến trúc giao thoa Đông – Tây có một không hai. Tây Ninh còn nổi tiếng với bánh tráng phơi sương và muối tôm đậm đà.', 'Tháng 11 đến tháng 4 và mùa lễ hội tháng Giêng', '["Bánh tráng phơi sương Trảng Bàng","Muối tôm Tây Ninh","Bánh canh Trảng Bàng"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('thai-binh', 'red-river-delta', 'Thái Bình', 'Thai Binh', 'Đồng bằng sông Hồng', '#c7993f', 106.3862, 20.5075, 'Quê hương năm tấn với chùa Keo cổ kính, biển Cồn Vành hoang sơ và những cánh đồng lúa thẳng cánh cò bay.', 'Thái Bình là quê lúa thanh bình của đồng bằng sông Hồng, nơi những cánh đồng vàng óng trải dài tận chân trời. Vùng đất này tự hào với chùa Keo gần 400 năm tuổi, kiệt tác kiến trúc gỗ với gác chuông ba tầng độc nhất vô nhị. Bờ biển Thái Bình còn có Cồn Vành hoang sơ nằm trong khu dự trữ sinh quyển sông Hồng. Người Thái Bình hiền hòa, chân chất, gìn giữ những giá trị văn hóa làng quê và các lễ hội cổ truyền đậm đà bản sắc Bắc Bộ.', 'Tháng 4 đến tháng 9', '["Bánh cáy làng Nguyễn","Canh cá Quỳnh Côi","Gỏi nhệch","Nem chạo Vị Thủy"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('thai-nguyen', 'northeast', 'Thái Nguyên', 'Thai Nguyen', 'Đông Bắc', '#4f7b6a', 105.8213, 21.692, 'Vùng đất ''đệ nhất danh trà'' với những đồi chè bát ngát, Hồ Núi Cốc huyền thoại và di tích ATK lịch sử.', 'Thái Nguyên là tỉnh trung du nổi danh khắp nước với những đồi chè Tân Cương xanh mướt, cái nôi của ''đệ nhất danh trà'' Việt Nam. Nơi đây còn có Hồ Núi Cốc gắn liền truyền thuyết tình yêu nàng Công - chàng Cốc, hang Phượng Hoàng kỳ vĩ và khu di tích ATK Định Hóa lịch sử. Thái Nguyên hài hòa giữa cảnh sắc thiên nhiên thanh bình, văn hóa trà đặc sắc và truyền thống cách mạng, là điểm đến hấp dẫn của vùng Việt Bắc.', 'Tháng 3 đến tháng 9', '["Trà Tân Cương","Cơm lam","Bánh chưng Bờ Đậu","Tương nếp Úc Kỳ"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('thanh-hoa', 'north-central-coast', 'Thanh Hóa', 'Thanh Hoa', 'Bắc Trung Bộ', '#5a8aa6', 105.3171, 20.0465, 'Vùng đất địa linh nhân kiệt xứ Thanh, hội tụ di sản thành đá, bãi biển sầm uất và suối cá thần kỳ bí.', 'Thanh Hóa là mảnh đất giàu trầm tích lịch sử, quê hương của nhiều triều đại và anh hùng dân tộc. Nơi đây sở hữu Thành nhà Hồ - di sản thế giới bằng đá độc nhất vô nhị, bãi biển Sầm Sơn rộn ràng cùng suối cá thần Cẩm Lương huyền bí. Từ đồng bằng trù phú đến miền núi đại ngàn, xứ Thanh luôn níu chân du khách bởi bề dày văn hóa và thiên nhiên đa dạng, hào sảng.', 'Tháng 4 đến tháng 9', '["Nem chua Thanh Hóa","Bánh gai Tứ Trụ","Hải sản Sầm Sơn","Cơm lam"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('thua-thien-hue', 'north-central-coast', 'Thừa Thiên Huế', 'Thua Thien Hue', 'Bắc Trung Bộ', '#5a8aa6', 107.5061, 16.3332, 'Cố đô trầm mặc bên dòng sông Hương, nơi lưu giữ di sản cung đình và ẩm thực tinh tế.', 'Huế mang vẻ đẹp cổ kính, hoài niệm. Quần thể di tích triều Nguyễn, lăng tẩm uy nghiêm, chùa Thiên Mụ soi bóng sông Hương. Người Huế nhẹ nhàng, giọng nói ngọt ngào, và ẩm thực cung đình cầu kỳ đến từng chi tiết. Đến Huế là để sống chậm và lắng nghe.', 'Tháng 1–4, tránh mùa mưa cuối năm', '["Bún bò Huế","Cơm hến","Bánh bèo, nậm, lọc","Chè Huế"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('tien-giang', 'mekong-delta', 'Tiền Giang', 'Tien Giang', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.3122, 10.3974, 'Vựa trái cây của miền Tây bên sông Tiền, với các cù lao trù phú, chợ nổi sầm uất và đờn ca tài tử ngọt ngào.', 'Tiền Giang nằm bên dòng sông Tiền hiền hòa, là một trong những vựa trái cây lớn nhất đồng bằng sông Cửu Long. Tỉnh nổi tiếng với các cù lao xanh mát như Thới Sơn, chợ nổi Cái Bè trăm năm tuổi và những vườn cây ăn trái sai trĩu quanh năm. Du lịch miệt vườn sông nước nơi đây gắn liền với đờn ca tài tử, ẩm thực dân dã và lòng hiếu khách của người miền Tây. Tiền Giang là điểm khởi đầu quen thuộc cho hành trình khám phá đồng bằng.', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', '["Hủ tiếu Mỹ Tho","Trái cây miệt vườn","Mắm còng","Bánh giá Gò Công"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('tra-vinh', 'mekong-delta', 'Trà Vinh', 'Tra Vinh', 'Đồng bằng sông Cửu Long', '#5d9e86', 106.3155, 9.7977, 'Vùng đất văn hóa Khmer đặc sắc với những ngôi chùa cổ kính, hàng cây cổ thụ và lễ hội truyền thống độc đáo.', 'Trà Vinh là tỉnh ven biển mang đậm bản sắc văn hóa Khmer Nam Bộ, nổi tiếng với hàng trăm ngôi chùa cổ kính nằm giữa những hàng cây sao, dầu trăm tuổi. Thắng cảnh Ao Bà Om huyền thoại, chùa Vàm Ray dát vàng lộng lẫy cùng các lễ hội Ok Om Bok, Chôl Chnăm Thmây tạo nên một không gian văn hóa đặc sắc hiếm có. Người Kinh, Khmer và Hoa cùng sinh sống hòa thuận, gìn giữ những giá trị truyền thống và nét đẹp tâm linh độc đáo của vùng đất hiền hòa này.', 'Tháng 11 đến tháng 1, dịp lễ Ok Om Bok của người Khmer', '["Bún nước lèo","Bánh canh Bến Có","Dừa sáp Cầu Kè","Cốm dẹp"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('tuyen-quang', 'northeast', 'Tuyên Quang', 'Tuyen Quang', 'Đông Bắc', '#4f7b6a', 105.267, 22.1131, 'Thủ đô kháng chiến với di tích Tân Trào lịch sử, hồ thủy điện Nà Hang thơ mộng và những cánh rừng nguyên sinh.', 'Tuyên Quang là vùng đất cách mạng được mệnh danh ''Thủ đô khu giải phóng'' với cụm di tích lịch sử Tân Trào, cây đa Tân Trào và lán Nà Nưa gắn liền những ngày tiền khởi nghĩa năm 1945. Bên cạnh giá trị lịch sử, Tuyên Quang còn quyến rũ bởi hồ thủy điện Nà Hang xanh biếc, Thác Mơ thơ mộng và Khu bảo tồn thiên nhiên với rừng nguyên sinh trùng điệp. Lễ hội Thành Tuyên rước đèn khổng lồ độc đáo cũng là điểm nhấn không thể bỏ lỡ.', 'Tháng 5 đến tháng 11', '["Thịt trâu gác bếp","Cá lăng sông Lô","Bánh gai Chiêm Hóa","Rượu ngô"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('vinh-long', 'mekong-delta', 'Vĩnh Long', 'Vinh Long', 'Đồng bằng sông Cửu Long', '#5d9e86', 105.9888, 10.1025, 'Trái tim miệt vườn của miền Tây giữa hai dòng sông, nổi tiếng với cù lao trái cây và làng nghề gạch gốm trăm năm.', 'Vĩnh Long nằm giữa sông Tiền và sông Hậu, là vùng đất phù sa trù phú bậc nhất đồng bằng sông Cửu Long. Tỉnh nổi tiếng với cù lao An Bình xanh mát, cái nôi của du lịch homestay miệt vườn, cùng vương quốc lò gạch gốm Mang Thít độc đáo ven sông Cổ Chiên. Vĩnh Long còn là quê hương của nhiều danh nhân và là vùng đất hiếu học. Đến đây, du khách được đắm mình trong những vườn trái cây sum suê, nghe đờn ca tài tử và cảm nhận nhịp sống sông nước chân chất, đậm đà tình người.', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', '["Cá tai tượng chiên xù","Bưởi năm roi Bình Minh","Khoai lang Bình Tân","Tàu hủ ky"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('vinh-phuc', 'red-river-delta', 'Vĩnh Phúc', 'Vinh Phuc', 'Đồng bằng sông Hồng', '#c7993f', 105.5579, 21.3611, 'Cửa ngõ Tây Bắc Hà Nội với thị trấn mây Tam Đảo mát lành và khu danh thắng tâm linh Tây Thiên linh thiêng.', 'Vĩnh Phúc là vùng đất chuyển tiếp giữa đồng bằng và miền núi phía Bắc, nổi bật với thị trấn nghỉ mát Tam Đảo bồng bềnh trong mây. Quanh năm khí hậu mát mẻ, Tam Đảo trở thành điểm trốn nóng lý tưởng và là chốn check-in lãng mạn bậc nhất miền Bắc. Dưới chân núi là khu danh thắng Tây Thiên với thiền viện Trúc Lâm và tín ngưỡng thờ Quốc Mẫu ngàn năm. Vĩnh Phúc còn có đặc sản su su Tam Đảo, bánh trùng mật mía và các món gà đồi thơm ngon, níu chân du khách phương xa.', 'Tháng 4 đến tháng 10', '["Su su Tam Đảo","Bánh trùng mật mía","Gà đồi Tam Đảo","Bò tái kiến đốt"]');
INSERT OR REPLACE INTO provinces (slug, region_id, name, name_en, region_name, color, center_lng, center_lat, summary, story, best_time, specialties) VALUES ('yen-bai', 'northeast', 'Yên Bái', 'Yen Bai', 'Đông Bắc', '#4f7b6a', 104.567, 21.7778, 'Miền Tây Bắc kỳ vĩ với ruộng bậc thang Mù Cang Chải vàng óng, hồ Thác Bà nghìn đảo và sắc màu văn hóa vùng cao.', 'Yên Bái là tỉnh miền núi Tây Bắc nổi danh với ruộng bậc thang Mù Cang Chải - di tích quốc gia đặc biệt và là kỳ quan do người Mông tạo nên. Mùa lúa chín, cả vùng nhuộm vàng óng ả đẹp ngỡ ngàng. Yên Bái còn có Hồ Thác Bà với hơn 1.300 hòn đảo xanh, đồi chè Suối Giàng, suối khoáng nóng và sắc màu văn hóa của người Mông, Thái, Tày. Đây là điểm đến lý tưởng cho những ai yêu thiên nhiên hùng vĩ và bản sắc vùng cao.', 'Tháng 9 đến tháng 10', '["Cốm Tú Lệ","Thịt trâu gác bếp","Chè Shan tuyết Suối Giàng","Cá nướng hồ Thác Bà"]');
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('lung-cu-flag-tower', 'lung-cu-flag-tower', 'ha-giang', 'Cột cờ Lũng Cú', 'Lung Cu Flag Tower', 'mountain', 105.3133, 23.3617, 'Điểm cực Bắc thiêng liêng của Tổ quốc, nơi lá cờ đỏ sao vàng tung bay giữa trời cao nguyên đá.', 'Đứng trên đỉnh Lũng Cú, gió từ biên giới thổi qua mang theo cái lạnh trong veo của vùng cao. Lá cờ rộng 54m² — tượng trưng cho 54 dân tộc anh em — kiêu hãnh phấp phới trên nền trời. Leo hết 839 bậc đá, cả cao nguyên đá Đồng Văn mở ra dưới chân bạn: những thửa ruộng bậc thang, bản làng người Mông, và đường biên giới uốn lượn theo dòng Nho Quế.', '["Cột cờ cao 33,15m, đặt trên đỉnh núi Rồng ở độ cao gần 1.470m.","Lá cờ có diện tích 54m², tượng trưng cho 54 dân tộc Việt Nam.","Từ đỉnh cột cờ có thể nhìn thấy hai hồ nước gọi là ''mắt rồng''."]', '["Mang theo áo ấm — đỉnh núi lộng gió và lạnh kể cả mùa hè.","Đi sáng sớm để tránh sương mù che tầm nhìn."]', 'Tháng 10–12 (mùa hoa tam giác mạch) hoặc tháng 9 (mùa lúa chín)', 'Nửa ngày', '25.000đ', '07:00 – 18:00', '["popular","verified"]', '["mountain","culture","photography"]', '[{"seed":"lungcu-1","caption":"Lá cờ Tổ quốc trên đỉnh núi Rồng","ratio":"16/9"},{"seed":"lungcu-2","caption":"Đường lên cột cờ","ratio":"4/3"},{"seed":"lungcu-3","caption":"Cao nguyên đá nhìn từ trên cao","ratio":"1/1"},{"seed":"lungcu-4","caption":"Cột cờ uy nghiêm, lá cờ đỏ tung bay trong sương","ratio":"4/3"}]', '["dong-van-old-town","ma-pi-leng-pass"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ma-pi-leng-pass', 'ma-pi-leng-pass', 'ha-giang', 'Đèo Mã Pì Lèng', 'Ma Pi Leng Pass', 'mountain', 105.2667, 23.2333, 'Một trong ''tứ đại đỉnh đèo'' của Việt Nam, vách đá dựng đứng bên dòng Nho Quế xanh ngọc.', 'Mã Pì Lèng là cung đường khiến mọi tay lái phải nín thở. Con đường Hạnh Phúc men theo vách núi, một bên là đá tai mèo sừng sững, một bên là vực sâu hun hút nơi dòng Nho Quế chảy như một dải lụa xanh. Người ta nói đứng ở đây mới thấy con người thật nhỏ bé, còn thiên nhiên thì vĩ đại đến nhường nào.', '["Đèo dài khoảng 20km, ở độ cao gần 1.500m.","Tên ''Mã Pì Lèng'' theo tiếng Mông nghĩa là ''sống mũi con ngựa''.","Hẻm vực Tu Sản bên dưới là hẻm vực sâu nhất Đông Nam Á."]', '["Thuê thuyền trên sông Nho Quế để ngắm đèo từ dưới lên — góc nhìn ngoạn mục.","Lái xe chậm và cẩn thận, đặc biệt khi trời mưa."]', 'Tháng 9–11, trời khô ráo, ít sương', '2–3 giờ', '', 'Cả ngày', '["trending","hidden-gem"]', '["mountain","photography"]', '[{"seed":"mapileng-1","caption":"Đường Hạnh Phúc vắt qua vách núi","ratio":"16/9"},{"seed":"mapileng-2","caption":"Dòng Nho Quế xanh ngọc","ratio":"4/3"},{"seed":"mapileng-3","caption":"Hẻm vực Tu Sản","ratio":"1/1"}]', '["lung-cu-flag-tower","dong-van-old-town"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dong-van-old-town', 'dong-van-old-town', 'ha-giang', 'Phố cổ Đồng Văn', 'Dong Van Old Town', 'village', 105.3633, 23.2783, 'Khu phố cổ trăm tuổi giữa lòng cao nguyên đá, nơi nhịp sống vùng cao chậm rãi và ấm áp.', 'Khi màn đêm buông xuống, những ngôi nhà trình tường mái ngói âm dương ở Đồng Văn lên đèn lồng đỏ. Quán cà phê phố cổ tỏa hương, người Mông, người Tày, người Hoa ngồi bên nhau. Phiên chợ cuối tuần là cả một thế giới sắc màu — váy áo thổ cẩm, tiếng khèn, và những nụ cười hồn hậu của người vùng cao.', '["Khu phố cổ hình thành từ đầu thế kỷ 20.","Kiến trúc pha trộn giữa người Mông, Tày và Hoa.","Chợ phiên Đồng Văn họp vào Chủ nhật hằng tuần."]', '["Ở lại một đêm để cảm nhận phố cổ lên đèn.","Thử thắng cố và rượu ngô của người Mông."]', 'Cuối tuần để kịp phiên chợ', 'Nửa ngày', '', 'Cả ngày', '["hidden-gem"]', '["village","culture","food"]', '[{"seed":"dongvan-1","caption":"Phố cổ lên đèn lồng","ratio":"16/9"},{"seed":"dongvan-2","caption":"Phiên chợ vùng cao","ratio":"4/3"}]', '["ma-pi-leng-pass","lung-cu-flag-tower"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('sa-pa-town', 'sa-pa-town', 'lao-cai', 'Sa Pa', 'Sa Pa', 'mountain', 103.8438, 22.3361, 'Thị trấn trong mây, nơi ruộng bậc thang trải dài và những bản làng người Mông, Dao ẩn hiện trong sương.', 'Sa Pa đón bạn bằng một làn sương mỏng và cái se lạnh dễ chịu. Buổi sáng, mây luồn qua những thung lũng ruộng bậc thang vàng óng. Người phụ nữ Mông gùi rau xuống chợ, trẻ con má hồng cười giòn tan. Khi hoàng hôn nhuộm tím dãy Hoàng Liên Sơn, Sa Pa trở nên yên bình đến nao lòng.', '["Sa Pa nằm ở độ cao khoảng 1.500–1.650m.","Là cửa ngõ chinh phục Fansipan — ''nóc nhà Đông Dương'' cao 3.143m.","Ruộng bậc thang Sa Pa từng được tạp chí du lịch quốc tế bình chọn đẹp nhất thế giới."]', '["Mùa lúa chín (tháng 9) là thời điểm ruộng bậc thang đẹp nhất.","Đi cáp treo hoặc leo bộ lên Fansipan tùy sức khỏe."]', 'Tháng 9 (lúa chín) hoặc tháng 3–5 (trời trong)', '2 ngày', '', 'Cả ngày', '["popular","verified"]', '["mountain","culture","photography"]', '[{"seed":"sapa-1","caption":"Ruộng bậc thang mùa lúa chín","ratio":"16/9"},{"seed":"sapa-2","caption":"Sương sớm trên thung lũng Mường Hoa","ratio":"4/3"},{"seed":"sapa-3","caption":"Đỉnh Fansipan trong mây","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ha-long-bay', 'ha-long-bay', 'quang-ninh', 'Vịnh Hạ Long', 'Ha Long Bay', 'unesco', 107, 20.9101, 'Kỳ quan thiên nhiên thế giới với hàng nghìn hòn đảo đá vôi nhô lên giữa làn nước xanh ngọc bích.', 'Truyền thuyết kể rằng Rồng Mẹ đã hạ xuống vùng biển này, nhả ra những viên ngọc hóa thành nghìn hòn đảo che chắn cho người dân. Hôm nay, khi con thuyền lướt nhẹ qua những khối đá vôi phủ rêu, len lỏi vào hang động kỳ ảo, bạn sẽ hiểu vì sao Hạ Long là niềm tự hào của Việt Nam. Bình minh trên vịnh, mặt nước phẳng lặng như gương, là khoảnh khắc khó quên.', '["Được UNESCO công nhận là Di sản thiên nhiên thế giới năm 1994.","Vịnh có khoảng 1.600 hòn đảo lớn nhỏ.","''Hạ Long'' nghĩa là ''rồng hạ xuống''."]', '["Ngủ đêm trên du thuyền để ngắm bình minh và hoàng hôn trên vịnh.","Chèo kayak vào các hang để khám phá những bãi tắm ẩn."]', 'Tháng 10–12, biển êm và trời trong', '1–2 ngày', '290.000đ', 'Cả ngày', '["unesco","popular","verified"]', '["beach","nature","photography"]', '[{"seed":"halong-1","caption":"Bình minh trên vịnh","ratio":"16/9"},{"seed":"halong-2","caption":"Thuyền giữa rừng đảo đá vôi","ratio":"4/3"},{"seed":"halong-3","caption":"Hang Sửng Sốt","ratio":"1/1"},{"seed":"halong-4","caption":"Làng chài trên vịnh","ratio":"4/3"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('trang-an', 'trang-an', 'ninh-binh', 'Tràng An', 'Trang An', 'unesco', 105.9167, 20.25, '‘Vịnh Hạ Long trên cạn’ — những dòng sông uốn lượn qua núi đá vôi và hang động huyền bí.', 'Ngồi trên chiếc thuyền nan, người lái đò khẽ khua mái chèo đưa bạn trôi giữa khung cảnh như tranh thủy mặc. Thuyền luồn qua những hang động tối, nơi thạch nhũ rủ xuống chạm mặt nước, rồi bất ngờ mở ra một thung lũng xanh mướt. Tiếng chim, tiếng nước, và sự tĩnh lặng tuyệt đối khiến Tràng An trở thành chốn bình yên hiếm có.', '["Di sản hỗn hợp văn hóa và thiên nhiên thế giới được UNESCO công nhận năm 2014.","Có hơn 30 hang động xuyên thủy.","Từng là kinh đô Hoa Lư của nước Đại Cồ Việt thế kỷ 10."]', '["Mỗi tuyến đò kéo dài 2–3 giờ, hãy mang nón và nước.","Ghé Hang Múa leo 500 bậc để ngắm toàn cảnh từ trên cao."]', 'Tháng 1–3 hoặc mùa lúa chín tháng 5–6', 'Nửa ngày', '250.000đ', '07:00 – 17:00', '["unesco","verified"]', '["nature","history","photography"]', '[{"seed":"trangan-1","caption":"Thuyền nan giữa núi đá","ratio":"16/9"},{"seed":"trangan-2","caption":"Thuyền nhỏ lướt giữa hồ nước phẳng dưới chân núi đá","ratio":"4/3"},{"seed":"trangan-3","caption":"Toàn cảnh từ Hang Múa","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hoan-kiem-lake', 'hoan-kiem-lake', 'ha-noi', 'Hồ Hoàn Kiếm', 'Hoan Kiem Lake', 'lake', 105.8525, 21.0287, 'Trái tim của Hà Nội ngàn năm, nơi Tháp Rùa soi bóng và truyền thuyết trả gươm còn vang vọng.', 'Sáng sớm, người Hà Nội tập thể dục quanh hồ, hàng liễu rủ soi bóng nước. Cầu Thê Húc đỏ rực dẫn vào đền Ngọc Sơn. Tương truyền vua Lê Lợi đã trả lại thanh gươm thần cho Rùa Vàng ở chính hồ này — vì thế hồ mang tên ''Hoàn Kiếm'', nghĩa là trả gươm. Tối cuối tuần, phố quanh hồ thành phố đi bộ, rộn ràng tiếng cười và âm nhạc.', '["Tên cũ là hồ Lục Thủy vì nước có màu xanh quanh năm.","Cầu Thê Húc nghĩa là ''nơi đậu ánh sáng ban mai''.","Đền Ngọc Sơn thờ Hưng Đạo Đại Vương Trần Quốc Tuấn."]', '["Đi dạo phố đi bộ vào tối thứ Sáu đến Chủ nhật.","Thử cà phê trứng và kem Tràng Tiền gần hồ."]', 'Mùa thu (tháng 9–11), tiết trời mát dịu', '1–2 giờ', '', 'Cả ngày', '["popular","verified"]', '["history","culture","city"]', '[{"seed":"hoankiem-1","caption":"Tháp Rùa giữa hồ","ratio":"16/9"},{"seed":"hoankiem-2","caption":"Chàng trai lặng ngồi ngắm mặt hồ bên gốc cây","ratio":"4/3"},{"seed":"hoankiem-3","caption":"Cành cây trơ lá in bóng trên mặt hồ mờ sương","ratio":"1/1"}]', '["old-quarter-hanoi"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('old-quarter-hanoi', 'old-quarter-hanoi', 'ha-noi', 'Phố cổ Hà Nội', 'Hanoi Old Quarter', 'city', 105.8497, 21.0333, 'Mê cung 36 phố phường, nơi mỗi con phố từng mang tên một nghề thủ công truyền thống.', 'Lạc vào phố cổ là lạc vào một Hà Nội của những thế kỷ trước. Hàng Bạc, Hàng Mã, Hàng Gai — mỗi cái tên kể một câu chuyện nghề. Mùi phở thơm lừng buổi sáng, tiếng rao hàng, những ngôi nhà ống mái rêu phong. Ngồi vỉa hè nhâm nhi cốc bia hơi, bạn sẽ thấy nhịp sống Hà Nội vừa hối hả vừa thong dong.', '["Khu phố cổ có 36 phố nghề hình thành từ thế kỷ 15.","Mỗi phố ''Hàng'' từng chuyên bán một mặt hàng riêng.","Phở, bún chả và cà phê trứng đều là đặc sản nơi đây."]', '["Khám phá bằng xích lô hoặc đi bộ.","Thử bún chả trưa và phở sáng."]', 'Mùa thu Hà Nội', 'Nửa ngày', '', 'Cả ngày', '["popular"]', '["city","food","culture"]', '[{"seed":"oldquarter-1","caption":"Phố nghề truyền thống","ratio":"16/9"},{"seed":"oldquarter-2","caption":"Gánh hàng rong","ratio":"4/3"}]', '["hoan-kiem-lake"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hue-imperial-city', 'hue-imperial-city', 'thua-thien-hue', 'Đại Nội Huế', 'Hue Imperial City', 'unesco', 107.5776, 16.4698, 'Kinh thành của 13 đời vua Nguyễn, trầm mặc và cổ kính bên dòng sông Hương thơ mộng.', 'Bước qua Ngọ Môn, bạn lùi về một thời vàng son của triều Nguyễn. Những điện rồng, sân chầu, tường thành rêu phong kể câu chuyện của một vương triều. Chiều Huế buông xuống chậm rãi, tiếng chuông chùa Thiên Mụ vọng qua sông Hương, một điệu Nam ai man mác. Huế không ồn ào — Huế khiến lòng người lắng lại.', '["Quần thể di tích Cố đô Huế được UNESCO công nhận năm 1993.","Là kinh đô Việt Nam thời nhà Nguyễn (1802–1945).","Kinh thành được xây theo nguyên tắc phong thủy với sông Hương làm minh đường."]', '["Đi thuyền rồng nghe ca Huế trên sông Hương buổi tối.","Thử các món cung đình: bún bò Huế, bánh bèo, chè Huế."]', 'Tháng 1–4, tránh mùa mưa cuối năm', 'Nửa ngày', '200.000đ', '07:00 – 17:30', '["unesco","verified"]', '["history","culture","temple"]', '[{"seed":"hue-1","caption":"Ngọ Môn uy nghi","ratio":"16/9"},{"seed":"hue-2","caption":"Ngọ Môn cổ kính nhìn từ lối vào lát đá","ratio":"4/3"},{"seed":"hue-3","caption":"Sông Hương chiều buông","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('golden-bridge', 'golden-bridge', 'da-nang', 'Cầu Vàng', 'Golden Bridge', 'bridge', 107.9883, 15.9953, 'Cây cầu được nâng đỡ bởi đôi bàn tay khổng lồ, lơ lửng giữa mây trên đỉnh Bà Nà.', 'Xuất hiện như trong một giấc mơ, Cầu Vàng vươn ra giữa không trung, được nâng bởi hai bàn tay đá rêu phong khổng lồ. Đứng giữa cầu, mây trôi dưới chân, cả vùng núi Bà Nà trải ra mênh mông. Khoảnh khắc ấy khiến cả thế giới phải trầm trồ khi những bức ảnh đầu tiên lan truyền năm 2018.', '["Khánh thành năm 2018, dài gần 150m.","Nằm ở độ cao khoảng 1.400m trên núi Bà Nà.","Gây sốt truyền thông toàn cầu ngay khi xuất hiện."]', '["Đi cáp treo sớm để tránh đông và mây mù.","Kết hợp tham quan Làng Pháp và vườn hoa Le Jardin."]', 'Tháng 3–8, trời nắng đẹp', '1 ngày', '900.000đ (vé Bà Nà)', '08:00 – 22:00', '["trending","popular"]', '["mountain","photography","bridge"]', '[{"seed":"goldenbridge-1","caption":"Cầu Vàng giữa mây","ratio":"16/9"},{"seed":"goldenbridge-2","caption":"Đôi bàn tay nâng cầu","ratio":"4/3"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hoi-an-ancient-town', 'hoi-an-ancient-town', 'quang-nam', 'Phố cổ Hội An', 'Hoi An Ancient Town', 'unesco', 108.3266, 15.8801, 'Thương cảng cổ vàng son, lung linh sắc đèn lồng mỗi khi đêm về bên dòng sông Hoài.', 'Khi mặt trời lặn, Hội An khoác lên mình tấm áo huyền ảo. Hàng nghìn chiếc đèn lồng đủ màu thắp sáng từng con phố, in bóng xuống dòng sông Hoài. Du khách thả những chiếc đèn hoa đăng mang theo điều ước. Nếu đến Hội An vào khoảng 18:30, khi đèn lồng vừa được thắp lên, bạn sẽ hiểu vì sao nơi này khiến biết bao người phải lòng.', '["Được UNESCO công nhận Di sản văn hóa thế giới năm 1999.","Từng là thương cảng sầm uất thế kỷ 16–17.","Chùa Cầu là biểu tượng do thương nhân Nhật Bản xây dựng."]', '["Đến khoảng 17:30–18:30 để ngắm phố lên đèn.","Thử cao lầu và bánh mì Hội An — ngon trứ danh."]', 'Tháng 2–4, khô ráo dễ chịu', 'Nửa ngày đến 1 ngày', '120.000đ', 'Cả ngày', '["unesco","popular","verified"]', '["culture","history","food","photography"]', '[{"seed":"hoian-1","caption":"Đèn lồng đêm phố cổ","ratio":"16/9"},{"seed":"hoian-2","caption":"Bóng dừa đổ dài trên tường vàng, người đội nón lá đi qua","ratio":"4/3"},{"seed":"hoian-3","caption":"Thả đèn hoa đăng trên sông Hoài","ratio":"1/1"},{"seed":"hoian-4","caption":"Phố cổ ban ngày","ratio":"4/3"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('da-lat-city', 'da-lat-city', 'lam-dong', 'Đà Lạt', 'Da Lat', 'city', 108.4583, 11.9404, 'Thành phố ngàn hoa trong sương, lãng mạn với rừng thông, hồ nước và những sớm mai săn mây.', 'Đà Lạt chào bạn bằng cái lạnh dịu dàng và hương cà phê thoảng trong gió. Những đồi thông xanh ngút ngàn, hồ Xuân Hương phẳng lặng, và muôn loài hoa khoe sắc quanh năm. Bình minh, từng lớp mây bồng bềnh trôi qua thung lũng — khoảnh khắc ''săn mây'' khiến người ta nín thở. Một ly cà phê nóng bên hồ buổi sáng là đủ để yêu Đà Lạt.', '["Nằm ở độ cao khoảng 1.500m, khí hậu mát quanh năm.","Được người Pháp quy hoạch thành nơi nghỉ dưỡng đầu thế kỷ 20.","Nổi tiếng với hoa, cà phê, dâu tây và atisô."]', '["Dậy sớm lên Cầu Đất hoặc đồi Đa Phú để săn mây.","Mang theo áo khoác nhẹ — đêm Đà Lạt khá lạnh."]', 'Quanh năm; đẹp nhất tháng 10–12 mùa dã quỳ', '2–3 ngày', '', 'Cả ngày', '["popular","verified"]', '["mountain","nature","food","photography"]', '[{"seed":"dalat-1","caption":"Săn mây bình minh","ratio":"16/9"},{"seed":"dalat-2","caption":"Hồ Xuân Hương","ratio":"4/3"},{"seed":"dalat-3","caption":"Đồi thông trong sương","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ben-thanh-market', 'ben-thanh-market', 'ho-chi-minh', 'Chợ Bến Thành', 'Ben Thanh Market', 'market', 106.698, 10.7721, 'Khu chợ biểu tượng của Sài Gòn, nơi nhịp sống sôi động và hương vị ẩm thực hội tụ.', 'Bến Thành là trái tim náo nhiệt của Sài Gòn. Từ sáng sớm, tiếng mời chào rộn ràng, sạp hàng đầy ắp trái cây, vải vóc, đặc sản. Khi đêm xuống, khu chợ đêm bên ngoài lại bừng lên với hàng quán ăn vặt: bánh xèo, gỏi cuốn, chè ba màu. Một vòng Bến Thành là cảm nhận trọn vẹn sự phóng khoáng, hào sảng của người Sài Gòn.', '["Chợ hiện tại được xây dựng năm 1914 thời Pháp thuộc.","Tháp đồng hồ cửa Nam là biểu tượng quen thuộc của thành phố.","Là điểm đến ẩm thực và mua sắm hàng đầu Sài Gòn."]', '["Mạnh dạn trả giá khi mua sắm.","Ghé chợ đêm sau 19:00 để thưởng thức ẩm thực đường phố."]', 'Quanh năm; mùa khô tháng 12–4 dễ chịu nhất', '1–2 giờ', '', '06:00 – 24:00 (chợ đêm)', '["popular"]', '["city","food","market"]', '[{"seed":"benthanh-1","caption":"Cửa Nam chợ Bến Thành","ratio":"16/9"},{"seed":"benthanh-2","caption":"Chợ đêm rực rỡ","ratio":"4/3"}]', '[]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('phong-nha-cave', 'phong-nha-cave', 'quang-binh', 'Động Phong Nha', 'Phong Nha Cave', 'cave', 106.2833, 17.5833, 'Trái tim của vương quốc hang động, nơi dòng sông ngầm len lỏi qua những thạch nhũ lộng lẫy.', 'Ngồi trên chiếc thuyền nhỏ trôi vào lòng Động Phong Nha, ánh sáng dần tắt sau lưng, nhường chỗ cho một thế giới huyền ảo. Dòng sông ngầm Son lặng lẽ đưa bạn qua những vòm hang cao vút, nơi thạch nhũ hàng triệu năm tuổi rủ xuống lấp lánh như cung điện pha lê. Tiếng nước nhỏ giọt vọng trong không gian tĩnh mịch, mỗi khối đá mang một hình hài kỳ lạ do tạo hóa khắc nên. Đây là một phần của di sản Phong Nha - Kẻ Bàng, nơi thiên nhiên kể câu chuyện về thời gian bằng đá và nước.', '["Thuộc Vườn quốc gia Phong Nha - Kẻ Bàng, Di sản thiên nhiên thế giới UNESCO (2003).","Sông ngầm trong động dài khoảng 1.500m có thể đi thuyền tham quan.","Khu vực này có hệ thống hang động đá vôi karst hơn 400 triệu năm tuổi."]', '["Đi thuyền trên sông Son để vào động — trải nghiệm không thể bỏ lỡ.","Mang giày chống trượt vì nền hang ẩm ướt."]', 'Tháng 2–8, mùa khô ráo, nước sông trong', 'Nửa ngày', '150.000đ', '07:30 – 16:30', '["unesco","popular","verified"]', '["nature","history","photography"]', '[{"seed":"phongnha-1","caption":"Vòm hang sâu thẳm ánh lên sắc đá nâu đỏ","ratio":"16/9"},{"seed":"phongnha-2","caption":"Thạch nhũ huyền ảo trong lòng hang tĩnh lặng","ratio":"4/3"},{"seed":"phongnha-3","caption":"Dòng sông ngầm Son","ratio":"1/1"}]', '["son-doong-cave"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('son-doong-cave', 'son-doong-cave', 'quang-binh', 'Hang Sơn Đoòng', 'Son Doong Cave', 'cave', 106.2872, 17.4475, 'Hang động tự nhiên lớn nhất thế giới, một vũ trụ riêng với rừng nguyên sinh và mây trôi trong lòng đất.', 'Sơn Đoòng không giống bất cứ nơi nào trên Trái Đất. Trong lòng hang khổng lồ ấy có cả một khu rừng nguyên sinh, có sông chảy, có những đám mây hình thành rồi tan biến, và những giếng trời rọi xuống cột sáng huyền diệu. Đứng dưới vòm hang cao tới gần 200m, con người chỉ như một chấm nhỏ giữa kỳ quan vĩ đại của tạo hóa. Khám phá Sơn Đoòng là một hành trình phiêu lưu thực sự, dành cho những ai khao khát chạm tới điều phi thường.', '["Là hang động tự nhiên lớn nhất thế giới, được phát hiện năm 1990 và khảo sát năm 2009.","Vòm hang có chỗ cao gần 200m, đủ chứa cả một tòa nhà chọc trời.","Bên trong có rừng nguyên sinh và hệ sinh thái riêng biệt."]', '["Chỉ tham quan qua tour thám hiểm được cấp phép, đặt trước nhiều tháng.","Cần sức khỏe tốt cho hành trình trekking nhiều ngày."]', 'Tháng 1–8, ngoài mùa mưa lũ', 'Tour 4 ngày 3 đêm', 'Tour từ 70 triệu đồng', 'Theo lịch tour', '["hidden-gem","trending","verified"]', '["nature","mountain","photography"]', '[{"seed":"sondoong-1","caption":"Cột sáng giếng trời trong hang","ratio":"16/9"},{"seed":"sondoong-2","caption":"Lòng hang đá nâu đỏ uốn cong dẫn vào sâu","ratio":"4/3"},{"seed":"sondoong-3","caption":"Đoàn người nhỏ bé dưới giếng trời rừng xanh trong hang","ratio":"1/1"}]', '["phong-nha-cave"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nha-trang-beach', 'nha-trang-beach', 'khanh-hoa', 'Biển Nha Trang', 'Nha Trang Beach', 'beach', 109.1967, 12.2388, 'Vịnh biển xanh trong vắt với bãi cát trắng cong mềm, một trong những vịnh đẹp nhất thế giới.', 'Nha Trang mở ra trước mắt bạn một dải biển xanh ngọc bích ôm lấy bờ cát trắng dài. Buổi sáng, mặt trời lên từ phía biển nhuộm hồng cả vịnh, người dân tắm biển sớm, thuyền thúng dập dềnh. Hàng dừa nghiêng mình theo gió, và xa xa là những hòn đảo nhô lên giữa làn nước trong đến mức nhìn thấy đáy. Lặn biển ngắm san hô, thưởng thức hải sản tươi rói bên bờ — Nha Trang là thiên đường nghỉ dưỡng của miền Trung.', '["Vịnh Nha Trang là thành viên Câu lạc bộ các vịnh đẹp nhất thế giới.","Bãi biển trải dài khoảng 6km dọc thành phố.","Vùng biển có nhiều rạn san hô đa dạng để lặn ngắm."]', '["Đi tour 4 đảo để lặn ngắm san hô và tắm biển.","Thưởng thức hải sản tươi và bún cá Nha Trang."]', 'Tháng 3–9, biển êm và nắng đẹp', '1–2 ngày', '', 'Cả ngày', '["popular","verified"]', '["beach","nature","food"]', '[{"seed":"nhatrang-1","caption":"Bình minh trên vịnh Nha Trang","ratio":"16/9"},{"seed":"nhatrang-2","caption":"Bãi cát trắng cong mềm","ratio":"4/3"},{"seed":"nhatrang-3","caption":"Hàng dừa ven biển","ratio":"1/1"}]', '["hon-mun-island"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hon-mun-island', 'hon-mun-island', 'khanh-hoa', 'Đảo Hòn Mun', 'Hon Mun Island', 'island', 109.2833, 12.1667, 'Khu bảo tồn biển với rạn san hô rực rỡ, thiên đường lặn biển bậc nhất Việt Nam.', 'Hòn Mun mang tên loài đá đen óng ánh ven đảo, nhưng điều khiến nơi đây nổi tiếng lại nằm dưới mặt nước. Lặn xuống làn nước trong vắt, cả một thế giới san hô muôn màu hiện ra: những rặng san hô đỏ, vàng, tím, đàn cá nhỏ tung tăng len lỏi. Đây là khu bảo tồn biển đầu tiên của Việt Nam, nơi đa dạng sinh học biển phong phú bậc nhất. Một ngày ở Hòn Mun là một ngày lạc vào khu vườn cổ tích giữa đại dương.', '["Là khu bảo tồn biển đầu tiên của Việt Nam, thành lập năm 2001.","Có khoảng 350 loài san hô và đa dạng sinh vật biển.","Tên ''Hòn Mun'' bắt nguồn từ loại đá đen như gỗ mun ven đảo."]', '["Mang theo kính lặn hoặc thuê tại bến để ngắm san hô.","Đi sớm để nước trong và tránh đông khách."]', 'Tháng 3–9, biển lặng nước trong', 'Nửa ngày', '22.000đ (phí tham quan)', '07:00 – 17:00', '["hidden-gem","verified"]', '["island","beach","nature"]', '[{"seed":"honmun-1","caption":"Rạn san hô rực rỡ dưới nước","ratio":"16/9"},{"seed":"honmun-2","caption":"Làn nước trong vắt quanh đảo","ratio":"4/3"},{"seed":"honmun-3","caption":"Lặn ngắm san hô","ratio":"1/1"}]', '["nha-trang-beach"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('phu-quoc-island', 'phu-quoc-island', 'kien-giang', 'Đảo Phú Quốc', 'Phu Quoc Island', 'island', 103.9667, 10.2167, 'Đảo Ngọc lớn nhất Việt Nam với bãi biển hoang sơ, rừng nguyên sinh và hoàng hôn tuyệt mỹ.', 'Phú Quốc — hòn đảo lớn nhất nước — chào đón bạn bằng những bãi biển cát vàng trải dài và làn nước ấm áp. Hoàng hôn trên Bãi Trường nhuộm cả trời biển một màu cam rực, khoảnh khắc khiến ai cũng phải dừng bước. Rừng nguyên sinh phủ xanh trung tâm đảo, làng chài bình dị tỏa hương nước mắm trứ danh, và cáp treo vượt biển dài nhất thế giới nối ra hòn đảo phía Nam. Phú Quốc vừa hoang sơ vừa hiện đại, là viên ngọc của vùng biển Tây Nam.', '["Là đảo lớn nhất Việt Nam với diện tích khoảng 574km².","Cáp treo Hòn Thơm dài hơn 7,8km — từng là cáp treo vượt biển dài nhất thế giới.","Nổi tiếng với nước mắm Phú Quốc và hồ tiêu thơm nồng."]', '["Ngắm hoàng hôn ở Bãi Trường hoặc Dinh Cậu.","Thử nước mắm, hải sản và đi cáp treo Hòn Thơm."]', 'Tháng 11–4, mùa khô biển đẹp', '2–3 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["island","beach","nature","food"]', '[{"seed":"phuquoc-1","caption":"Hoàng hôn trên Bãi Trường","ratio":"16/9"},{"seed":"phuquoc-2","caption":"Cáp treo vượt biển Hòn Thơm","ratio":"4/3"},{"seed":"phuquoc-3","caption":"Cáp treo vượt biển xanh ngắt giữa những hòn đảo","ratio":"1/1"}]', '["bai-sao-beach"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bai-sao-beach', 'bai-sao-beach', 'kien-giang', 'Bãi Sao', 'Sao Beach', 'beach', 104.0306, 10.0461, 'Bãi biển cát trắng mịn như bột, làn nước xanh ngọc — viên ngọc đẹp nhất Phú Quốc.', 'Bãi Sao được nhiều người gọi là bãi biển đẹp nhất Phú Quốc, và chỉ cần đặt chân tới là hiểu vì sao. Cát ở đây trắng mịn như bột, mềm mại dưới chân, ôm lấy một vịnh nước xanh ngọc trong vắt và lặng êm. Hàng dừa nghiêng bóng, những chiếc xích đu gỗ thả mình trên mặt nước, và biển hiền hòa quanh năm. Nằm dài trên cát, nghe sóng vỗ nhẹ và ngắm chân trời xanh ngắt, Bãi Sao cho bạn cảm giác bình yên tuyệt đối.', '["Tên ''Bãi Sao'' tương truyền vì xưa sao biển dạt vào bờ rất nhiều.","Cát trắng mịn và nước biển trong vào loại đẹp nhất đảo.","Nằm ở phía Nam đảo Phú Quốc, gần thị trấn An Thới."]', '["Đến buổi sáng để biển lặng và ít người.","Thuê xích đu, ghế gỗ và thử hải sản nướng tại bãi."]', 'Tháng 11–4, mùa khô nước trong', 'Nửa ngày', '', 'Cả ngày', '["popular","hidden-gem"]', '["beach","island","photography"]', '[{"seed":"baisao-1","caption":"Bãi cát trắng mịn ven biển xanh","ratio":"16/9"},{"seed":"baisao-2","caption":"Xích đu trên mặt nước","ratio":"4/3"}]', '["phu-quoc-island"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tra-su-forest', 'tra-su-forest', 'an-giang', 'Rừng tràm Trà Sư', 'Tra Su Cajuput Forest', 'park', 105.05, 10.5833, 'Khu rừng tràm ngập nước với thảm bèo xanh mướt, thiên đường chim nước của miền Tây.', 'Chiếc xuồng ba lá khẽ rẽ nước, đưa bạn vào một thế giới xanh huyền diệu. Mặt nước phủ kín bèo tấm xanh non như tấm thảm nhung, hai bên là rừng tràm soi bóng. Đàn cò trắng, chim nước bay rợp trời, tiếng chim ríu rít vang khắp không gian. Trà Sư là khu rừng ngập nước tiêu biểu của vùng Tây sông Hậu, nơi hệ sinh thái đa dạng và cảnh sắc bình yên đến lạ. Ngồi xuồng trôi giữa rừng tràm mùa nước nổi là một trải nghiệm khó quên của miền Tây.', '["Rừng tràm rộng khoảng 845ha, là khu bảo tồn thiên nhiên đất ngập nước.","Là nơi cư trú của nhiều loài chim nước quý hiếm.","Đẹp nhất vào mùa nước nổi tháng 9–11 khi bèo xanh phủ kín mặt nước."]', '["Đi xuồng máy rồi chuyển xuồng chèo tay để vào sâu rừng.","Leo đài quan sát để ngắm toàn cảnh rừng tràm."]', 'Tháng 9–11, mùa nước nổi', 'Nửa ngày', '100.000đ', '07:00 – 17:00', '["hidden-gem","verified"]', '["nature","photography"]', '[{"seed":"trasu-1","caption":"Xuồng trôi giữa thảm bèo xanh","ratio":"16/9"},{"seed":"trasu-2","caption":"Rừng tràm soi bóng nước","ratio":"4/3"},{"seed":"trasu-3","caption":"Rừng tràm soi bóng trên thảm bèo xanh mướt","ratio":"1/1"}]', '["mieu-ba-chua-xu"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('mieu-ba-chua-xu', 'mieu-ba-chua-xu', 'an-giang', 'Miếu Bà Chúa Xứ Núi Sam', 'Ba Chua Xu Temple', 'temple', 105.0747, 10.6792, 'Ngôi miếu linh thiêng dưới chân Núi Sam, điểm hành hương lớn bậc nhất miền Tây Nam Bộ.', 'Dưới chân Núi Sam, Miếu Bà Chúa Xứ uy nghi với mái cong vút và sắc vàng son rực rỡ. Mỗi năm, hàng triệu người hành hương về đây cầu bình an, tài lộc, đặc biệt trong dịp Lễ hội Vía Bà tháng tư âm lịch. Khói nhang nghi ngút, tiếng cầu khấn thành kính hòa cùng nhịp sống tâm linh sôi động. Đây không chỉ là điểm tín ngưỡng mà còn là nét văn hóa đặc sắc của vùng đất Châu Đốc, nơi giao thoa của người Kinh, Khmer, Chăm và Hoa.', '["Lễ hội Vía Bà Chúa Xứ Núi Sam là Di sản văn hóa phi vật thể quốc gia.","Thu hút hàng triệu lượt khách hành hương mỗi năm.","Nằm dưới chân Núi Sam, gần thành phố Châu Đốc."]', '["Đi vào dịp Lễ hội Vía Bà (tháng 4 âm lịch) để cảm nhận không khí lễ hội.","Ăn mặc lịch sự khi vào miếu và cẩn thận tư trang nơi đông người."]', 'Tháng 4 âm lịch (mùa lễ hội)', '1–2 giờ', '', 'Cả ngày', '["festival","popular"]', '["temple","culture","history"]', '[{"seed":"bachuaxu-1","caption":"Miếu Bà Chúa Xứ uy nghi","ratio":"16/9"},{"seed":"bachuaxu-2","caption":"Khói nhang ngày lễ hội","ratio":"4/3"}]', '["tra-su-forest"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('buon-don', 'buon-don', 'dak-lak', 'Buôn Đôn', 'Buon Don', 'village', 107.7833, 12.9, 'Quê hương của nghề săn và thuần dưỡng voi, đậm đà bản sắc văn hóa Tây Nguyên.', 'Buôn Đôn là vùng đất huyền thoại bên dòng Sêrêpốk cuộn chảy, nơi gắn liền với nghề săn bắt và thuần dưỡng voi rừng lâu đời. Những cây cầu treo bằng tre nứa đung đưa nối các cồn đảo giữa sông, nhà sàn dài của người Ê Đê, M''Nông ẩn dưới tán cây cổ thụ. Bên ánh lửa bập bùng, tiếng cồng chiêng vang vọng, chén rượu cần truyền tay nhau, người Tây Nguyên kể cho bạn nghe những câu chuyện về rừng, về voi và về một nền văn hóa hào sảng giữa đại ngàn.', '["Nổi tiếng với nghề săn và thuần dưỡng voi rừng truyền thống.","Nằm bên dòng sông Sêrêpốk chảy ngược về hướng Tây.","Là nơi sinh sống của người Ê Đê, M''Nông, Lào với văn hóa cồng chiêng."]', '["Trải nghiệm văn hóa cồng chiêng và rượu cần cùng người bản địa.","Đi cầu treo qua sông và tham quan nhà sàn truyền thống."]', 'Tháng 11–4, mùa khô Tây Nguyên', 'Nửa ngày', '20.000đ', '07:00 – 17:00', '["hidden-gem","verified"]', '["village","culture","nature"]', '[{"seed":"buondon-1","caption":"Cầu treo bằng tre qua sông Sêrêpốk","ratio":"16/9"},{"seed":"buondon-2","caption":"Nhà sàn dài Tây Nguyên","ratio":"4/3"},{"seed":"buondon-3","caption":"Đêm cồng chiêng bên lửa","ratio":"1/1"}]', '["dray-nur-waterfall"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dray-nur-waterfall', 'dray-nur-waterfall', 'dak-lak', 'Thác Dray Nur', 'Dray Nur Waterfall', 'waterfall', 107.9847, 12.5375, 'Thác nước hùng vĩ rộng nhất Tây Nguyên, tung bọt trắng xóa giữa đại ngàn xanh.', 'Thác Dray Nur đổ xuống như một bức tường nước khổng lồ, tiếng gầm vang dội cả một vùng. Dòng Sêrêpốk hung dữ lao mình qua vách đá, tung bọt trắng xóa, hơi nước mát lạnh phủ kín không gian. Phía sau màn nước là một hang động bí ẩn gắn với truyền thuyết tình yêu của người Ê Đê. Bao quanh thác là rừng cây xanh mướt, dây leo chằng chịt. Đứng trước Dray Nur, bạn cảm nhận trọn vẹn sức mạnh hoang dã và vẻ đẹp dữ dội của thiên nhiên Tây Nguyên.', '["Là thác nước rộng nhất Tây Nguyên, rộng khoảng 250m.","Tên ''Dray Nur'' theo tiếng Ê Đê nghĩa là ''thác cái''.","Phía sau thác có hang động lớn gắn với truyền thuyết của người Ê Đê."]', '["Mang dép chống trượt vì đường quanh thác trơn ướt.","Khám phá hang động phía sau màn nước nếu nước cạn."]', 'Tháng 6–11, mùa mưa thác cuộn nước', '2–3 giờ', '30.000đ', '07:00 – 17:00', '["hidden-gem"]', '["nature","photography"]', '[{"seed":"draynur-1","caption":"Bức tường nước tung bọt trắng","ratio":"16/9"},{"seed":"draynur-2","caption":"Dòng Sêrêpốk hùng vĩ","ratio":"4/3"}]', '["buon-don"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('moc-chau-plateau', 'moc-chau-plateau', 'son-la', 'Cao nguyên Mộc Châu', 'Moc Chau Plateau', 'mountain', 104.6833, 20.8333, 'Cao nguyên xanh mướt với đồi chè, rừng mận trắng và những mùa hoa nối tiếp quanh năm.', 'Mộc Châu trải ra trước mắt bạn một thảo nguyên xanh mênh mông, nơi những đồi chè uốn lượn như sóng và không khí trong lành mát rượi. Mùa xuân, hoa mận, hoa cải nở trắng cả triền đồi; mùa thu, cao nguyên ngập trong sắc dã quỳ vàng. Đàn bò sữa thong dong gặm cỏ, bản làng người Mông, Thái nép mình bên sườn núi. Một ly sữa tươi nóng giữa cái se lạnh cao nguyên, ngắm sương sớm giăng mờ trên đồi chè — Mộc Châu khiến lòng người dịu lại.', '["Cao nguyên ở độ cao trung bình khoảng 1.050m, khí hậu mát quanh năm.","Nổi tiếng với đồi chè trái tim, rừng mận Nà Ka và bò sữa Mộc Châu.","Mùa hoa mận, hoa cải trắng đẹp nhất vào tháng 11–2."]', '["Ghé đồi chè trái tim và thác Dải Yếm để chụp ảnh.","Thử bê chao, sữa tươi và bắp cải mèo đặc sản."]', 'Tháng 11–2 (mùa hoa) và tháng 9 (hoa cải)', '2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["mountain","nature","photography"]', '[{"seed":"mocchau-1","caption":"Đồi chè trái tim","ratio":"16/9"},{"seed":"mocchau-2","caption":"Rừng mận nở trắng triền đồi","ratio":"4/3"},{"seed":"mocchau-3","caption":"Sương sớm trên thảo nguyên","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('mui-ne-sand-dunes', 'mui-ne-sand-dunes', 'binh-thuan', 'Đồi cát Mũi Né', 'Mui Ne Sand Dunes', 'beach', 108.2917, 10.9472, 'Sa mạc thu nhỏ với đồi cát vàng và cát đỏ uốn lượn, nơi hoàng hôn nhuộm cát rực rỡ.', 'Đồi cát Mũi Né như một mảnh sa mạc lạc giữa miền biển Bình Thuận. Những đụn cát vàng, cát đỏ uốn lượn vô tận, đổi hình theo gió mỗi ngày. Bình minh và hoàng hôn là lúc đẹp nhất, khi ánh nắng xiên nghiêng nhuộm cát thành màu cam đỏ huyền ảo, đổ bóng những gợn sóng cát mềm mại. Trượt cát từ đỉnh đồi xuống, để gió biển mơn man, ngắm chân trời mở rộng — Mũi Né mang đến cảm giác phiêu lưu giữa khung cảnh siêu thực hiếm có ở Việt Nam.', '["Gồm hai khu nổi tiếng: Đồi cát Bay (cát vàng) và Đồi cát Hồng (cát đỏ).","Hình dạng đụn cát thay đổi liên tục theo hướng gió.","Là điểm chụp ảnh bình minh và hoàng hôn nổi tiếng của Bình Thuận."]', '["Đi lúc sáng sớm hoặc chiều muộn để tránh nắng gắt và ngắm ánh sáng đẹp.","Thuê ván trượt cát và mang theo nước uống."]', 'Tháng 11–4, mùa khô ít mưa', '2–3 giờ', '', 'Cả ngày', '["popular","verified"]', '["beach","nature","photography"]', '[{"seed":"muine-1","caption":"Làng chài tấp nập thuyền ghe neo đậu ven biển","ratio":"16/9"},{"seed":"muine-2","caption":"Cát đỏ Mũi Né","ratio":"4/3"},{"seed":"muine-3","caption":"Trượt cát trên đỉnh đồi","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('cai-rang-floating-market', 'cai-rang-floating-market', 'can-tho', 'Chợ nổi Cái Răng', 'Cai Rang Floating Market', 'market', 105.7639, 10.0086, 'Chợ nổi sầm uất nhất miền Tây, nơi cuộc sống sông nước hội tụ trên những ghe thuyền đầy ắp.', 'Khi trời còn tờ mờ sáng, Chợ nổi Cái Răng đã rộn ràng trên dòng sông Hậu. Hàng trăm ghe thuyền tụ về, mỗi chiếc treo lên ''cây bẹo'' cắm các loại hàng để rao bán — khóm, dưa hấu, khoai, rau củ chất đầy khoang. Tiếng máy ghe, tiếng mua bán, tiếng cười nói hòa vào nhau tạo nên bản giao hưởng sông nước đặc trưng. Ngồi trên ghe nhỏ, nhâm nhi tô hủ tiếu nóng và ly cà phê giữa chợ nổi, bạn cảm nhận trọn vẹn nhịp sống phóng khoáng, chân chất của người miền Tây.', '["Là chợ nổi lớn và sầm uất nhất Đồng bằng sông Cửu Long.","Người bán treo hàng lên ''cây bẹo'' để khách từ xa biết bán gì.","Văn hóa chợ nổi Cái Răng là Di sản văn hóa phi vật thể quốc gia."]', '["Đi từ 5–7h sáng khi chợ đông và nhộn nhịp nhất.","Thử ăn sáng trên ghe: hủ tiếu, bún và cà phê."]', 'Quanh năm; sáng sớm là đẹp nhất', 'Nửa ngày', '', '05:00 – 09:00', '["popular","verified"]', '["market","culture","food"]', '[{"seed":"cairang-1","caption":"Ghe thuyền tụ về chợ nổi sáng sớm","ratio":"16/9"},{"seed":"cairang-2","caption":"Ghe hàng treo cây bẹo dập dềnh trên sông buổi sớm","ratio":"4/3"},{"seed":"cairang-3","caption":"Người phụ nữ chèo ghe chở đầy bắp cải đi bán","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dien-bien-phu-battlefield', 'dien-bien-phu-battlefield', 'dien-bien', 'Di tích Chiến trường Điện Biên Phủ', 'Dien Bien Phu Battlefield', 'museum', 103.0167, 21.3833, 'Chiến trường lịch sử lừng lẫy năm châu, nơi làm nên chiến thắng ''chấn động địa cầu'' năm 1954.', 'Đặt chân tới Điện Biên Phủ là chạm vào một trang sử hào hùng của dân tộc. Đồi A1 còn nguyên dấu tích chiến hào, hố bộc phá khổng lồ, nơi diễn ra trận đánh ác liệt nhất. Hầm De Castries — sở chỉ huy quân Pháp — vẫn lặng im như một chứng nhân. Bảo tàng Chiến thắng Điện Biên Phủ tái hiện sống động 56 ngày đêm ''khoét núi, ngủ hầm'' của quân và dân ta. Đứng giữa thung lũng Mường Thanh xanh mướt hôm nay, bạn cảm nhận sâu sắc giá trị của hòa bình và sự hy sinh anh dũng đã làm nên chiến thắng lừng lẫy năm châu.', '["Chiến thắng Điện Biên Phủ ngày 7/5/1954 ''lừng lẫy năm châu, chấn động địa cầu''.","Đồi A1 là điểm cao chiến lược với trận đánh khốc liệt nhất chiến dịch.","Tượng đài Chiến thắng Điện Biên Phủ là tượng đài bằng đồng lớn nhất Việt Nam."]', '["Ghé Bảo tàng, Đồi A1 và Hầm De Castries để hiểu trọn câu chuyện.","Đến dịp 7/5 để dự lễ kỷ niệm Chiến thắng Điện Biên Phủ."]', 'Tháng 3–5; dịp 7/5 lễ kỷ niệm', '1 ngày', '100.000đ', '07:00 – 17:00', '["verified","popular"]', '["history","culture","museum"]', '[{"seed":"dienbienphu-1","caption":"Tượng đài Chiến thắng Điện Biên Phủ","ratio":"16/9"},{"seed":"dienbienphu-2","caption":"Chiến hào trên Đồi A1","ratio":"4/3"},{"seed":"dienbienphu-3","caption":"Hầm De Castries","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ban-gioc-waterfall', 'thac-ban-gioc', 'cao-bang', 'Thác Bản Giốc', 'Ban Gioc Waterfall', 'waterfall', 106.7227, 22.8536, 'Thác nước biên giới hùng vĩ bậc nhất Đông Nam Á, nước đổ tầng tầng giữa núi đá vôi và ruộng lúa xanh.', 'Nằm nơi địa đầu Tổ quốc, Thác Bản Giốc đổ xuống ba tầng nước trắng xóa giữa khung cảnh núi non trùng điệp của Cao Bằng. Vào mùa nước, dòng Quây Sơn cuộn chảy rộng tới hàng trăm mét, tung bọt mịt mù trong nắng tạo nên cầu vồng lung linh. Du khách thường ngồi bè tre lướt sát chân thác, cảm nhận hơi nước mát lạnh phả vào mặt. Quanh thác là những thửa ruộng bậc thang, bản làng người Tày, Nùng yên bình. Bình minh và hoàng hôn nơi đây đẹp đến nao lòng, khiến Bản Giốc trở thành biểu tượng của vùng non nước Cao Bằng.', '["Là thác nước tự nhiên lớn nhất Đông Nam Á và lớn thứ tư thế giới nằm trên đường biên giới.","Dòng sông Quây Sơn tạo thành thác, chia ranh giới tự nhiên giữa Việt Nam và Trung Quốc.","Thác cao khoảng 30m, trải rộng trên 200m với ba tầng nước.","Nằm trong Công viên địa chất toàn cầu UNESCO Non nước Cao Bằng."]', '["Đi vào tháng 9–10 khi nước nhiều và lúa chín vàng quanh thác.","Thuê bè tre để tới gần chân thác và chụp ảnh đẹp nhất."]', 'Tháng 9 đến tháng 10', 'Nửa ngày', '45.000đ', '07:00 - 17:00', '["popular","verified","trending"]', '["nature","photography","mountain"]', '[{"seed":"ban-gioc-waterfall-1","caption":"Ba tầng thác Bản Giốc mùa nước đổ","ratio":"16/9"},{"seed":"ban-gioc-waterfall-2","caption":"Du khách tắm mát dưới chân thác trắng xóa","ratio":"4/3"},{"seed":"ban-gioc-waterfall-3","caption":"Dòng thác đổ trắng xóa giữa rừng xanh","ratio":"1/1"}]', '["nguom-ngao-cave"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nguom-ngao-cave', 'dong-nguom-ngao', 'cao-bang', 'Động Ngườm Ngao', 'Nguom Ngao Cave', 'cave', 106.7081, 22.8419, 'Hang động đá vôi kỳ ảo dài hàng cây số với vô vàn nhũ đá hình thù độc đáo, ngay cạnh Thác Bản Giốc.', 'Ẩn mình trong lòng núi bản Gun, Động Ngườm Ngao mở ra một thế giới ngầm huyền bí với những khối nhũ đá rủ xuống lấp lánh như châu báu. Tên gọi theo tiếng Tày nghĩa là ''hang hổ'', gắn với truyền thuyết xưa từng có hổ trú ngụ. Đi sâu vào lòng động, du khách gặp những măng đá hình cây tơ hồng, đài sen úp ngược, ruộng bậc thang thu nhỏ được kiến tạo qua hàng triệu năm. Không khí mát lạnh, tiếng nước nhỏ tí tách vang vọng tạo cảm giác lạc vào chốn tiên cảnh. Hệ thống đèn nghệ thuật làm nổi bật vẻ kỳ vĩ của từng phiến đá.', '["Tên ''Ngườm Ngao'' theo tiếng Tày nghĩa là động hổ.","Tổng chiều dài hệ thống hang khoảng 2.144m.","Được phát hiện năm 1921 và đưa vào khai thác du lịch từ năm 1996.","Thuộc Công viên địa chất toàn cầu UNESCO Non nước Cao Bằng."]', '["Mang giày chống trượt vì nền động ẩm ướt.","Kết hợp tham quan cùng Thác Bản Giốc chỉ cách vài cây số."]', 'Quanh năm', '1 - 2 giờ', '45.000đ', '07:30 - 17:00', '["verified","hidden-gem"]', '["nature","photography"]', '[{"seed":"nguom-ngao-cave-1","caption":"Rừng nhũ đá trong lòng động","ratio":"16/9"},{"seed":"nguom-ngao-cave-2","caption":"Măng đá hình đài sen","ratio":"4/3"},{"seed":"nguom-ngao-cave-3","caption":"Lối đi ánh đèn nghệ thuật","ratio":"1/1"}]', '["ban-gioc-waterfall"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ba-be-lake', 'ho-ba-be', 'bac-kan', 'Hồ Ba Bể', 'Ba Be Lake', 'lake', 105.6181, 22.4022, 'Hồ nước ngọt tự nhiên lớn nhất Việt Nam, mặt nước xanh ngắt ôm trọn núi rừng nguyên sinh Vườn quốc gia Ba Bể.', 'Giữa đại ngàn Bắc Kạn, Hồ Ba Bể trải dài như một dải lụa xanh phẳng lặng được bao bọc bởi những vách núi đá vôi và rừng nguyên sinh. Đây là hồ nước ngọt tự nhiên trên núi lớn nhất nước, hình thành cách đây hơn 200 triệu năm. Ngồi thuyền độc mộc lướt trên mặt hồ, du khách nghe tiếng chèo khua nhẹ, ngắm Ao Tiên, đảo Bà Góa và động Puông kỳ vĩ. Hai bên bờ là bản làng người Tày với những nếp nhà sàn cổ kính. Hoàng hôn buông, mặt hồ nhuộm vàng cam, đàn cò bay về tổ tạo nên khung cảnh thanh bình hiếm có.', '["Là một trong 20 hồ nước ngọt tự nhiên đẹp nhất thế giới.","Diện tích mặt hồ khoảng 650 ha, độ sâu trung bình 20–25m.","Nằm trong Vườn quốc gia Ba Bể, khu Ramsar thứ ba của Việt Nam.","Được tạo bởi ba nhánh sông nên có tên ''Ba Bể''."]', '["Đi thuyền độc mộc do người Tày chèo để khám phá lòng hồ.","Nghỉ homestay nhà sàn ở bản Pác Ngòi để trải nghiệm văn hóa địa phương."]', 'Tháng 4 đến tháng 11', '1 - 2 ngày', '25.000đ', '06:00 - 18:00', '["popular","verified","trending"]', '["nature","photography","culture"]', '[{"seed":"ba-be-lake-1","caption":"Thuyền độc mộc trên hồ Ba Bể","ratio":"16/9"},{"seed":"ba-be-lake-2","caption":"Mặt hồ lấp lánh ôm đảo nhỏ trong sương sớm","ratio":"4/3"},{"seed":"ba-be-lake-3","caption":"Hồ nước phẳng lặng giữa núi non mờ sương","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tam-thanh-cave', 'dong-tam-thanh', 'lang-son', 'Động Tam Thanh', 'Tam Thanh Cave', 'cave', 106.7558, 21.8567, 'Động đá vôi linh thiêng giữa lòng thành phố Lạng Sơn, nổi tiếng với chùa cổ trong hang và ''Đệ nhất bát cảnh xứ Lạng''.', 'Nằm trong dãy núi đá vôi ngay giữa phố phường Lạng Sơn, Động Tam Thanh từ lâu được mệnh danh là ''Đệ nhất bát cảnh xứ Lạng''. Bước qua cổng đá, du khách lạc vào không gian linh thiêng với ngôi chùa Tam Thanh được tạc thẳng vào vách hang từ thời Lê. Bên trong, tượng Phật A Di Đà khắc nổi trên đá, hồ Âm Ti nước trong vắt quanh năm và những khối thạch nhũ buông rủ huyền ảo. Qua khe núi, du khách phóng tầm mắt ngắm ''cửa trời'' đón ánh sáng tự nhiên. Tiếng chuông chùa ngân vang trong động tạo nên cảm giác tĩnh tại, thiêng liêng giữa lòng thành phố biên cương.', '["Được người xưa xếp vào ''Trấn doanh bát cảnh'' của xứ Lạng.","Chùa Tam Thanh trong động được xây dựng từ thời nhà Lê.","Có bức phù điêu tượng Phật A Di Đà tạc vào vách đá cao gần 2m.","Trong động có hồ Âm Ti nước không bao giờ cạn."]', '["Ghé thăm cùng nàng Tô Thị và thành nhà Mạc ngay gần đó.","Đi buổi sáng để ánh sáng từ ''cửa trời'' đẹp nhất."]', 'Quanh năm', '1 - 2 giờ', '20.000đ', '07:00 - 18:00', '["verified","popular"]', '["culture","history","nature"]', '[{"seed":"tam-thanh-cave-1","caption":"Chùa cổ trong động Tam Thanh","ratio":"16/9"},{"seed":"tam-thanh-cave-2","caption":"Phù điêu Phật A Di Đà trên vách đá","ratio":"4/3"},{"seed":"tam-thanh-cave-3","caption":"Cửa trời đón nắng","ratio":"1/1"}]', '["mau-son-mountain"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('mau-son-mountain', 'nui-mau-son', 'lang-son', 'Núi Mẫu Sơn', 'Mau Son Mountain', 'mountain', 107.0228, 21.8581, 'Đỉnh núi mây phủ quanh năm, nơi hiếm hoi miền Bắc có băng tuyết mùa đông và những đồi đào, chè cổ thụ.', 'Cao hơn 1.500m so với mực nước biển, Mẫu Sơn là vùng núi mây mù bao phủ quanh năm nơi biên giới Lạng Sơn. Mùa đông, nhiệt độ có khi xuống dưới 0 độ, băng giá phủ trắng cây cối tạo nên cảnh tượng kỳ ảo hiếm thấy ở miền Bắc. Trên đỉnh núi còn dấu tích những biệt thự nghỉ dưỡng cổ thời Pháp rêu phong giữa biển mây. Người Dao đỏ sinh sống nơi đây gìn giữ nghề thuốc tắm lá truyền thống và những vườn đào, chè cổ thụ. Du khách lên Mẫu Sơn để săn mây, ngắm bình minh và thưởng thức gà sáu cựa, rượu Mẫu Sơn nồng ấm.', '["Gồm khoảng 80 ngọn núi lớn nhỏ, đỉnh cao nhất hơn 1.500m.","Là một trong số ít nơi miền Bắc xuất hiện băng tuyết vào mùa đông.","Nổi tiếng với rượu Mẫu Sơn ủ men lá của người Dao.","Còn lưu giữ phế tích biệt thự nghỉ dưỡng từ thời Pháp thuộc."]', '["Mang áo ấm dày kể cả mùa hè vì đỉnh núi rất lạnh.","Trải nghiệm tắm lá thuốc của người Dao đỏ để thư giãn."]', 'Tháng 12 đến tháng 2', '1 ngày', '', 'Cả ngày', '["hidden-gem","verified"]', '["mountain","nature","photography"]', '[{"seed":"mau-son-mountain-1","caption":"Biển mây trên đỉnh Mẫu Sơn","ratio":"16/9"},{"seed":"mau-son-mountain-2","caption":"Băng giá phủ trắng cây mùa đông","ratio":"4/3"},{"seed":"mau-son-mountain-3","caption":"Phế tích biệt thự Pháp cổ","ratio":"1/1"}]', '["tam-thanh-cave"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tan-trao-relic', 'khu-di-tich-tan-trao', 'tuyen-quang', 'Khu di tích Tân Trào', 'Tan Trao Historical Site', 'village', 105.4017, 21.8472, 'Thủ đô kháng chiến giữa rừng Tuyên Quang, nơi gắn liền cây đa Tân Trào, lán Nà Nưa và Quốc dân Đại hội năm 1945.', 'Giữa đại ngàn Tuyên Quang, Tân Trào được khắc ghi như ''Thủ đô khu giải phóng'' của cách mạng Việt Nam. Dưới bóng cây đa Tân Trào cổ thụ, Việt Nam Giải phóng quân từng làm lễ xuất quân tiến về giải phóng Thái Nguyên năm 1945. Cách đó không xa là lán Nà Nưa đơn sơ bằng tre nứa, nơi Chủ tịch Hồ Chí Minh sống và làm việc trong những ngày tiền khởi nghĩa. Đình Tân Trào lưu dấu Quốc dân Đại hội lịch sử. Đến đây, du khách lặng mình giữa rừng cọ, đồi chè, lắng nghe câu chuyện hào hùng của một thời dựng nước giữa núi rừng Việt Bắc.', '["Là nơi diễn ra Quốc dân Đại hội tháng 8 năm 1945.","Cây đa Tân Trào là nơi Việt Nam Giải phóng quân làm lễ xuất quân.","Lán Nà Nưa là nơi Bác Hồ ở và làm việc năm 1945.","Được xếp hạng Di tích quốc gia đặc biệt."]', '["Thuê hướng dẫn viên để hiểu trọn vẹn câu chuyện lịch sử.","Kết hợp tham quan các điểm trong cụm di tích bằng xe điện."]', 'Quanh năm', 'Nửa ngày', '', '07:00 - 17:00', '["verified","popular"]', '["history","culture"]', '[{"seed":"tan-trao-relic-1","caption":"Cây đa Tân Trào cổ thụ","ratio":"16/9"},{"seed":"tan-trao-relic-2","caption":"Lán Nà Nưa giữa rừng","ratio":"4/3"},{"seed":"tan-trao-relic-3","caption":"Đình Tân Trào lịch sử","ratio":"1/1"}]', '["mo-na-hang-waterfall"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('mo-na-hang-waterfall', 'thac-mo-na-hang', 'tuyen-quang', 'Thác Mơ Nà Hang', 'Mo Na Hang Waterfall', 'waterfall', 105.3839, 22.3389, 'Dòng thác trắng mềm mại đổ từ đỉnh núi Pắc Ban, ẩn mình giữa rừng nguyên sinh và hồ thủy điện xanh ngắt Nà Hang.', 'Nép mình dưới chân núi Pắc Ban giữa khu bảo tồn thiên nhiên Nà Hang, Thác Mơ tuôn chảy như dải lụa trắng vắt ngang sườn núi xanh thẫm. Đi qua con đường rừng rợp bóng cây, du khách bắt gặp dòng nước mát lành đổ qua nhiều tầng đá, tạo nên những hồ nước trong vắt để tắm mát. Truyền thuyết kể về đôi trai gái yêu nhau hóa thành dòng thác, khiến nơi đây thêm phần thơ mộng. Kết hợp đi thuyền trên hồ thủy điện Nà Hang xanh biếc, ngắm những vách núi soi bóng nước, hành trình tới Thác Mơ là một trải nghiệm thiên nhiên trong trẻo, đậm chất núi rừng Tuyên Quang.', '["Thác bắt nguồn từ đỉnh núi Pắc Ban cao gần 1.000m.","Nằm trong Khu bảo tồn thiên nhiên Nà Hang - Lâm Bình.","Gắn với truyền thuyết tình yêu đôi trai gái hóa dòng thác.","Thường kết hợp với tour du thuyền hồ thủy điện Nà Hang."]', '["Đi vào mùa mưa để thác nhiều nước và hùng vĩ nhất.","Kết hợp du thuyền ngắm hồ Nà Hang và núi Pắc Tạ."]', 'Tháng 5 đến tháng 9', 'Nửa ngày', '', '07:00 - 18:00', '["hidden-gem","verified"]', '["nature","photography","mountain"]', '[{"seed":"mo-na-hang-waterfall-1","caption":"Thác Mơ buông xuống sườn núi","ratio":"16/9"},{"seed":"mo-na-hang-waterfall-2","caption":"Hồ nước trong dưới chân thác","ratio":"4/3"},{"seed":"mo-na-hang-waterfall-3","caption":"Du thuyền hồ Nà Hang","ratio":"1/1"}]', '["tan-trao-relic"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nui-coc-lake', 'ho-nui-coc', 'thai-nguyen', 'Hồ Núi Cốc', 'Nui Coc Lake', 'lake', 105.7236, 21.5439, 'Hồ nước thơ mộng với hàng chục hòn đảo nhỏ, gắn liền huyền thoại nàng Công - chàng Cốc và những đồi chè bát ngát.', 'Hồ Núi Cốc trải rộng mênh mông dưới chân dãy Tam Đảo, mặt nước xanh êm điểm xuyết hàng chục đảo nhỏ nhấp nhô như tranh thủy mặc. Hồ gắn liền truyền thuyết tình yêu bi thương của nàng Công và chàng Cốc, nước mắt nàng chảy thành dòng sông Công tạo nên hồ. Du khách lên thuyền dạo quanh các đảo Cò, đảo Núi Cái, ghé khu du lịch với động Huyền Thoại Cung và những công trình mô phỏng câu chuyện tình. Bao quanh hồ là đồi chè Thái Nguyên ngút ngàn, nơi sản sinh thứ trà thơm nức tiếng. Buổi sớm sương giăng trên mặt hồ tạo nên khung cảnh huyền ảo, lãng mạn.', '["Là hồ nhân tạo hình thành từ đập sông Công, hoàn thành năm 1978.","Lòng hồ có hơn 89 hòn đảo lớn nhỏ.","Gắn với huyền thoại tình yêu nàng Công - chàng Cốc.","Nằm gần vùng chè đặc sản Tân Cương nổi tiếng."]', '["Đi thuyền dạo quanh các đảo nhỏ trên hồ.","Kết hợp thưởng trà tại các đồi chè Tân Cương lân cận."]', 'Tháng 4 đến tháng 9', 'Nửa ngày đến 1 ngày', '50.000đ', '07:00 - 18:00', '["popular","verified"]', '["nature","culture","photography"]', '[{"seed":"nui-coc-lake-1","caption":"Đảo nhỏ giữa lòng hồ Núi Cốc","ratio":"16/9"},{"seed":"nui-coc-lake-2","caption":"Sương sớm trên mặt hồ","ratio":"4/3"},{"seed":"nui-coc-lake-3","caption":"Thuyền dạo quanh hồ","ratio":"1/1"}]', '["tan-cuong-tea-hills"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tan-cuong-tea-hills', 'doi-che-tan-cuong', 'thai-nguyen', 'Đồi chè Tân Cương', 'Tan Cuong Tea Hills', 'park', 105.7619, 21.55, 'Vùng đất ''đệ nhất danh trà'' với những đồi chè xanh mướt uốn lượn, nơi sản sinh trà Thái Nguyên trứ danh cả nước.', 'Cách thành phố Thái Nguyên không xa, Tân Cương hiện ra với những đồi chè xanh mướt trải dài, uốn lượn mềm mại như sóng dưới ánh nắng ban mai. Đây là cái nôi của trà Thái Nguyên, thứ ''đệ nhất danh trà'' với hương cốm thanh tao và vị chát dịu hậu ngọt đặc trưng. Du khách dạo bước giữa các luống chè, ngắm những người nông dân khéo léo hái búp non, rồi ghé thăm xưởng sao trà để tận mắt chứng kiến quy trình thủ công truyền thống. Một chén trà nóng nhâm nhi giữa đồi chè bát ngát, gió mát lành thổi qua, là trải nghiệm bình yên khó quên nơi miền trung du Thái Nguyên.', '["Tân Cương được mệnh danh là vùng ''đệ nhất danh trà'' của Việt Nam.","Cây chè được trồng tại đây từ những năm 1920.","Trà Tân Cương nổi tiếng với hương cốm và vị chát hậu ngọt.","Có Không gian văn hóa trà giới thiệu nghề làm trà truyền thống."]', '["Đến sáng sớm để ngắm đồi chè còn đọng sương.","Ghé hộ làm trà để xem sao trà và mua trà chính gốc."]', 'Tháng 3 đến tháng 5', 'Nửa ngày', '', 'Cả ngày', '["verified","hidden-gem"]', '["nature","food","photography"]', '[{"seed":"tan-cuong-tea-hills-1","caption":"Đồi chè xanh mướt uốn lượn","ratio":"16/9"},{"seed":"tan-cuong-tea-hills-2","caption":"Hái búp chè non buổi sớm","ratio":"4/3"},{"seed":"tan-cuong-tea-hills-3","caption":"Chén trà giữa đồi chè","ratio":"1/1"}]', '["nui-coc-lake"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('den-hung-temple', 'den-hung', 'phu-tho', 'Đền Hùng', 'Hung Kings Temple', 'temple', 105.3239, 21.3658, 'Khu di tích thiêng liêng thờ các Vua Hùng trên núi Nghĩa Lĩnh, cội nguồn dân tộc và nơi diễn ra Giỗ Tổ Hùng Vương.', 'Tọa lạc trên núi Nghĩa Lĩnh, Khu di tích Đền Hùng là nơi cội nguồn thiêng liêng của dân tộc Việt, thờ các Vua Hùng đã có công dựng nước. Từ chân núi, du khách leo qua hàng trăm bậc đá rợp bóng cây cổ thụ, lần lượt viếng Đền Hạ, Đền Trung, Đền Thượng rồi tới Lăng Vua Hùng. Mỗi ngôi đền cổ kính phủ rêu phong là một dấu son trong truyền thuyết dựng nước. Vào ngày mùng 10 tháng 3 âm lịch, hàng triệu người con đất Việt hành hương về đây dự Giỗ Tổ, dâng hương tưởng nhớ tổ tiên. Câu ca ''Dù ai đi ngược về xuôi, nhớ ngày Giỗ Tổ mùng mười tháng ba'' vang vọng ngàn đời.', '["Thờ 18 đời Vua Hùng, được coi là quốc tổ của người Việt.","Tín ngưỡng thờ cúng Hùng Vương được UNESCO ghi danh Di sản văn hóa phi vật thể năm 2012.","Giỗ Tổ Hùng Vương diễn ra ngày mùng 10 tháng 3 âm lịch hằng năm.","Khu di tích trải trên núi Nghĩa Lĩnh với hệ thống Đền Hạ, Trung, Thượng."]', '["Đến dịp Giỗ Tổ mùng 10/3 âm lịch để dự lễ hội lớn nhất.","Mặc trang phục lịch sự và chuẩn bị sức khỏe để leo bậc đá."]', 'Tháng 3 âm lịch', 'Nửa ngày', '', '06:00 - 18:00', '["unesco","festival","verified","popular"]', '["temple","history","culture"]', '[{"seed":"den-hung-temple-1","caption":"Đền Thượng trên núi Nghĩa Lĩnh","ratio":"16/9"},{"seed":"den-hung-temple-2","caption":"Bậc đá rợp bóng cây cổ thụ","ratio":"4/3"},{"seed":"den-hung-temple-3","caption":"Dòng người hành hương Giỗ Tổ","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tay-yen-tu', 'tay-yen-tu', 'bac-giang', 'Tây Yên Tử', 'Tay Yen Tu', 'mountain', 106.725, 21.1789, 'Sườn tây dãy Yên Tử với hệ thống chùa chiền, cáp treo lên chùa Đồng và con đường hoằng dương Phật pháp của Phật hoàng Trần Nhân Tông.', 'Nằm trên sườn tây dãy núi Yên Tử thuộc Bắc Giang, Khu du lịch tâm linh Tây Yên Tử là cửa ngõ tìm về cõi Phật giữa rừng già nguyên sinh. Đây chính là con đường mà Phật hoàng Trần Nhân Tông cùng các thiền sư xưa kia hoằng dương Phật pháp, dựng nên hệ thống chùa tháp dọc sườn núi. Du khách đi cáp treo vượt rừng trúc, suối thác để lên chùa Thượng, chùa Đồng linh thiêng trên đỉnh non thiêng. Không gian chùa Hạ, chùa Trung mới được tôn tạo nguy nga giữa thiên nhiên hùng vĩ. Hành hương Tây Yên Tử, lòng người như lắng lại giữa tiếng chuông chùa và mây núi bồng bềnh.', '["Là sườn tây của dãy Yên Tử, gắn với Thiền phái Trúc Lâm.","Gắn liền hành trình tu hành của Phật hoàng Trần Nhân Tông.","Có tuyến cáp treo đưa du khách lên gần đỉnh chùa Đồng.","Nằm trong quần thể di tích và danh thắng Yên Tử."]', '["Đi lễ hội xuân Tây Yên Tử khai hội đầu năm âm lịch.","Kết hợp đi cáp treo và leo bộ để cảm nhận trọn vẹn không gian."]', 'Tháng 1 đến tháng 3 âm lịch', '1 ngày', '', '06:00 - 18:00', '["festival","verified","trending"]', '["temple","mountain","culture"]', '[{"seed":"tay-yen-tu-1","caption":"Cáp treo vượt rừng lên đỉnh núi","ratio":"16/9"},{"seed":"tay-yen-tu-2","caption":"Chùa giữa mây núi Tây Yên Tử","ratio":"4/3"},{"seed":"tay-yen-tu-3","caption":"Lễ hội xuân Tây Yên Tử","ratio":"1/1"}]', '["vinh-nghiem-pagoda"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vinh-nghiem-pagoda', 'chua-vinh-nghiem', 'bac-giang', 'Chùa Vĩnh Nghiêm', 'Vinh Nghiem Pagoda', 'temple', 106.3197, 21.2542, 'Cổ tự nghìn năm, chốn tổ của Thiền phái Trúc Lâm, nơi lưu giữ kho mộc bản được UNESCO ghi danh Di sản tư liệu.', 'Bên dòng sông Thương hiền hòa, Chùa Vĩnh Nghiêm uy nghi tọa lạc như chốn tổ của Thiền phái Trúc Lâm Yên Tử. Ngôi cổ tự có lịch sử gần nghìn năm này từng là trung tâm Phật giáo lớn, nơi ba vị Tổ Trúc Lâm là Trần Nhân Tông, Pháp Loa và Huyền Quang tu hành, đào tạo tăng đồ. Kiến trúc chùa cổ kính với những nếp nhà gỗ lim, tượng Phật trầm mặc dưới tán cây cổ thụ. Đặc biệt, chùa còn lưu giữ kho mộc bản hơn 3.000 bản khắc kinh Phật bằng gỗ thị, được UNESCO công nhận Di sản tư liệu ký ức thế giới. Vĩnh Nghiêm là nơi tìm về cội nguồn văn hóa, tâm linh dân tộc.', '["Được mệnh danh là chốn tổ của Thiền phái Trúc Lâm.","Kho mộc bản chùa Vĩnh Nghiêm được UNESCO ghi danh Di sản tư liệu năm 2012.","Lưu giữ hơn 3.000 mộc bản khắc kinh Phật bằng gỗ thị.","Có lịch sử khởi dựng từ thời Lý, được mở mang dưới thời Trần."]', '["Tham quan nhà lưu giữ mộc bản để hiểu giá trị di sản.","Ghé vào dịp lễ hội chùa Vĩnh Nghiêm rằm tháng 2 âm lịch."]', 'Quanh năm', '1 - 2 giờ', '', '06:00 - 18:00', '["unesco","verified","festival"]', '["temple","history","culture"]', '[{"seed":"vinh-nghiem-pagoda-1","caption":"Cổng tam quan chùa Vĩnh Nghiêm","ratio":"16/9"},{"seed":"vinh-nghiem-pagoda-2","caption":"Kho mộc bản kinh Phật cổ","ratio":"4/3"},{"seed":"vinh-nghiem-pagoda-3","caption":"Sân chùa dưới tán cây cổ thụ","ratio":"1/1"}]', '["tay-yen-tu"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('mu-cang-chai-terraces', 'ruong-bac-thang-mu-cang-chai', 'yen-bai', 'Ruộng bậc thang Mù Cang Chải', 'Mu Cang Chai Rice Terraces', 'mountain', 104.09, 21.7167, 'Kỳ quan ruộng bậc thang vàng óng mùa lúa chín, di tích quốc gia đặc biệt do người Mông tạo tác qua bao thế hệ.', 'Vắt mình trên những sườn núi cao của Yên Bái, ruộng bậc thang Mù Cang Chải là bản trường ca lao động do người Mông tạo nên qua hàng trăm năm. Mùa nước đổ tháng 5–6, từng thửa ruộng lấp lánh ánh trời như những tấm gương khổng lồ. Đến mùa lúa chín tháng 9–10, cả vùng La Pán Tẩn, Chế Cu Nha, Dế Xu Phình rực lên sắc vàng óng ả tầng tầng lớp lớp, đẹp đến ngỡ ngàng. Du khách trekking giữa các thửa ruộng, ngắm ''mâm xôi'' tròn trịa nổi tiếng, hòa mình vào nhịp sống bản làng vùng cao. Mù Cang Chải mùa lúa chín là điểm hẹn của bao tay máy và lữ khách yêu thiên nhiên.', '["Ruộng bậc thang Mù Cang Chải là Di tích quốc gia đặc biệt.","Do đồng bào dân tộc Mông canh tác qua nhiều thế hệ.","Đồi ''mâm xôi'' ở La Pán Tẩn là điểm chụp ảnh nổi tiếng.","Đẹp nhất vào mùa nước đổ và mùa lúa chín."]', '["Đi tháng 9–10 để ngắm lúa chín vàng rực cả thung lũng.","Vượt đèo Khau Phạ - một trong tứ đại đỉnh đèo - trên đường tới."]', 'Tháng 9 đến tháng 10', '1 - 2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["mountain","nature","photography","culture"]', '[{"seed":"mu-cang-chai-terraces-1","caption":"Ruộng bậc thang vàng óng mùa lúa chín","ratio":"16/9"},{"seed":"mu-cang-chai-terraces-2","caption":"Đồi mâm xôi La Pán Tẩn","ratio":"4/3"},{"seed":"mu-cang-chai-terraces-3","caption":"Mùa nước đổ lấp lánh ánh trời","ratio":"1/1"}]', '["thac-ba-lake"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('thac-ba-lake', 'ho-thac-ba', 'yen-bai', 'Hồ Thác Bà', 'Thac Ba Lake', 'lake', 104.9, 21.9667, 'Một trong ba hồ nước nhân tạo lớn nhất Việt Nam với hơn 1.300 hòn đảo xanh, được ví như ''Hạ Long trên núi''.', 'Hình thành từ công trình thủy điện đầu tiên của miền Bắc, Hồ Thác Bà trải rộng mênh mông với hơn 1.300 hòn đảo lớn nhỏ phủ kín màu xanh, được ví như ''vịnh Hạ Long trên núi''. Mặt hồ phẳng lặng phản chiếu mây trời, len lỏi giữa những dãy núi đá vôi và rừng cây bạt ngàn. Du khách lênh đênh trên thuyền khám phá động Thủy Tiên huyền ảo, đền Thác Bà linh thiêng, hay ghé bản làng người Dao, Tày, Cao Lan ven hồ. Bình minh trên hồ, sương mờ giăng mặt nước, tiếng chim rừng vọng lại tạo nên khung cảnh thanh bình, thơ mộng hiếm nơi nào có được giữa miền núi Yên Bái.', '["Là một trong ba hồ nước nhân tạo lớn nhất Việt Nam.","Hình thành khi xây Nhà máy thủy điện Thác Bà năm 1971.","Có hơn 1.300 hòn đảo lớn nhỏ trên mặt hồ.","Được ví là ''Hạ Long trên núi'' của vùng Tây Bắc."]', '["Thuê thuyền khám phá các đảo và động Thủy Tiên.","Nghỉ homestay ven hồ để ngắm bình minh và hoàng hôn."]', 'Tháng 8 đến tháng 11', '1 ngày', '', '06:00 - 18:00', '["verified","hidden-gem"]', '["nature","photography","culture"]', '[{"seed":"thac-ba-lake-1","caption":"Hàng nghìn đảo xanh trên hồ Thác Bà","ratio":"16/9"},{"seed":"thac-ba-lake-2","caption":"Sương sớm giăng mặt hồ","ratio":"4/3"},{"seed":"thac-ba-lake-3","caption":"Thuyền khám phá lòng hồ","ratio":"1/1"}]', '["mu-cang-chai-terraces"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('o-quy-ho-pass', 'deo-o-quy-ho', 'lai-chau', 'Đèo Ô Quy Hồ', 'O Quy Ho Pass', 'mountain', 103.7733, 22.3528, 'Một trong tứ đại đỉnh đèo Tây Bắc, cung đường mây phủ ngoạn mục nối Lai Châu với Sa Pa qua đỉnh Hoàng Liên Sơn.', 'Vắt qua đỉnh Hoàng Liên Sơn ở độ cao gần 2.000m, Đèo Ô Quy Hồ là một trong ''tứ đại đỉnh đèo'' hùng vĩ nhất Tây Bắc, nối liền Lai Châu và Lào Cai. Cung đường dài gần 50km uốn lượn quanh co bên vách núi dựng đứng, một bên là vực sâu thăm thẳm, một bên là rừng già nguyên sinh. Người ta còn gọi đây là ''đèo Mây'' bởi quanh năm mây mù bao phủ, tạo nên biển mây bồng bềnh mê hoặc. Từ đỉnh đèo phía Lai Châu, du khách phóng tầm mắt ngắm trọn dãy Hoàng Liên Sơn trùng điệp, săn mây, đón hoàng hôn rực rỡ. Mùa đông, đỉnh đèo đôi khi phủ băng tuyết trắng xóa.', '["Là một trong tứ đại đỉnh đèo của vùng núi Tây Bắc.","Đỉnh đèo cao gần 2.000m, dài khoảng 50km.","Còn được gọi là ''đèo Mây'' vì quanh năm mây phủ.","Nối liền hai tỉnh Lai Châu và Lào Cai qua dãy Hoàng Liên Sơn."]', '["Dừng ở Cổng Trời phía Lai Châu để săn mây và ngắm cảnh.","Lái xe cẩn thận vì đường đèo nhiều khúc cua nguy hiểm."]', 'Tháng 9 đến tháng 4', 'Nửa ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["mountain","nature","photography"]', '[{"seed":"o-quy-ho-pass-1","caption":"Biển mây trên đỉnh Ô Quy Hồ","ratio":"16/9"},{"seed":"o-quy-ho-pass-2","caption":"Cung đèo uốn lượn bên vách núi","ratio":"4/3"},{"seed":"o-quy-ho-pass-3","caption":"Hoàng hôn nhìn từ Cổng Trời","ratio":"1/1"}]', '["sin-suoi-ho-village"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('sin-suoi-ho-village', 'ban-sin-suoi-ho', 'lai-chau', 'Bản Sin Suối Hồ', 'Sin Suoi Ho Village', 'village', 103.6228, 22.4419, 'Bản làng người Mông xanh sạch đẹp giữa núi rừng Lai Châu, nổi tiếng với du lịch cộng đồng, hoa địa lan và thác Trái Tim.', 'Nằm cheo leo trên độ cao hơn 1.500m dưới chân dãy Hoàng Liên Sơn, Sin Suối Hồ là bản làng người Mông được mệnh danh đẹp như cổ tích. Từ một bản nghèo, người dân nơi đây đã cùng nhau làm du lịch cộng đồng, biến bản thành điểm đến xanh - sạch - đẹp nức tiếng. Những nếp nhà gỗ pơ mu nép mình giữa vườn hoa địa lan, đào, mận khoe sắc. Du khách trekking tới thác Trái Tim thơ mộng, ghé chợ phiên rực rỡ sắc màu thổ cẩm, thưởng thức ẩm thực bản địa và nghỉ trong homestay ấm cúng. Người Mông hiền hậu, mến khách khiến hành trình tới Sin Suối Hồ thêm phần ấm áp, đáng nhớ.', '["Bản của người Mông nằm ở độ cao hơn 1.500m.","Được vinh danh là Làng du lịch cộng đồng ASEAN.","Nổi tiếng với nghề trồng hoa địa lan và thác Trái Tim.","Là điểm du lịch cộng đồng xanh - sạch - đẹp tiêu biểu của Lai Châu."]', '["Ghé vào chợ phiên cuối tuần để trải nghiệm văn hóa Mông.","Đi mùa xuân để ngắm hoa địa lan và hoa đào nở rộ."]', 'Tháng 12 đến tháng 3', '1 ngày', '', 'Cả ngày', '["hidden-gem","verified","new"]', '["culture","nature","photography"]', '[{"seed":"sin-suoi-ho-village-1","caption":"Bản Mông giữa núi rừng Lai Châu","ratio":"16/9"},{"seed":"sin-suoi-ho-village-2","caption":"Vườn hoa địa lan khoe sắc","ratio":"4/3"},{"seed":"sin-suoi-ho-village-3","caption":"Thác Trái Tim thơ mộng","ratio":"1/1"}]', '["o-quy-ho-pass"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('mai-chau-valley', 'thung-lung-mai-chau', 'hoa-binh', 'Thung lũng Mai Châu', 'Mai Chau Valley', 'village', 105.0533, 20.6597, 'Thung lũng xanh mướt với bản làng người Thái, nhà sàn, ruộng lúa và điệu xòe rộn ràng giữa lòng Hòa Bình.', 'Sau khi vượt đèo Thung Khe mây phủ, Thung lũng Mai Châu hiện ra như bức tranh thanh bình với những thửa ruộng xanh mướt trải dài dưới chân núi. Đây là vùng đất của người Thái trắng, nơi những nếp nhà sàn truyền thống ẩn mình giữa hàng cau, lũy tre. Du khách đạp xe quanh bản Lác, bản Pom Coọng, ghé thăm các khung dệt thổ cẩm rực rỡ và thưởng thức cơm lam, rượu cần. Khi đêm xuống, bên ánh lửa bập bùng, điệu xòe Thái uyển chuyển cùng tiếng khèn, tiếng trống khiến lòng người ngất ngây. Mai Châu mộc mạc, hiếu khách là chốn dừng chân lý tưởng để tận hưởng nhịp sống chậm rãi vùng cao.', '["Là quê hương của đồng bào dân tộc Thái trắng.","Bản Lác là điểm du lịch cộng đồng lâu đời và nổi tiếng nhất.","Nổi tiếng với nghề dệt thổ cẩm truyền thống.","Đường vào thung lũng phải qua đèo Thung Khe (đèo Đá Trắng)."]', '["Thuê xe đạp dạo quanh các bản để cảm nhận nhịp sống.","Nghỉ homestay nhà sàn và xem biểu diễn múa xòe buổi tối."]', 'Tháng 9 đến tháng 11', '1 - 2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["culture","nature","photography","food"]', '[{"seed":"mai-chau-valley-1","caption":"Thung lũng Mai Châu nhìn từ đèo","ratio":"16/9"},{"seed":"mai-chau-valley-2","caption":"Nhà sàn người Thái bản Lác","ratio":"4/3"},{"seed":"mai-chau-valley-3","caption":"Điệu xòe bên ánh lửa","ratio":"1/1"}]', '["hoa-binh-lake"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hoa-binh-lake', 'ho-hoa-binh', 'hoa-binh', 'Hồ Hòa Bình', 'Hoa Binh Lake', 'lake', 105.15, 20.7833, 'Hồ thủy điện rộng lớn ôm trọn núi non sông Đà, được ví như ''Hạ Long thu nhỏ'' với đền Thác Bờ linh thiêng.', 'Trải dài trên dòng sông Đà hùng vĩ, Hồ Hòa Bình là hồ nhân tạo rộng lớn hình thành từ công trình thủy điện Hòa Bình. Mặt hồ xanh thẳm len lỏi giữa hàng trăm hòn đảo và những dãy núi đá vôi trùng điệp, tạo nên cảnh sắc được ví như ''vịnh Hạ Long thu nhỏ'' giữa núi rừng Tây Bắc. Du khách lên thuyền dạo hồ, viếng đền Thác Bờ linh thiêng thờ Bà Chúa Thác, khám phá động Thác Bờ với nhũ đá kỳ ảo. Ven hồ, các bản làng người Mường, Thái cùng những điểm du lịch cộng đồng mời gọi du khách nghỉ dưỡng. Bình minh và hoàng hôn trên hồ Hòa Bình mang vẻ đẹp tĩnh lặng, thơ mộng đắm say lòng người.', '["Hình thành từ Nhà máy thủy điện Hòa Bình trên sông Đà.","Được ví như ''vịnh Hạ Long thu nhỏ'' của vùng Tây Bắc.","Có đền Thác Bờ và động Thác Bờ nổi tiếng linh thiêng.","Ven hồ là các bản làng người Mường, Thái."]', '["Đi thuyền tham quan đền và động Thác Bờ.","Kết hợp nghỉ dưỡng tại các khu du lịch cộng đồng ven hồ."]', 'Tháng 9 đến tháng 12', '1 ngày', '', '06:00 - 18:00', '["verified","popular"]', '["nature","culture","photography"]', '[{"seed":"hoa-binh-lake-1","caption":"Hồ Hòa Bình giữa núi non sông Đà","ratio":"16/9"},{"seed":"hoa-binh-lake-2","caption":"Đền Thác Bờ bên hồ","ratio":"4/3"},{"seed":"hoa-binh-lake-3","caption":"Thuyền dạo trên lòng hồ","ratio":"1/1"}]', '["mai-chau-valley"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hp-cat-ba-island', 'dao-cat-ba', 'hai-phong', 'Đảo Cát Bà', 'Cat Ba Island', 'island', 107.0489, 20.7281, 'Hòn đảo lớn nhất vịnh Lan Hạ với rừng nguyên sinh, bãi tắm trong xanh và những vịnh đá vôi kỳ vĩ.', 'Cát Bà là viên ngọc xanh của Hải Phòng, nơi rừng quốc gia ôm lấy biển và những dãy núi đá vôi nhô lên giữa làn nước ngọc bích. Đảo nổi tiếng với loài voọc Cát Bà quý hiếm chỉ còn vài chục cá thể trên thế giới. Du khách có thể chèo kayak luồn lách qua vịnh Lan Hạ, leo lên đỉnh Ngự Lâm ngắm toàn cảnh, hay thả mình trên những bãi cát trắng mịn. Năm 2023, quần thể vịnh Hạ Long - Cát Bà được UNESCO vinh danh Di sản Thiên nhiên Thế giới, khẳng định vẻ đẹp vượt thời gian của vùng đất này.', '["Là đảo lớn nhất trong quần đảo Cát Bà gồm 367 hòn đảo lớn nhỏ.","Rừng quốc gia Cát Bà là nơi cư trú của voọc Cát Bà cực kỳ nguy cấp.","Được UNESCO công nhận Di sản Thiên nhiên Thế giới năm 2023.","Vịnh Lan Hạ có hơn 130 bãi tắm nhỏ ẩn mình giữa núi đá vôi."]', '["Đặt tour kayak buổi sáng sớm để tránh nắng và đông đúc.","Mang giày bám tốt nếu muốn leo đỉnh Ngự Lâm hoặc trekking trong rừng quốc gia."]', 'Tháng 4 đến tháng 9', '2 ngày 1 đêm', '80.000đ', 'Cả ngày', '["unesco","trending","popular","verified"]', '["island","nature","beach","photography"]', '[{"seed":"hp-cat-ba-island-1","caption":"Vịnh Lan Hạ nhìn từ trên cao","ratio":"16/9"},{"seed":"hp-cat-ba-island-2","caption":"Bãi tắm Cát Cò trong xanh","ratio":"4/3"},{"seed":"hp-cat-ba-island-3","caption":"Rừng quốc gia Cát Bà","ratio":"1/1"}]', '["hp-do-son-beach"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hp-do-son-beach', 'bai-bien-do-son', 'hai-phong', 'Bãi biển Đồ Sơn', 'Do Son Beach', 'beach', 106.7872, 20.7142, 'Bãi biển truyền thống của miền Bắc với hàng phi lao rì rào, sóng êm và lễ hội chọi trâu nức tiếng.', 'Đồ Sơn là điểm nghỉ mát quen thuộc của người Hải Phòng và du khách miền Bắc suốt hơn một thế kỷ. Bán đảo nhô ra biển với ba khu bãi tắm trải dài dưới hàng phi lao xanh, từng là nơi nghỉ dưỡng của vua Bảo Đại và giới thượng lưu thời Pháp. Nơi đây còn nổi tiếng với lễ hội chọi trâu diễn ra mùng 9 tháng 8 âm lịch, một di sản văn hóa phi vật thể quốc gia đầy khí thế. Buổi chiều, du khách dạo bến Nghiêng lịch sử, thưởng thức hải sản tươi rói và ngắm hoàng hôn buông xuống cửa biển.', '["Lễ hội chọi trâu Đồ Sơn là Di sản văn hóa phi vật thể quốc gia.","Từng là khu nghỉ dưỡng của vua Bảo Đại với biệt thự trên đồi.","Bến Nghiêng là nơi lính Pháp cuối cùng rút khỏi miền Bắc năm 1955.","Bãi biển chia thành ba khu I, II, III với cảnh quan khác nhau."]', '["Đến vào dịp lễ hội chọi trâu tháng 8 âm lịch để cảm nhận không khí náo nhiệt.","Thưởng thức hải sản tại các nhà hàng ven bãi II để có giá hợp lý nhất."]', 'Tháng 5 đến tháng 8', '1 ngày', '', 'Cả ngày', '["festival","popular","verified"]', '["beach","culture","food"]', '[{"seed":"hp-do-son-beach-1","caption":"Bãi tắm Đồ Sơn dưới hàng phi lao","ratio":"16/9"},{"seed":"hp-do-son-beach-2","caption":"Lễ hội chọi trâu truyền thống","ratio":"4/3"},{"seed":"hp-do-son-beach-3","caption":"Hoàng hôn trên bán đảo Đồ Sơn","ratio":"1/1"}]', '["hp-cat-ba-island"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bn-den-do', 'den-do', 'bac-ninh', 'Đền Đô', 'Do Temple', 'temple', 105.9686, 21.1239, 'Ngôi đền cổ thờ tám vị vua nhà Lý, kiến trúc bề thế giữa vùng đất Kinh Bắc địa linh nhân kiệt.', 'Đền Đô, hay Cổ Pháp điện, là nơi thờ phụng tám vị vua triều Lý, vương triều khai mở nền văn minh Đại Việt rực rỡ. Tọa lạc tại làng Đình Bảng, đền được xây dựng từ thời Lý Công Uẩn và trùng tu qua nhiều thế kỷ với lối kiến trúc đăng đối, mái cong uy nghi soi bóng xuống hồ bán nguyệt. Mỗi độ rằm tháng ba âm lịch, lễ hội Đền Đô tưng bừng tái hiện cảnh vua Lý Thái Tổ rời đô về Thăng Long. Đây là nơi hội tụ tinh hoa văn hóa Kinh Bắc, gắn liền với những làn quan họ ngọt ngào say đắm lòng người.', '["Thờ tám vị vua triều Lý, bắt đầu từ Lý Thái Tổ Lý Công Uẩn.","Còn được gọi là Cổ Pháp điện, thuộc làng Đình Bảng cổ kính.","Lễ hội Đền Đô diễn ra ngày 15 tháng 3 âm lịch hằng năm.","Nhà Thủy đình trên hồ bán nguyệt là nơi diễn xướng quan họ."]', '["Kết hợp nghe hát quan họ vào dịp lễ hội tháng ba âm lịch.","Ghé thăm đình Đình Bảng gần đó để thưởng lãm kiến trúc gỗ tuyệt mỹ."]', 'Tháng 3 đến tháng 4 âm lịch', 'Nửa ngày', '', '07:00 - 18:00', '["festival","verified","popular"]', '["temple","history","culture"]', '[{"seed":"bn-den-do-1","caption":"Cổng tam quan Đền Đô uy nghi","ratio":"16/9"},{"seed":"bn-den-do-2","caption":"Thủy đình trên hồ bán nguyệt","ratio":"4/3"},{"seed":"bn-den-do-3","caption":"Lễ hội Đền Đô tháng ba","ratio":"1/1"}]', '["bn-dong-ho"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bn-dong-ho', 'lang-tranh-dong-ho', 'bac-ninh', 'Làng tranh Đông Hồ', 'Dong Ho Painting Village', 'village', 106.0631, 21.0561, 'Làng nghề tranh dân gian trứ danh bên dòng sông Đuống, lưu giữ hồn Việt qua từng bản khắc gỗ.', 'Làng Đông Hồ nằm bên bờ sông Đuống thơ mộng, là cái nôi của dòng tranh dân gian độc đáo bậc nhất Việt Nam. Tranh Đông Hồ được in trên giấy điệp lấp lánh vỏ sò, màu sắc hoàn toàn từ thiên nhiên: đỏ son, vàng hoa hòe, xanh lá chàm, đen than lá tre. Những bức Đám cưới chuột, Lợn đàn, Gà đại cát không chỉ đẹp mà còn gửi gắm triết lý nhân sinh và ước vọng no ấm của người nông dân. Trải qua bao thăng trầm, các nghệ nhân nơi đây vẫn miệt mài giữ lửa nghề. Nghề làm tranh Đông Hồ đang được đề nghị UNESCO ghi danh Di sản văn hóa phi vật thể cần bảo vệ khẩn cấp.', '["Tranh được in trên giấy điệp làm từ vỏ sò nghiền pha hồ nếp.","Màu sắc hoàn toàn từ nguyên liệu thiên nhiên truyền thống.","Mỗi bức tranh cần nhiều bản khắc gỗ, mỗi bản một màu riêng.","Nghề tranh Đông Hồ là Di sản văn hóa phi vật thể quốc gia."]', '["Ghé nhà nghệ nhân để tự tay in thử một bức tranh làm kỷ niệm.","Mua tranh trực tiếp tại làng để ủng hộ các gia đình giữ nghề."]', 'Tháng 11 đến tháng 1 (cận Tết)', 'Nửa ngày', '', '08:00 - 17:00', '["verified","hidden-gem","ai-recommended"]', '["village","culture","history"]', '[{"seed":"bn-dong-ho-1","caption":"Nghệ nhân in tranh trên giấy điệp","ratio":"16/9"},{"seed":"bn-dong-ho-2","caption":"Tranh thờ Táo Quân rực rỡ sắc màu dân gian","ratio":"4/3"},{"seed":"bn-dong-ho-3","caption":"Tranh đàn cá chép bơi giữa sen","ratio":"1/1"}]', '["bn-den-do"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hd-con-son-kiep-bac', 'con-son-kiep-bac', 'hai-duong', 'Côn Sơn - Kiếp Bạc', 'Con Son - Kiep Bac', 'temple', 106.3892, 21.1336, 'Quần thể di tích quốc gia đặc biệt gắn với Trần Hưng Đạo và Nguyễn Trãi, ẩn mình giữa rừng thông xanh.', 'Côn Sơn - Kiếp Bạc là quần thể di tích linh thiêng bậc nhất xứ Đông, nơi lưu dấu hai vị anh hùng dân tộc. Đền Kiếp Bạc thờ Hưng Đạo Đại Vương Trần Quốc Tuấn, người ba lần đánh tan quân Nguyên Mông, tọa lạc bên dòng Lục Đầu Giang hùng vĩ. Cách đó không xa, chùa Côn Sơn nép mình dưới rừng thông bạt ngàn, gắn với danh nhân văn hóa thế giới Nguyễn Trãi cùng câu thơ Côn Sơn suối chảy rì rầm. Mỗi mùa thu, lễ hội Kiếp Bạc và lễ hội Côn Sơn thu hút hàng vạn người về dâng hương, tưởng nhớ công đức tiền nhân giữa khung cảnh non nước hữu tình.', '["Đền Kiếp Bạc thờ Hưng Đạo Đại Vương Trần Quốc Tuấn.","Chùa Côn Sơn gắn liền với danh nhân văn hóa Nguyễn Trãi.","Được xếp hạng Di tích quốc gia đặc biệt năm 2012.","Lễ hội mùa thu Kiếp Bạc diễn ra rằm tháng tám âm lịch."]', '["Leo bộ lên Bàn Cờ Tiên trên đỉnh núi Côn Sơn để ngắm toàn cảnh.","Về dự lễ hội mùa xuân và mùa thu để cảm nhận không khí linh thiêng."]', 'Tháng 1 và tháng 8 âm lịch', '1 ngày', '', '06:30 - 18:00', '["festival","verified","popular"]', '["temple","history","nature","culture"]', '[{"seed":"hd-con-son-kiep-bac-1","caption":"Đền Kiếp Bạc bên Lục Đầu Giang","ratio":"16/9"},{"seed":"hd-con-son-kiep-bac-2","caption":"Chùa Côn Sơn giữa rừng thông","ratio":"4/3"},{"seed":"hd-con-son-kiep-bac-3","caption":"Lễ hội mùa thu truyền thống","ratio":"1/1"}]', '["hd-dao-co"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hd-dao-co', 'dao-co-chi-lang-nam', 'hai-duong', 'Đảo Cò Chi Lăng Nam', 'Chi Lang Nam Stork Island', 'park', 106.2289, 20.8067, 'Hòn đảo giữa hồ An Dương là thiên đường của hàng vạn cánh cò vạc, điểm sinh thái độc đáo của đồng bằng.', 'Giữa lòng hồ An Dương xanh biếc, Đảo Cò Chi Lăng Nam hiện lên như một ốc đảo của tự nhiên, nơi trú ngụ của hàng vạn con cò, vạc, diệc, mòng két. Hình thành từ những trận lụt vỡ đê hàng thế kỷ trước, hai gò đất nổi dần trở thành chốn an cư cho đàn chim trời. Bình minh và hoàng hôn là khoảnh khắc kỳ diệu nhất, khi từng đàn cò trắng rợp trời bay về tổ tạo nên bức tranh thiên nhiên sống động. Du khách lên thuyền nan lướt nhẹ quanh đảo, lắng nghe tiếng chim ríu rít và hít hà bầu không khí trong lành hiếm có giữa đồng bằng Bắc Bộ.', '["Nơi cư trú của khoảng 15.000 con cò và 5.000 con vạc.","Hình thành tự nhiên từ những lần vỡ đê hàng trăm năm trước.","Có tới chín loài cò và ba loài vạc cùng nhiều loài chim nước.","Được công nhận là Di tích danh thắng cấp quốc gia."]', '["Đi thuyền lúc bình minh hoặc hoàng hôn để ngắm cò bay rợp trời.","Mang ống nhòm và máy ảnh tele để quan sát chim mà không làm chúng hoảng sợ."]', 'Tháng 9 đến tháng 4', 'Nửa ngày', '30.000đ', '06:00 - 18:00', '["hidden-gem","verified","ai-recommended"]', '["nature","photography"]', '[{"seed":"hd-dao-co-1","caption":"Đàn cò bay về tổ lúc hoàng hôn","ratio":"16/9"},{"seed":"hd-dao-co-2","caption":"Thuyền nan dạo quanh đảo","ratio":"4/3"},{"seed":"hd-dao-co-3","caption":"Hồ An Dương xanh biếc","ratio":"1/1"}]', '["hd-con-son-kiep-bac"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hy-pho-hien', 'pho-hien', 'hung-yen', 'Phố Hiến', 'Pho Hien', 'city', 106.0511, 20.6394, 'Thương cảng sầm uất một thời với câu Thứ nhất Kinh Kỳ, thứ nhì Phố Hiến, nay là quần thể di tích cổ kính.', 'Phố Hiến từng là thương cảng phồn hoa bậc nhất Đàng Ngoài thế kỷ XVII, nơi thuyền buôn Trung Hoa, Nhật Bản, Hà Lan tấp nập cập bến trên dòng sông Hồng. Câu ca Thứ nhất Kinh Kỳ, thứ nhì Phố Hiến đã khắc ghi vị thế của vùng đất này trong tâm thức người Việt. Dạo bước qua phố cổ Hưng Yên hôm nay, du khách gặp lại dấu xưa qua đền Mây, chùa Chuông, Văn Miếu Xích Đằng và đền Mẫu rêu phong. Mỗi mùa hè, hương nhãn lồng tiến vua tỏa ngát khắp phố phường, gợi nhớ thời vàng son của một đô thị cổ giàu bản sắc giao thoa Đông Tây.', '["Từng là thương cảng quốc tế sầm uất nhất Đàng Ngoài thế kỷ XVII.","Quần thể di tích Phố Hiến gồm hơn 100 di tích lớn nhỏ.","Nổi tiếng với đặc sản nhãn lồng từng được tiến vua.","Văn Miếu Xích Đằng là biểu tượng hiếu học của vùng đất."]', '["Tham quan cụm di tích bằng xe đạp để khám phá trọn vẹn phố cổ.","Đến mùa hè để thưởng thức nhãn lồng Hưng Yên chính gốc."]', 'Tháng 7 đến tháng 8 (mùa nhãn)', '1 ngày', '', '07:00 - 18:00', '["verified","popular","ai-recommended"]', '["history","culture","city","food"]', '[{"seed":"hy-pho-hien-1","caption":"Văn Miếu Xích Đằng cổ kính","ratio":"16/9"},{"seed":"hy-pho-hien-2","caption":"Đền Mẫu Phố Hiến","ratio":"4/3"},{"seed":"hy-pho-hien-3","caption":"Nhãn lồng Hưng Yên mùa thu hoạch","ratio":"1/1"}]', '["hy-chua-chuong"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hy-chua-chuong', 'chua-chuong', 'hung-yen', 'Chùa Chuông', 'Chuong Pagoda', 'temple', 106.0533, 20.6433, 'Ngôi chùa cổ được mệnh danh Phố Hiến đệ nhất danh lam với cầu đá, vườn tháp và tượng pháp tinh xảo.', 'Chùa Chuông, tên chữ Kim Chung Tự, được người xưa ca tụng là Phố Hiến đệ nhất danh lam, ngôi chùa đẹp nhất chốn thương cảng phồn hoa. Truyền thuyết kể rằng một quả chuông vàng trôi dạt theo dòng nước về đây, dân làng lập chùa thờ phụng nên thành tên. Bước qua cây cầu đá xanh bắc ngang ao mắt rồng, du khách lạc vào không gian thanh tịnh với hành lang La Hán mười tám pho tượng sống động và cây hương đá khắc chữ Hán cổ. Kiến trúc nội công ngoại quốc hài hòa cùng những mảng chạm khắc gỗ tinh xảo khiến chùa Chuông trở thành viên ngọc kiến trúc Phật giáo quý giá của vùng đất Hưng Yên.', '["Tên chữ là Kim Chung Tự, nghĩa là chùa Chuông Vàng.","Được xây dựng từ thời Hậu Lê thế kỷ XV.","Có hành lang mười tám vị La Hán chạm khắc sống động.","Cầu đá và ao mắt rồng tạo nên lối vào độc đáo."]', '["Kết hợp tham quan cùng cụm di tích Phố Hiến trong một buổi.","Ghé vào sáng sớm để tận hưởng không gian tĩnh lặng, thanh tịnh."]', 'Quanh năm', '1-2 giờ', '', '06:00 - 18:00', '["verified","hidden-gem"]', '["temple","history","culture"]', '[{"seed":"hy-chua-chuong-1","caption":"Cầu đá bắc qua ao mắt rồng","ratio":"16/9"},{"seed":"hy-chua-chuong-2","caption":"Hành lang mười tám vị La Hán","ratio":"4/3"},{"seed":"hy-chua-chuong-3","caption":"Tam quan chùa Chuông cổ kính","ratio":"1/1"}]', '["hy-pho-hien"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hn-tam-chuc', 'chua-tam-chuc', 'ha-nam', 'Chùa Tam Chúc', 'Tam Chuc Pagoda', 'temple', 105.8847, 20.4642, 'Ngôi chùa lớn bậc nhất thế giới, tọa lạc giữa hồ nước mênh mông và núi đá vôi trùng điệp ở Hà Nam.', 'Chùa Tam Chúc được mệnh danh là ngôi chùa lớn nhất thế giới, trải rộng trên vùng non nước kỳ vĩ phía nam Hà Nam. Quần thể tựa lưng vào núi Thất Tinh, mặt hướng ra hồ Lục Nhạc với sáu hòn đảo đá nổi như sáu chiếc chuông trời. Trục thần đạo nối tiếp từ cổng Tam Quan, vườn Cột Kinh, điện Quan Âm, điện Pháp Chủ đến điện Tam Thế nguy nga, nơi đặt ba pho tượng Phật bằng đồng nặng hàng trăm tấn. Tương truyền đây là vùng đất gắn với truyền thuyết Tiền Lục Nhạc, Hậu Thất Tinh huyền bí. Hành hương về Tam Chúc, lòng người như lắng lại giữa khung cảnh thiên nhiên hùng vĩ và không gian tâm linh thanh tịnh.', '["Được xem là một trong những ngôi chùa lớn nhất thế giới.","Điện Tam Thế đặt ba pho tượng Phật đồng nặng khoảng 80 tấn mỗi pho.","Vườn Cột Kinh có 32 cột đá khổng lồ khắc kinh Phật.","Hồ Lục Nhạc có sáu hòn đảo đá tự nhiên giữa lòng hồ."]', '["Đi thuyền hoặc xe điện để di chuyển giữa các điện trong quần thể rộng lớn.","Đến sớm buổi sáng để tránh nắng và đông đúc, kịp ngắm sương trên hồ."]', 'Tháng 1 đến tháng 3 (mùa lễ hội)', '1 ngày', '', '06:00 - 21:00', '["trending","popular","verified","ai-recommended"]', '["temple","nature","culture","photography"]', '[{"seed":"hn-tam-chuc-1","caption":"Điện Tam Thế bên hồ Lục Nhạc","ratio":"16/9"},{"seed":"hn-tam-chuc-2","caption":"Vườn Cột Kinh khắc kinh Phật","ratio":"4/3"},{"seed":"hn-tam-chuc-3","caption":"Toàn cảnh chùa giữa núi non","ratio":"1/1"}]', '[]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nd-den-tran', 'den-tran', 'nam-dinh', 'Đền Trần', 'Tran Temple', 'temple', 106.1747, 20.4561, 'Khu di tích thờ các vua Trần và Trần Hưng Đạo, nổi danh với lễ khai ấn đầu xuân thu hút hàng vạn người.', 'Đền Trần Nam Định là nơi thờ phụng mười bốn vị hoàng đế nhà Trần cùng các quan lại có công, dựng trên nền Thái miếu xưa của hương Tức Mặc, quê hương phát tích vương triều. Quần thể gồm ba ngôi đền chính: đền Thiên Trường, đền Cố Trạch và đền Trùng Hoa, mang đậm dấu ấn kiến trúc cổ với cổng ngũ môn uy nghi và những hàng cây cổ thụ rợp bóng. Nổi tiếng nhất là lễ khai ấn đêm 14 rạng sáng 15 tháng Giêng, khi hàng vạn người về xin ấn cầu mong công danh, tài lộc một năm hanh thông. Đền Trần không chỉ là chốn linh thiêng mà còn là biểu tượng hào khí Đông A bất diệt của dân tộc.', '["Thờ mười bốn vị vua triều Trần tại nền Thái miếu cổ.","Lễ khai ấn diễn ra đêm 14 rạng sáng 15 tháng Giêng âm lịch.","Vùng Tức Mặc là quê hương phát tích của nhà Trần.","Quần thể gồm ba đền: Thiên Trường, Cố Trạch và Trùng Hoa."]', '["Tránh chen lấn đêm khai ấn, có thể xin ấn vào các ngày sau đó.","Kết hợp thăm chùa Phổ Minh gần kề với tháp cổ thời Trần."]', 'Tháng Giêng âm lịch', 'Nửa ngày', '', '07:00 - 18:00', '["festival","popular","verified"]', '["temple","history","culture"]', '[{"seed":"nd-den-tran-1","caption":"Cổng ngũ môn Đền Trần uy nghi","ratio":"16/9"},{"seed":"nd-den-tran-2","caption":"Lễ khai ấn đầu xuân","ratio":"4/3"},{"seed":"nd-den-tran-3","caption":"Đền Thiên Trường cổ kính","ratio":"1/1"}]', '["nd-nha-tho-do"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nd-nha-tho-do', 'nha-tho-do-hai-ly', 'nam-dinh', 'Nhà thờ đổ Hải Lý', 'Hai Ly Ruined Church', 'city', 106.2783, 19.9744, 'Tàn tích nhà thờ ven biển bị sóng biển bào mòn, mang vẻ đẹp hoang hoải đầy mê hoặc với giới nhiếp ảnh.', 'Nhà thờ đổ Hải Lý là di tích nhà thờ Trái Tim đổ, chứng nhân lặng lẽ của cuộc chiến giữa con người và biển cả. Được xây dựng đầu thế kỷ XX, nhà thờ từng là nơi sinh hoạt của giáo dân vùng Xương Điền, nhưng nạn xâm thực biển khiến cả làng phải lùi sâu vào đất liền, bỏ lại ngôi thánh đường trơ trọi giữa bãi cát. Tháp chuông rêu phong sừng sững trước sóng gió, lúc ẩn lúc hiện theo con nước thủy triều, tạo nên khung cảnh vừa hoang tàn vừa thi vị. Bình minh và hoàng hôn nơi đây trở thành điểm hẹn lý tưởng của những tay máy săn tìm khoảnh khắc đẹp ma mị giữa trời nước bao la.', '["Nguyên là nhà thờ Trái Tim, xây đầu thế kỷ XX.","Bị bỏ hoang do nạn xâm thực biển nuốt dần làng Xương Điền.","Tháp chuông cổ vẫn đứng vững giữa sóng gió sau hơn một thế kỷ.","Là điểm chụp ảnh bình minh nổi tiếng của Nam Định."]', '["Canh thủy triều rút để có thể ra sát chân nhà thờ chụp ảnh.","Đến lúc bình minh để bắt trọn khoảnh khắc ánh sáng đẹp nhất."]', 'Tháng 10 đến tháng 4', '1-2 giờ', '', 'Cả ngày', '["hidden-gem","trending","ai-recommended"]', '["history","photography","beach"]', '[{"seed":"nd-nha-tho-do-1","caption":"Tháp chuông đổ giữa bãi biển","ratio":"16/9"},{"seed":"nd-nha-tho-do-2","caption":"Bình minh trên nhà thờ đổ","ratio":"4/3"},{"seed":"nd-nha-tho-do-3","caption":"Sóng vỗ chân tường rêu phong","ratio":"1/1"}]', '["nd-den-tran"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tb-chua-keo', 'chua-keo', 'thai-binh', 'Chùa Keo', 'Keo Pagoda', 'temple', 106.5497, 20.5306, 'Ngôi chùa cổ gần 400 năm với gác chuông gỗ ba tầng tuyệt mỹ, kiệt tác kiến trúc Phật giáo Việt Nam.', 'Chùa Keo, tên chữ Thần Quang Tự, là một trong những ngôi cổ tự đẹp và còn nguyên vẹn nhất Việt Nam, tọa lạc bên dòng sông Hồng hiền hòa. Được xây dựng năm 1632 thời Hậu Lê, chùa thờ Phật và Thiền sư Không Lộ, người có công chữa bệnh cho vua Lý. Điểm nhấn tuyệt mỹ là gác chuông gỗ ba tầng cao gần mười hai mét, dựng hoàn toàn bằng mộng gỗ không dùng đinh, mái cong vút như cánh chim sắp bay. Toàn bộ quần thể với hàng trăm gian nhà gỗ lim sắp xếp đăng đối là minh chứng cho tài hoa của người thợ xưa. Lễ hội chùa Keo mùa thu với những nghi thức cổ truyền độc đáo luôn thu hút đông đảo du khách thập phương.', '["Tên chữ Thần Quang Tự, xây dựng năm 1632 thời Hậu Lê.","Gác chuông gỗ ba tầng dựng bằng mộng gỗ không dùng một chiếc đinh.","Thờ Thiền sư Không Lộ, người chữa bệnh cho vua Lý Thần Tông.","Là Di tích quốc gia đặc biệt với gần 400 năm tuổi."]', '["Về dự lễ hội chùa Keo mùa thu rằm tháng chín âm lịch.","Quan sát kỹ kết cấu gác chuông để cảm nhận tài hoa nghề mộc cổ."]', 'Tháng 9 âm lịch (mùa lễ hội)', 'Nửa ngày', '', '07:00 - 18:00', '["festival","verified","popular"]', '["temple","history","culture","photography"]', '[{"seed":"tb-chua-keo-1","caption":"Gác chuông gỗ ba tầng nổi tiếng","ratio":"16/9"},{"seed":"tb-chua-keo-2","caption":"Lễ hội chùa Keo mùa thu","ratio":"4/3"},{"seed":"tb-chua-keo-3","caption":"Quần thể nhà gỗ lim đăng đối","ratio":"1/1"}]', '["tb-con-vanh"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tb-con-vanh', 'bien-con-vanh', 'thai-binh', 'Biển Cồn Vành', 'Con Vanh Beach', 'beach', 106.5836, 20.2392, 'Bãi biển hoang sơ trong khu dự trữ sinh quyển, với rừng phi lao, rừng ngập mặn và bình minh tuyệt đẹp.', 'Cồn Vành là dải đất bồi hoang sơ vươn ra biển Đông, nằm trong Khu dự trữ sinh quyển châu thổ sông Hồng được UNESCO công nhận. Khác với những bãi tắm ồn ào, nơi đây giữ trọn vẻ mộc mạc với bãi cát phẳng lì trải dài hàng cây số, rừng phi lao vi vu trong gió và những cánh rừng ngập mặn xanh ngắt. Cồn Vành là thiên đường của các loài chim di cư và là nơi mưu sinh của ngư dân với nghề cào ngao, bắt còng. Du khách về đây để cắm trại, đón bình minh rực rỡ trên biển, thưởng thức hải sản tươi ngon và tận hưởng không gian trong lành, yên bình hiếm có của miền quê lúa Thái Bình.', '["Nằm trong Khu dự trữ sinh quyển châu thổ sông Hồng của UNESCO.","Có hệ sinh thái rừng ngập mặn và rừng phi lao phong phú.","Là điểm dừng chân của nhiều loài chim di cư quý hiếm.","Bãi cát phẳng dài, thích hợp cắm trại và đón bình minh."]', '["Mang theo lều và đồ dùng cá nhân vì dịch vụ nơi đây còn hoang sơ.","Dậy sớm đón bình minh và trải nghiệm cào ngao cùng ngư dân."]', 'Tháng 4 đến tháng 8', '1 ngày', '', 'Cả ngày', '["hidden-gem","new","ai-recommended"]', '["beach","nature","photography"]', '[{"seed":"tb-con-vanh-1","caption":"Bình minh trên biển Cồn Vành","ratio":"16/9"},{"seed":"tb-con-vanh-2","caption":"Rừng phi lao ven biển","ratio":"4/3"},{"seed":"tb-con-vanh-3","caption":"Rừng ngập mặn xanh ngắt","ratio":"1/1"}]', '["tb-chua-keo"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vp-tam-dao', 'tam-dao', 'vinh-phuc', 'Tam Đảo', 'Tam Dao', 'mountain', 105.6447, 21.4561, 'Thị trấn nghỉ mát trên mây ở độ cao 900m, khí hậu mát lành quanh năm với sương mù bảng lảng huyền ảo.', 'Tam Đảo là thị trấn nghỉ dưỡng nằm vắt vẻo trên dãy núi cùng tên ở độ cao gần 900 mét, được người Pháp khám phá và xây dựng từ đầu thế kỷ XX. Quanh năm mây mù bao phủ, khí hậu se lạnh khiến nơi đây được ví như Đà Lạt của miền Bắc. Du khách lên Tam Đảo để trốn cái nóng oi ả, dạo bước trên những con dốc quanh co, chinh phục 1.300 bậc thang xuống Thác Bạc, hay check-in nhà thờ đá cổ kính phủ rêu phong. Khi màn sương buông xuống, cả thị trấn chìm trong không gian mờ ảo, lãng mạn như chốn bồng lai. Đặc sản su su xanh mướt và những bữa lẩu gà nóng hổi càng làm chuyến đi thêm trọn vẹn.', '["Nằm ở độ cao gần 900m, khí hậu mát mẻ quanh năm.","Được người Pháp xây dựng làm khu nghỉ dưỡng từ năm 1904.","Nhà thờ đá Tam Đảo là biểu tượng kiến trúc cổ kính.","Đặc sản su su Tam Đảo nổi tiếng xanh non, giòn ngọt."]', '["Mang theo áo ấm vì nhiệt độ ban đêm có thể xuống rất thấp.","Đi giữa tuần để tránh đông đúc và đặt phòng giá tốt hơn."]', 'Tháng 4 đến tháng 10', '2 ngày 1 đêm', '', 'Cả ngày', '["trending","popular","verified","ai-recommended"]', '["mountain","nature","photography","food"]', '[{"seed":"vp-tam-dao-1","caption":"Thị trấn Tam Đảo trong sương mù","ratio":"16/9"},{"seed":"vp-tam-dao-2","caption":"Nhà thờ đá cổ kính","ratio":"4/3"},{"seed":"vp-tam-dao-3","caption":"Thác Bạc giữa rừng xanh","ratio":"1/1"}]', '["vp-tay-thien"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vp-tay-thien', 'thien-vien-truc-lam-tay-thien', 'vinh-phuc', 'Thiền viện Trúc Lâm Tây Thiên', 'Truc Lam Tay Thien Zen Monastery', 'temple', 105.5961, 21.4392, 'Thiền viện lớn dưới chân Tam Đảo, chốn tu hành thanh tịnh gắn với khu danh thắng Tây Thiên linh thiêng.', 'Thiền viện Trúc Lâm Tây Thiên tọa lạc dưới chân núi Tam Đảo, là một trong những thiền viện lớn nhất Việt Nam, nơi kế thừa và phát huy dòng thiền Trúc Lâm Yên Tử do Phật hoàng Trần Nhân Tông sáng lập. Quần thể uy nghi với chính điện, lầu chuông, lầu trống và vườn tượng nằm giữa rừng núi xanh mát, không gian tĩnh lặng đưa lòng người vào cõi an nhiên. Tây Thiên còn được xem là một trong những cái nôi của Phật giáo Việt Nam, gắn với truyền thuyết Quốc Mẫu Tây Thiên Lăng Thị Tiêu. Hành hương lên đền Thượng qua những bậc đá rêu phong giữa rừng già, du khách vừa vãn cảnh vừa cảm nhận chiều sâu tâm linh ngàn năm của vùng đất thiêng.', '["Là một trong những thiền viện lớn nhất cả nước.","Kế thừa dòng thiền Trúc Lâm do Phật hoàng Trần Nhân Tông khai sáng.","Khu danh thắng Tây Thiên gắn với tín ngưỡng thờ Quốc Mẫu.","Có thể đi cáp treo lên đền Thượng giữa rừng nguyên sinh."]', '["Kết hợp đi cáp treo lên Tây Thiên để tiết kiệm sức khi viếng đền Thượng.","Mặc trang phục kín đáo, lịch sự khi vào khu vực thiền viện."]', 'Tháng 2 đến tháng 4 (mùa lễ hội)', 'Nửa ngày', '', '06:00 - 18:00', '["festival","verified","popular"]', '["temple","nature","culture"]', '[{"seed":"vp-tay-thien-1","caption":"Chính điện thiền viện uy nghi","ratio":"16/9"},{"seed":"vp-tay-thien-2","caption":"Đường lên đền Thượng Tây Thiên","ratio":"4/3"},{"seed":"vp-tay-thien-3","caption":"Vườn tượng giữa rừng xanh","ratio":"1/1"}]', '["vp-tam-dao"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('thanh-nha-ho', 'thanh-nha-ho', 'thanh-hoa', 'Thành nhà Hồ', 'Ho Citadel', 'unesco', 105.6038, 20.0773, 'Tòa thành đá đồ sộ cuối thế kỷ 14, kỳ quan kiến trúc quân sự được UNESCO vinh danh giữa vùng quê xứ Thanh.', 'Được vua Hồ Quý Ly cho xây dựng năm 1397, Thành nhà Hồ là tòa thành đá hiếm hoi còn lại ở Đông Nam Á. Những khối đá xanh nặng hàng chục tấn được ghép khít nhau không cần chất kết dính, dựng nên bốn cổng vòm uy nghi sừng sững qua hơn sáu thế kỷ mưa nắng. Đứng dưới cổng Nam, du khách như chạm vào tài hoa của cha ông và những toan tính cải cách táo bạo một thời. Năm 2011, UNESCO ghi danh nơi đây là Di sản Văn hóa Thế giới, khẳng định giá trị độc đáo của một biểu tượng quyền lực và trí tuệ Đại Việt.', '["Được xây trong khoảng 3 tháng đầu năm 1397.","Tường thành ghép từ những phiến đá nặng tới 20 tấn.","UNESCO công nhận Di sản Văn hóa Thế giới năm 2011.","Từng là kinh đô của nhà Hồ trong giai đoạn ngắn ngủi."]', '["Đi sớm buổi sáng để chụp ảnh cổng đá trong nắng dịu.","Kết hợp thuê xe điện tham quan vành đai thành và đàn tế Nam Giao."]', 'Tháng 10 đến tháng 4', 'Nửa ngày', '40.000đ', '07:00 - 17:30', '["unesco","verified","popular"]', '["history","culture","photography"]', '[{"seed":"thanh-nha-ho-cong-nam","caption":"Cổng Nam đá xanh uy nghi","ratio":"16/9"},{"seed":"thanh-nha-ho-tuong-thanh","caption":"Tường thành ghép đá hàng thế kỷ","ratio":"4/3"},{"seed":"thanh-nha-ho-canh-dong","caption":"Thành cổ giữa đồng quê xứ Thanh","ratio":"1/1"}]', '["suoi-ca-than-cam-luong"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bien-sam-son', 'bien-sam-son', 'thanh-hoa', 'Biển Sầm Sơn', 'Sam Son Beach', 'beach', 105.9069, 19.7497, 'Bãi biển trứ danh xứ Thanh với bờ cát thoải, sóng êm và không khí lễ hội rộn ràng suốt mùa hè.', 'Sầm Sơn từ lâu đã là điểm nghỉ mát yêu thích của người dân miền Bắc, nơi bãi cát trải dài thoai thoải và làn nước trong xanh mời gọi. Từ thời Pháp thuộc, vùng biển này đã được chọn làm nơi an dưỡng nhờ khí hậu mát lành. Bình minh trên hòn Trống Mái, dạo chân lên đền Độc Cước linh thiêng tựa lưng vào núi Trường Lệ, rồi thưởng thức hải sản tươi rói bên bờ sóng, tất cả tạo nên một Sầm Sơn vừa náo nhiệt vừa đậm đà bản sắc. Mỗi độ hè về, các lễ hội biển lại thắp sáng cả một vùng trời.', '["Bãi biển dài khoảng 9km với cát mịn thoai thoải.","Hòn Trống Mái gắn với truyền thuyết tình yêu nổi tiếng.","Đền Độc Cước thờ vị thần tự xẻ đôi thân mình cứu dân.","Được người Pháp khai thác du lịch từ năm 1906."]', '["Tắm biển vào sáng sớm hoặc chiều muộn để tránh nắng gắt.","Thỏa thuận giá hải sản trước khi gọi món tại các quán ven biển."]', 'Tháng 5 đến tháng 8', '1 - 2 ngày', '', 'Cả ngày', '["popular","trending","festival"]', '["beach","nature","food"]', '[{"seed":"sam-son-binh-minh","caption":"Bình minh trên bãi tắm Sầm Sơn","ratio":"16/9"},{"seed":"sam-son-trong-mai","caption":"Hòn Trống Mái lừng danh","ratio":"4/3"},{"seed":"sam-son-hai-san","caption":"Bãi tắm rợp dù che nhìn từ trên cao","ratio":"1/1"}]', '["thanh-nha-ho"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('suoi-ca-than-cam-luong', 'suoi-ca-than-cam-luong', 'thanh-hoa', 'Suối cá thần Cẩm Lương', 'Cam Luong Fish Stream', 'park', 105.3711, 20.2542, 'Dòng suối kỳ lạ nơi hàng nghìn con cá thần quây quần dưới chân núi đá vôi, gắn với tín ngưỡng người Mường.', 'Ẩn mình dưới chân núi Trường Sinh ở huyện Cẩm Thủy, suối cá thần Cẩm Lương khiến bao du khách kinh ngạc bởi hàng nghìn con cá to lớn bơi lượn dày đặc trong làn nước trong vắt. Người Mường nơi đây tin rằng đàn cá là thần giữ bình yên cho bản làng, nên không ai dám đánh bắt. Cá ở đây thân tròn, vây hồng, có con nặng tới vài cân, ung dung sống qua bao đời. Bên dòng suối mát lành còn có hang động kỳ thú và những nếp nhà sàn mộc mạc, tạo nên một bức tranh thiên nhiên và văn hóa hài hòa, bình yên đến lạ.', '["Ước tính có hàng nghìn con cá sinh sống trong đoạn suối ngắn.","Người Mường coi đàn cá là cá thần, tuyệt đối không đánh bắt.","Cá thuộc họ cá chép, có con nặng vài kilôgam.","Suối chảy ra từ một hang động trong lòng núi đá vôi."]', '["Mang giày chống trượt vì lối đi ven suối khá ẩm.","Ghé bản Mường gần đó để thưởng thức cơm lam và rượu cần."]', 'Tháng 3 đến tháng 9', 'Nửa ngày', '20.000đ', '07:00 - 18:00', '["hidden-gem","verified"]', '["nature","culture","photography"]', '[{"seed":"cam-luong-dan-ca","caption":"Đàn cá thần dưới chân núi","ratio":"16/9"},{"seed":"cam-luong-suoi-trong","caption":"Dòng suối trong vắt","ratio":"4/3"},{"seed":"cam-luong-nha-san","caption":"Bản Mường ven suối","ratio":"1/1"}]', '["thanh-nha-ho"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('khu-di-tich-kim-lien', 'khu-di-tich-kim-lien', 'nghe-an', 'Khu di tích Kim Liên - quê Bác', 'Kim Lien Relic Site', 'museum', 105.5611, 18.6797, 'Làng Sen, làng Hoàng Trù - nơi Chủ tịch Hồ Chí Minh sinh ra và lớn lên, điểm hành hương thiêng liêng của triệu trái tim.', 'Về Kim Liên, huyện Nam Đàn, ta như được trở lại tuổi thơ của Bác Hồ kính yêu. Trong ngôi nhà tranh đơn sơ ở làng Hoàng Trù, cậu bé Nguyễn Sinh Cung cất tiếng khóc chào đời; còn ở làng Sen, mái nhà lá giản dị in dấu những năm tháng Người sống cùng cha. Khung cửi, võng đay, chiếc phản gỗ mộc mạc vẫn còn đó, gợi nhắc nếp sống thanh bạch của một gia đình nhà Nho yêu nước. Hàng năm, hàng triệu người con đất Việt tìm về đây, lặng đứng bên giếng Cốc, cây đa, mái nhà xưa, để tưởng nhớ và tri ân vị lãnh tụ vĩ đại của dân tộc.', '["Gồm hai cụm di tích chính: làng Sen và làng Hoàng Trù.","Là nơi Chủ tịch Hồ Chí Minh sinh năm 1890.","Được công nhận là Di tích Quốc gia đặc biệt.","Đón hàng triệu lượt khách hành hương mỗi năm."]', '["Ăn mặc lịch sự, giữ trật tự khi tham quan khu di tích.","Đến vào dịp 19/5 để hòa mình vào lễ hội Làng Sen."]', 'Tháng 4 đến tháng 5', 'Nửa ngày', '', '07:00 - 17:00', '["verified","popular","festival"]', '["history","culture"]', '[{"seed":"kim-lien-nha-tranh","caption":"Ngôi nhà tranh quê Bác","ratio":"16/9"},{"seed":"kim-lien-gieng-coc","caption":"Giếng Cốc làng Sen","ratio":"4/3"},{"seed":"kim-lien-cay-da","caption":"Cây đa cổ thụ đầu làng","ratio":"1/1"}]', '["bien-cua-lo"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bien-cua-lo', 'bien-cua-lo', 'nghe-an', 'Biển Cửa Lò', 'Cua Lo Beach', 'beach', 105.7178, 18.8047, 'Bãi biển sầm uất bậc nhất xứ Nghệ với cát trắng, nước trong và đặc sản mực nhảy trứ danh.', 'Cửa Lò là viên ngọc du lịch của Nghệ An, nơi bờ cát trắng mịn trải dài hơn mười cây số ôm lấy biển xanh lồng lộng gió. Buổi sớm, ngư dân trở về với những khoang thuyền đầy ắp, mang theo món mực nhảy tươi roi rói khiến thực khách mê mẩn. Du khách có thể chèo thuyền ra đảo Lan Châu, ngắm đảo Ngư xa xa, hay thong dong dạo bộ trên con đường ven biển lộng gió lúc hoàng hôn. Về đêm, các khu phố ẩm thực và quảng trường lại bừng sáng, mang đến một Cửa Lò vừa thơ mộng vừa náo nhiệt, xứng danh điểm đến mùa hè được yêu thích nhất miền Trung.', '["Bãi biển dài hơn 10km, cát trắng mịn và nước trong.","Mực nhảy Cửa Lò là đặc sản nổi tiếng khắp cả nước.","Đảo Lan Châu nằm sát bờ, nối liền lúc thủy triều xuống.","Được quy hoạch thành đô thị du lịch biển từ năm 1994."]', '["Thưởng thức mực nhảy hấp ngay tại bến cá lúc sáng sớm.","Đặt phòng trước vào cuối tuần hè vì lượng khách rất đông."]', 'Tháng 5 đến tháng 8', '1 - 2 ngày', '', 'Cả ngày', '["popular","trending"]', '["beach","food","nature"]', '[{"seed":"cua-lo-bai-cat","caption":"Đại lộ ven biển rợp bóng cây buổi sớm","ratio":"16/9"},{"seed":"cua-lo-muc-nhay","caption":"Phố biển lên đèn lung linh lúc hoàng hôn","ratio":"4/3"},{"seed":"cua-lo-dao-lan-chau","caption":"Đảo Lan Châu sát bờ","ratio":"1/1"}]', '["khu-di-tich-kim-lien"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vuon-quoc-gia-pu-mat', 'vuon-quoc-gia-pu-mat', 'nghe-an', 'Vườn quốc gia Pù Mát', 'Pu Mat National Park', 'park', 104.8833, 18.9667, 'Khu rừng nguyên sinh rộng lớn miền Tây Nghệ An với thác Khe Kèm hùng vĩ và hệ sinh thái đa dạng bậc nhất.', 'Trải dài trên dãy Trường Sơn hùng vĩ, Vườn quốc gia Pù Mát là kho báu xanh của miền Tây xứ Nghệ với hơn chín mươi nghìn hecta rừng nguyên sinh. Nơi đây là mái nhà của sao la quý hiếm, voi rừng, vượn đen và vô vàn loài thực vật cổ thụ. Du khách có thể men theo dòng sông Giăng trong vắt bằng thuyền, đắm mình dưới thác Khe Kèm trắng xóa đổ từ độ cao hơn trăm mét, hay ghé thăm bản người Đan Lai sống biệt lập giữa đại ngàn. Tiếng chim rừng, hương cây cỏ và làn nước mát lạnh nơi đây mang đến trải nghiệm hoang sơ, thanh tịnh hiếm có cho những ai yêu thiên nhiên.', '["Diện tích vùng lõi hơn 94.000 hecta rừng nguyên sinh.","Là nơi cư trú của sao la, loài thú quý hiếm bậc nhất thế giới.","Thác Khe Kèm cao hơn 100m, được ví như nàng tiên giữa rừng.","Thuộc Khu dự trữ sinh quyển miền Tây Nghệ An của UNESCO."]', '["Đi cùng hướng dẫn viên bản địa khi vào sâu trong rừng.","Mang theo áo mưa và giày leo núi cho hành trình khám phá."]', 'Tháng 9 đến tháng 12', '1 - 2 ngày', '50.000đ', '07:00 - 17:00', '["hidden-gem","verified","ai-recommended"]', '["nature","mountain","photography"]', '[{"seed":"pu-mat-thac-khe-kem","caption":"Nhà sàn mái lá nép bên đại ngàn xanh thẳm","ratio":"16/9"},{"seed":"pu-mat-rung-nguyen-sinh","caption":"Rừng nguyên sinh đại ngàn","ratio":"4/3"},{"seed":"pu-mat-song-giang","caption":"Dòng sông Giăng trong vắt","ratio":"1/1"}]', '["khu-di-tich-kim-lien"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('chua-huong-tich', 'chua-huong-tich', 'ha-tinh', 'Chùa Hương Tích', 'Huong Tich Pagoda', 'temple', 105.7197, 18.3539, 'Ngôi chùa cổ linh thiêng trên đỉnh Hồng Lĩnh, được mệnh danh Hoan Châu đệ nhất danh lam của xứ Nghệ Tĩnh.', 'Tọa lạc trên lưng chừng đỉnh Hương Tích thuộc dãy Hồng Lĩnh, ngôi chùa cổ này gắn liền với truyền thuyết về công chúa Diệu Thiện tu hành đắc đạo thành Phật Bà Quan Âm. Được dựng từ thời nhà Trần, chùa ẩn mình giữa rừng cây cổ thụ, mây trắng vờn quanh, mang vẻ u tịch và linh thiêng. Hành trình lên chùa đưa du khách qua suối Hương Tuyền róc rách, am Thánh Mẫu và những bậc đá rêu phong. Từ trên cao nhìn xuống, cả vùng quê Hà Tĩnh hiện ra trùng điệp xanh ngát. Mỗi độ xuân về, lễ hội chùa Hương Tích lại thu hút hàng vạn Phật tử và du khách hành hương.', '["Được xây dựng từ thời nhà Trần, thế kỷ 13.","Gắn với truyền thuyết công chúa Diệu Thiện hóa Phật Bà.","Mệnh danh là Hoan Châu đệ nhất danh lam.","Lễ hội chính diễn ra vào ngày 18 tháng 2 âm lịch."]', '["Đi cáp treo nếu ngại leo bộ đoạn dốc lên chùa.","Tránh ngày khai hội nếu không thích cảnh đông đúc chen lấn."]', 'Tháng 1 đến tháng 3 âm lịch', 'Nửa ngày', '30.000đ', '06:00 - 18:00', '["festival","verified","popular"]', '["temple","culture","history"]', '[{"seed":"huong-tich-chua-co","caption":"Chùa cổ giữa rừng Hồng Lĩnh","ratio":"16/9"},{"seed":"huong-tich-bac-da","caption":"Bậc đá rêu phong lên chùa","ratio":"4/3"},{"seed":"huong-tich-may-trang","caption":"Bậc đá rêu phong khuất trong sương mờ","ratio":"1/1"}]', '["bien-thien-cam"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bien-thien-cam', 'bien-thien-cam', 'ha-tinh', 'Biển Thiên Cầm', 'Thien Cam Beach', 'beach', 106.0356, 18.1306, 'Bãi biển hoang sơ tựa cây đàn trời, nơi sóng và gió hòa thành bản nhạc du dương bên bờ cát mịn Hà Tĩnh.', 'Cái tên Thiên Cầm gợi nhắc tiếng đàn trời, bởi tương truyền vua Hồ Quý Ly khi qua đây đã nghe gió biển và sóng vỗ vào vách núi tạo nên âm thanh tựa khúc nhạc thiêng. Bãi biển trải dài hơn ba cây số với làn cát trắng mịn, nước trong xanh và độ dốc thoải an toàn. Khác với những bãi biển náo nhiệt, Thiên Cầm vẫn giữ nét hoang sơ, bình yên hiếm có. Du khách có thể leo núi Thiên Cầm ngắm toàn cảnh, viếng chùa Cầm Sơn cổ kính, rồi thưởng thức mực một nắng và cá trích nướng thơm lừng. Một điểm dừng chân lý tưởng cho những ai tìm kiếm sự thư thái.', '["Tên gọi nghĩa là đàn trời, gắn với vua Hồ Quý Ly.","Bãi biển dài hơn 3km, cát mịn và sóng êm.","Núi Thiên Cầm có chùa Cầm Sơn cổ kính.","Mực một nắng là đặc sản nổi tiếng của vùng."]', '["Mua mực một nắng làm quà tại các quầy hải sản địa phương.","Leo núi Thiên Cầm buổi chiều để ngắm hoàng hôn trên biển."]', 'Tháng 5 đến tháng 8', '1 ngày', '', 'Cả ngày', '["hidden-gem","new"]', '["beach","nature","food"]', '[{"seed":"thien-cam-bai-bien","caption":"Bãi biển hoang sơ Thiên Cầm","ratio":"16/9"},{"seed":"thien-cam-nui","caption":"Núi Thiên Cầm bên bờ sóng","ratio":"4/3"},{"seed":"thien-cam-muc-mot-nang","caption":"Mực một nắng đặc sản","ratio":"1/1"}]', '["chua-huong-tich","nga-ba-dong-loc"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nga-ba-dong-loc', 'nga-ba-dong-loc', 'ha-tinh', 'Ngã ba Đồng Lộc', 'Dong Loc Junction', 'museum', 105.6042, 18.4878, 'Tọa độ lửa thời chống Mỹ, nơi mười nữ thanh niên xung phong anh dũng hy sinh, trở thành biểu tượng bất tử.', 'Ngã ba Đồng Lộc là nơi máu lửa của tuyến đường Trường Sơn huyền thoại, từng hứng chịu hàng nghìn tấn bom đạn trong những năm chống Mỹ ác liệt. Tại chính nơi đây, ngày 24 tháng 7 năm 1968, mười cô gái thanh niên xung phong tuổi đôi mươi đã ngã xuống khi đang san lấp hố bom, giữ cho mạch máu giao thông không bao giờ ngừng chảy. Khu di tích hôm nay lặng lẽ với mười ngôi mộ trắng, tháp chuông ngân vang và bảo tàng ghi dấu một thời hoa lửa. Đến đây, mỗi người con đất Việt đều cúi đầu xúc động trước sự hy sinh cao cả của những đóa hoa bất tử Đồng Lộc.', '["Là trọng điểm đánh phá trên tuyến đường Trường Sơn.","Mười nữ thanh niên xung phong hy sinh ngày 24/7/1968.","Được xếp hạng Di tích Lịch sử Quốc gia đặc biệt.","Có tháp chuông cao 37m và nhà bia tưởng niệm."]', '["Dâng hương tưởng niệm và giữ thái độ trang nghiêm.","Kết hợp tham quan bảo tàng để hiểu rõ lịch sử nơi đây."]', 'Quanh năm', 'Nửa ngày', '', '07:00 - 17:30', '["verified","popular"]', '["history","culture"]', '[{"seed":"dong-loc-mo-liet-si","caption":"Mười ngôi mộ nữ thanh niên xung phong","ratio":"16/9"},{"seed":"dong-loc-thap-chuong","caption":"Hàng mộ trắng phủ hoa cúc tưởng niệm","ratio":"4/3"},{"seed":"dong-loc-ho-bom","caption":"Dấu tích hố bom năm xưa","ratio":"1/1"}]', '["bien-thien-cam"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('thanh-co-quang-tri', 'thanh-co-quang-tri', 'quang-tri', 'Thành cổ Quảng Trị', 'Quang Tri Ancient Citadel', 'museum', 107.1889, 16.7506, 'Chứng tích 81 ngày đêm khốc liệt mùa hè 1972, nơi yên nghỉ của hàng nghìn chiến sĩ giữa lòng đất thiêng.', 'Thành cổ Quảng Trị là biểu tượng bất khuất của lịch sử dân tộc, nơi diễn ra trận chiến 81 ngày đêm rực lửa mùa hè năm 1972. Trên mảnh đất chỉ rộng vài cây số vuông, hàng vạn tấn bom đạn đã trút xuống, và biết bao người con ưu tú đã ngã xuống để giữ từng tấc đất. Người ta nói rằng mỗi nắm đất nơi đây đều thấm máu các anh, nên giữa lòng thành nay chỉ có một đài tưởng niệm hình ngôi mộ tập thể, không bia, không tên. Đến Thành cổ, du khách lặng người thắp nén hương, thả hoa xuống dòng Thạch Hãn, tưởng nhớ những người lính trẻ đã hóa thân thành bất tử.', '["Diễn ra trận chiến 81 ngày đêm năm 1972.","Được xây dựng từ thời vua Gia Long đầu thế kỷ 19.","Đài tưởng niệm trung tâm là ngôi mộ tập thể không tên.","Dòng Thạch Hãn bên cạnh được coi là dòng sông hoa."]', '["Thả hoa đăng xuống sông Thạch Hãn để tưởng niệm các liệt sĩ.","Nên có thuyết minh viên để cảm nhận trọn vẹn câu chuyện lịch sử."]', 'Quanh năm', 'Nửa ngày', '', '07:00 - 17:00', '["verified","popular"]', '["history","culture"]', '[{"seed":"thanh-co-dai-tuong-niem","caption":"Đài tưởng niệm trung tâm","ratio":"16/9"},{"seed":"thanh-co-cong-thanh","caption":"Cổng thành cổ rêu phong","ratio":"4/3"},{"seed":"thanh-co-thach-han","caption":"Lối vào đài tưởng niệm thành cổ rợp bóng cây","ratio":"1/1"}]', '["dia-dao-vinh-moc"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dia-dao-vinh-moc', 'dia-dao-vinh-moc', 'quang-tri', 'Địa đạo Vịnh Mốc', 'Vinh Moc Tunnels', 'museum', 107.025, 17.0244, 'Làng hầm kỳ vĩ trong lòng đất, nơi cả cộng đồng kiên cường sống và chiến đấu suốt những năm mưa bom bão đạn.', 'Địa đạo Vịnh Mốc là kỳ tích của ý chí con người Quảng Trị, một ngôi làng nằm sâu trong lòng đất đỏ bazan vùng Vĩnh Linh. Suốt những năm bom đạn ác liệt, người dân nơi đây đã đào hệ thống hầm dài gần hai cây số với ba tầng sâu, đủ chỗ cho hàng trăm người sinh sống. Trong lòng đất ấy có giếng nước, nhà hộ sinh nơi mười bảy em bé chào đời, hội trường, trạm xá và cả những căn hộ gia đình. Bước vào địa đạo mát lạnh, du khách không khỏi cảm phục sức sống mãnh liệt và tinh thần bất khuất của một dân tộc, biến lòng đất thành pháo đài giữ làng giữ nước.', '["Hệ thống hầm dài gần 2km, chia làm ba tầng sâu.","Có 17 em bé được sinh ra ngay trong lòng địa đạo.","Đào trong điều kiện bom đạn từ năm 1965 đến 1967.","Là Di tích Lịch sử Quốc gia đặc biệt tiêu biểu."]', '["Mang theo đèn pin và mặc đồ gọn nhẹ khi xuống hầm.","Đi cùng hướng dẫn viên để nghe câu chuyện về làng hầm."]', 'Tháng 2 đến tháng 8', 'Nửa ngày', '40.000đ', '07:00 - 17:00', '["verified","ai-recommended","popular"]', '["history","culture"]', '[{"seed":"vinh-moc-cua-ham","caption":"Cửa hầm địa đạo Vịnh Mốc","ratio":"16/9"},{"seed":"vinh-moc-long-dat","caption":"Đường hầm trong lòng đất","ratio":"4/3"},{"seed":"vinh-moc-nha-ho-sinh","caption":"Căn nhà hộ sinh dưới hầm","ratio":"1/1"}]', '["thanh-co-quang-tri","dao-con-co"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dao-con-co', 'dao-con-co', 'quang-tri', 'Đảo Cồn Cỏ', 'Con Co Island', 'island', 107.3389, 17.1583, 'Hòn đảo tiền tiêu xanh ngắt giữa biển khơi, kết hợp vẻ đẹp hoang sơ với những trang sử hào hùng giữ đảo.', 'Cồn Cỏ là hòn đảo tiền tiêu thiêng liêng của Tổ quốc, nằm cách đất liền Quảng Trị khoảng ba mươi cây số. Từng là chiến địa anh hùng trong kháng chiến chống Mỹ, đảo nhỏ này đã kiên cường bám trụ giữa muôn trùng bom đạn, đi vào câu hát ngợi ca. Ngày nay, Cồn Cỏ khoác lên mình màu xanh tươi mát của rừng nguyên sinh và làn nước biển trong vắt ôm lấy những rạn san hô rực rỡ. Du khách có thể lặn ngắm san hô, dạo quanh ngọn hải đăng cổ, đạp xe vòng quanh đảo và thưởng thức cua đá, ốc biển tươi ngon. Một viên ngọc hoang sơ đang dần mở cửa đón những ai ưa khám phá.', '["Cách đất liền khoảng 30km, là đảo tiền tiêu của Quảng Trị.","Diện tích chỉ khoảng 2,3 km vuông nhưng giàu sinh thái.","Có rừng nguyên sinh và rạn san hô đa dạng.","Được phong tặng danh hiệu Anh hùng trong kháng chiến."]', '["Đặt tàu cao tốc và lưu trú trước vì dịch vụ trên đảo còn hạn chế.","Mang theo đồ lặn để khám phá rạn san hô quanh đảo."]', 'Tháng 4 đến tháng 7', '1 - 2 ngày', '', 'Cả ngày', '["hidden-gem","new","ai-recommended"]', '["island","nature","beach"]', '[{"seed":"con-co-bien-xanh","caption":"Biển xanh ôm đảo Cồn Cỏ","ratio":"16/9"},{"seed":"con-co-hai-dang","caption":"Ngọn hải đăng cổ trên đảo","ratio":"4/3"},{"seed":"con-co-san-ho","caption":"Rạn san hô rực rỡ","ratio":"1/1"}]', '["dia-dao-vinh-moc"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('qng-ly-son', 'dao-ly-son', 'quang-ngai', 'Đảo Lý Sơn', 'Ly Son Island', 'island', 109.1167, 15.3833, 'Đảo núi lửa giữa biển khơi, vương quốc tỏi với những bãi đá đen, miệng núi lửa cổ và biển xanh ngắt.', 'Lý Sơn nổi lên giữa biển Đông như một bảo tàng địa chất sống, được kiến tạo từ năm ngọn núi lửa phun trào hàng triệu năm trước. Người dân nơi đây gọi đảo là quê hương của hùng binh Hoàng Sa, nơi mỗi năm tổ chức Lễ Khao lề thế lính tri ân những người con ra giữ biển. Đặt chân lên đỉnh Thới Lới, bạn nhìn thấy ruộng tỏi xanh mướt trải dài trên nền đá bazan, hồ nước ngọt phẳng lặng và cổng Tò Vò trầm mặc soi bóng hoàng hôn. Biển ở đây trong vắt, lặn ngắm san hô tựa lạc vào thủy cung. Lý Sơn vừa hùng vĩ vừa dung dị, níu chân lữ khách.', '["Hình thành từ 5 miệng núi lửa cổ phun trào cách đây khoảng 25-30 triệu năm.","Được mệnh danh là ''Vương quốc tỏi'' với giống tỏi cô đơn nổi tiếng cả nước.","Là nơi tổ chức Lễ Khao lề thế lính Hoàng Sa, di sản văn hóa phi vật thể quốc gia.","Cổng Tò Vò là vòm đá bazan tự nhiên được giới nhiếp ảnh săn đón.","Gồm đảo Lớn và đảo Bé (An Bình), cách đất liền khoảng 15 hải lý."]', '["Đặt vé tàu cao tốc từ cảng Sa Kỳ trước, mùa biển động nên kiểm tra lịch tàu.","Thuê xe máy chạy quanh đảo và mang theo kem chống nắng vì nắng đảo rất gắt."]', 'Tháng 6 đến tháng 9, biển êm và trời trong', '2 ngày 1 đêm', '', 'Cả ngày', '["trending","popular","verified"]', '["island","nature","photography","history"]', '[{"seed":"lyson-thoiloi","caption":"Đỉnh Thới Lới nhìn ra biển","ratio":"16/9"},{"seed":"lyson-tovo","caption":"Cổng Tò Vò lúc hoàng hôn","ratio":"4/3"},{"seed":"lyson-toi","caption":"Ruộng tỏi xanh trên nền đá bazan","ratio":"1/1"}]', '["qng-sa-huynh"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('qng-sa-huynh', 'bien-sa-huynh', 'quang-ngai', 'Biển Sa Huỳnh', 'Sa Huynh Beach', 'beach', 108.9667, 14.6667, 'Bãi biển cát vàng óng ả nơi cực nam Quảng Ngãi, gắn với nền văn hóa Sa Huỳnh cổ và những đồng muối trắng.', 'Sa Huỳnh đẹp một vẻ đẹp hiền hòa với bờ cát vàng ánh lên dưới nắng, ôm lấy làn nước biển xanh biếc và những rặng dừa nghiêng mình trong gió. Vùng đất này còn là cái nôi của nền văn hóa Sa Huỳnh rực rỡ cách đây hơn hai ngàn năm, để lại những mộ chum và đồ trang sức tinh xảo khiến giới khảo cổ say mê. Bên cạnh biển là những cánh đồng muối trắng phau, nơi diêm dân cần mẫn cào muối dưới nắng trưa, tạo nên bức tranh lao động mộc mạc. Buổi sớm, làng chài thức giấc với thuyền thúng rộn ràng cập bến, cá tươi đầy khoang. Sa Huỳnh là điểm dừng bình yên cho ai muốn trốn ồn ào phố thị.', '["Là nơi phát hiện nền văn hóa Sa Huỳnh có niên đại hơn 2.000 năm.","Đồng muối Sa Huỳnh là một trong những vựa muối lâu đời của miền Trung.","Tên gọi xuất phát từ ''Sa Hoàng'' nghĩa là bãi cát vàng.","Nằm ngay quốc lộ 1A, giáp ranh tỉnh Bình Định."]', '["Ghé chợ cá làng chài buổi sáng sớm để mua hải sản tươi giá tốt.","Kết hợp tham quan bảo tàng và di chỉ văn hóa Sa Huỳnh gần đó."]', 'Tháng 4 đến tháng 8', 'Nửa ngày', '', 'Cả ngày', '["hidden-gem","verified"]', '["beach","history","nature","culture"]', '[{"seed":"sahuynh-bai","caption":"Bãi cát vàng cong hình lưỡi liềm","ratio":"16/9"},{"seed":"sahuynh-muoi","caption":"Bãi cát vàng cong dài ôm vịnh biển lặng","ratio":"4/3"},{"seed":"sahuynh-thuyen","caption":"Cung đường ven biển uốn lượn bên bờ cát","ratio":"1/1"}]', '["qng-ly-son"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bdi-ky-co-eo-gio', 'ky-co-eo-gio', 'binh-dinh', 'Kỳ Co - Eo Gió', 'Ky Co - Eo Gio', 'beach', 109.3417, 13.7233, 'Bộ đôi tuyệt tác của Quy Nhơn: bãi tắm Kỳ Co nước xanh ngọc và eo biển Eo Gió uốn lượn giữa vách núi.', 'Được ví như ''Maldives của Việt Nam'', Kỳ Co khiến lữ khách ngỡ ngàng với làn nước trong vắt phân tầng từ xanh ngọc đến xanh thẳm, ôm lấy bãi cát trắng mịn nằm lọt giữa hai triền núi đá. Cách đó không xa, Eo Gió hiện ra như một dải lụa uốn cong, nơi gió biển luồn qua khe núi tạo thành âm thanh vi vu suốt ngày đêm. Con đường ven biển quanh Eo Gió được tô điểm bằng những giàn hoa giấy rực rỡ, là điểm ngắm bình minh và hoàng hôn tuyệt đẹp. Đứng trên vách đá nhìn xuống, từng con sóng bạc đầu vỗ vào ghềnh đá đen, đàn chim yến chao lượn. Kỳ Co và Eo Gió là hành trình không thể bỏ lỡ khi đến Bình Định.', '["Eo Gió được mệnh danh là nơi ngắm hoàng hôn đẹp nhất Việt Nam.","Kỳ Co được tiếp cận bằng ca nô hoặc đường bộ vượt núi Triều Châu.","Nước biển Kỳ Co phân tầng màu rõ rệt nhờ đáy cát trắng và san hô.","Eo Gió là vùng có nhiều hang yến tự nhiên ven biển.","Cả hai nằm tại bán đảo Nhơn Lý, cách trung tâm Quy Nhơn khoảng 20 km."]', '["Đi ca nô từ Nhơn Lý ra Kỳ Co để tiết kiệm sức và ngắm cảnh biển.","Mang giày bám tốt khi leo cầu thang quanh Eo Gió, nắng trưa khá gắt."]', 'Tháng 3 đến tháng 9', '1 ngày', '25.000đ (Eo Gió)', '06:00 - 18:00', '["trending","popular","verified"]', '["beach","nature","photography"]', '[{"seed":"kyco-bai","caption":"Bãi tắm Kỳ Co nước xanh ngọc","ratio":"16/9"},{"seed":"eogio-cong","caption":"Eo Gió uốn lượn giữa vách núi","ratio":"4/3"},{"seed":"eogio-hoa","caption":"Đường hoa giấy ven biển Eo Gió","ratio":"1/1"}]', '["bdi-thap-banh-it"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bdi-thap-banh-it', 'thap-banh-it', 'binh-dinh', 'Tháp Bánh Ít', 'Banh It Towers', 'temple', 109.1147, 13.8636, 'Cụm tháp Chăm cổ kính trên đỉnh đồi, một trong những quần thể tháp đẹp và còn nguyên vẹn nhất Bình Định.', 'Tháp Bánh Ít sừng sững trên ngọn đồi nhìn ra dòng sông Côn, là quần thể bốn ngôi tháp Chăm được xây dựng từ cuối thế kỷ XI đầu thế kỷ XII. Từ xa, cụm tháp gợi hình những chiếc bánh ít lá gai dân dã của xứ Nẫu, vì thế mà thành tên. Mỗi tháp một dáng vẻ: tháp Cổng vạm vỡ, tháp Bia thanh thoát, tháp Yên Ngựa với mái cong độc đáo và tháp Chính uy nghi cao gần hai mươi mét. Những phù điêu thần Shiva múa, các họa tiết hoa văn được chạm khắc tinh xảo trên gạch nung đỏ au, kể câu chuyện về một vương quốc Chăm Pa từng rực rỡ. Đứng giữa tháp đón gió đồng, ta như nghe vọng tiếng trống Chăm xa xưa.', '["Được xây dựng vào khoảng cuối thế kỷ XI - đầu thế kỷ XII.","Gồm 4 tháp với phong cách kiến trúc Chăm Pa khác nhau.","Được giới thiệu trong cuốn ''1.001 công trình kiến trúc phải đến trong cuộc đời''.","Tên gọi do hình dáng cụm tháp giống chiếc bánh ít lá gai.","Tháp Yên Ngựa có phần mái cong hình yên ngựa rất hiếm gặp."]', '["Đến vào sáng sớm hoặc chiều muộn để tránh nắng và chụp ảnh đẹp.","Leo bậc thang lên đỉnh đồi nên mang theo nước uống và đội mũ."]', 'Tháng 1 đến tháng 8', '1 - 2 giờ', '15.000đ', '07:00 - 17:30', '["verified","popular"]', '["temple","history","culture","photography"]', '[{"seed":"banhit-chinh","caption":"Tháp Chính uy nghi trên đồi","ratio":"16/9"},{"seed":"banhit-yenngua","caption":"Tháp Yên Ngựa mái cong độc đáo","ratio":"4/3"},{"seed":"banhit-phudieu","caption":"Cụm tháp Chăm cổ nhô lên giữa rừng xanh","ratio":"1/1"}]', '["bdi-ky-co-eo-gio"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('pye-ganh-da-dia', 'ganh-da-dia', 'phu-yen', 'Gành Đá Đĩa', 'Da Dia Reef', 'park', 109.2939, 13.4833, 'Kỳ quan địa chất với hàng vạn cột đá bazan đen xếp tầng tựa chồng đĩa khổng lồ vươn ra biển.', 'Gành Đá Đĩa là một tuyệt tác mà thiên nhiên dày công kiến tạo từ dòng dung nham núi lửa nguội lạnh hàng triệu năm trước. Khi đông cứng, đá bazan nứt vỡ thành những khối lăng trụ lục giác, ngũ giác đều đặn đến khó tin, xếp chồng khít nhau như những chồng đĩa được bàn tay người sắp đặt. Cả gành đá đen tuyền trải rộng hơn năm chục mét, một nửa ngâm mình dưới làn sóng biếc, nửa kia phơi mình đón nắng. Sóng vỗ vào ghềnh tung bọt trắng xóa, tạo nên khung cảnh vừa kỳ vĩ vừa nên thơ. Đây là một trong số ít thắng cảnh đá đĩa hiếm hoi trên thế giới, được công nhận là Di tích quốc gia đặc biệt và là niềm tự hào của xứ hoa vàng cỏ xanh.', '["Hình thành từ dung nham bazan nứt vỡ thành các cột đá lục giác, ngũ giác.","Được công nhận là Di tích quốc gia đặc biệt năm 2020.","Gành rộng khoảng 50m, dài 200m với hàng nghìn trụ đá.","Là một trong vài thắng cảnh đá đĩa hiếm có trên thế giới.","Gần đó có nhà thờ Mằng Lăng cổ và bãi Bàng hoang sơ."]', '["Đi vào sáng sớm khi thủy triều xuống để dạo trên gành đá an toàn.","Cẩn thận khi bước trên đá ướt vì khá trơn, nên mang giày bám tốt."]', 'Tháng 3 đến tháng 9', '2 - 3 giờ', '20.000đ', '06:30 - 18:00', '["trending","popular","verified"]', '["nature","photography","history"]', '[{"seed":"gddia-cot","caption":"Cột đá bazan xếp tầng kỳ vĩ","ratio":"16/9"},{"seed":"gddia-song","caption":"Sóng vỗ trắng xóa vào ghềnh đá","ratio":"4/3"},{"seed":"gddia-toancanh","caption":"Toàn cảnh gành đá vươn ra biển","ratio":"1/1"}]', '["pye-bai-xep"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('pye-bai-xep', 'bai-xep', 'phu-yen', 'Bãi Xép', 'Xep Beach', 'beach', 109.3083, 13.3306, 'Bãi biển hoang sơ với đồi cỏ xanh và ghềnh đá, nổi tiếng qua phim ''Tôi thấy hoa vàng trên cỏ xanh''.', 'Bãi Xép trở thành cái tên trong mơ của bao người sau khi xuất hiện trong bộ phim ''Tôi thấy hoa vàng trên cỏ xanh'', với những thước phim đẹp đến nao lòng. Nơi đây là sự hòa quyện tuyệt vời giữa bãi cát vàng cong mềm mại, đồi cỏ xanh mướt thoai thoải và ghềnh đá đen nhô ra biển. Buổi sáng, ánh nắng đầu ngày trải vàng trên triền cỏ, gió biển mơn man mang theo vị mặn mòi. Lữ khách thích leo lên mỏm đá cao ngắm toàn cảnh vịnh biển trải dài, hoặc thả mình trên thảm cỏ ngắm những con thuyền đánh cá xa xa. Không gian yên tĩnh, mộc mạc của Bãi Xép gợi cảm giác bình yên hiếm có, như chạm vào một miền ký ức tuổi thơ trong trẻo.', '["Là bối cảnh chính của phim ''Tôi thấy hoa vàng trên cỏ xanh'' (2015).","Cách thành phố Tuy Hòa khoảng 13 km về phía bắc.","Nổi bật với đồi cỏ xanh, ghềnh đá đen và bãi cát vàng đan xen.","Có hai bãi nhỏ là Bãi Xép và bãi Cây Me liền kề."]', '["Đến lúc bình minh để ngắm nắng vàng trải trên đồi cỏ tuyệt đẹp.","Mang theo nước và đồ ăn nhẹ vì dịch vụ tại bãi còn hạn chế."]', 'Tháng 1 đến tháng 8', 'Nửa ngày', '20.000đ', '06:00 - 18:00', '["popular","verified","hidden-gem"]', '["beach","nature","photography"]', '[{"seed":"baixep-doico","caption":"Triền đồi xương rồng nghiêng xuống bãi biển vắng","ratio":"16/9"},{"seed":"baixep-binhminh","caption":"Mặt trời ló rạng sau mỏm núi, sóng vỗ bờ cát","ratio":"4/3"},{"seed":"baixep-ghenh","caption":"Ghềnh đá đen nhô ra biển","ratio":"1/1"}]', '["pye-ganh-da-dia"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ntn-vinh-vinh-hy', 'vinh-vinh-hy', 'ninh-thuan', 'Vịnh Vĩnh Hy', 'Vinh Hy Bay', 'beach', 109.2058, 11.71, 'Một trong những vịnh biển đẹp nhất Việt Nam, nước trong vắt ôm trọn rừng núi Núi Chúa và rạn san hô rực rỡ.', 'Vĩnh Hy được xếp vào hàng những vịnh biển đẹp nhất Việt Nam, nơi rừng và biển giao hòa trong một bức tranh sơn thủy hữu tình. Vịnh nằm gọn trong lòng Vườn quốc gia Núi Chúa, ba bề là núi non trùng điệp ôm lấy mặt nước phẳng lặng xanh như ngọc. Ngồi trên thuyền đáy kính lướt trên vịnh, bạn ngắm những rạn san hô đủ sắc màu, đàn cá tung tăng và làn nước trong đến tận đáy. Cung đường ven biển dẫn đến Vĩnh Hy được mệnh danh là một trong những con đường ven biển đẹp nhất nước, với một bên là vách núi, một bên là biển khơi bao la. Làng chài Vĩnh Hy nhỏ bé nép mình bên vịnh, mang đến hải sản tươi rói và nhịp sống chậm rãi, an yên.', '["Là một trong 4 vịnh đẹp nhất Việt Nam theo nhiều bình chọn.","Nằm trong Khu dự trữ sinh quyển thế giới Núi Chúa.","Có thể ngắm san hô qua thuyền đáy kính hoặc lặn biển.","Cung đường ven biển DT702 dẫn vào vịnh nổi tiếng tuyệt đẹp.","Gần vịnh có Hang Rái với bãi san hô cổ độc đáo."]', '["Đi thuyền đáy kính buổi sáng khi nước trong để ngắm san hô rõ nhất.","Kết hợp ghé Hang Rái và vườn nho Ninh Thuận trên cùng cung đường."]', 'Tháng 1 đến tháng 8', '1 ngày', 'Tùy dịch vụ thuyền', 'Cả ngày', '["trending","popular","verified"]', '["beach","nature","island","photography"]', '[{"seed":"vinhhy-vinh","caption":"Vịnh Vĩnh Hy xanh ngọc ôm rừng núi","ratio":"16/9"},{"seed":"vinhhy-sanho","caption":"Vịnh nhỏ neo đậu hàng trăm thuyền cá","ratio":"4/3"},{"seed":"vinhhy-duongven","caption":"Cung đường ven biển Núi Chúa","ratio":"1/1"}]', '["ntn-po-klong-garai"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ntn-po-klong-garai', 'thap-po-klong-garai', 'ninh-thuan', 'Tháp Po Klong Garai', 'Po Klong Garai Tower', 'temple', 108.9583, 11.5969, 'Cụm tháp Chăm hùng vĩ trên đồi Trầu, công trình kiến trúc và tín ngưỡng còn nguyên vẹn bậc nhất của người Chăm.', 'Tháp Po Klong Garai sừng sững trên đồi Trầu, là cụm tháp Chăm được xây dựng từ cuối thế kỷ XIII để thờ vua Po Klong Garai, vị vua có công trị thủy và dạy dân làm thủy lợi. Đây được xem là quần thể đền tháp Chăm Pa đẹp và còn nguyên vẹn nhất hiện nay, gồm tháp Chính cao hơn hai mươi mét, tháp Lửa và tháp Cổng. Trên thân tháp gạch đỏ au là vô số phù điêu thần Shiva, bò thần Nandin và các hoa văn được chạm khắc tinh xảo, tinh tế đến từng đường nét. Tháp không chỉ là di sản kiến trúc mà còn là trung tâm tín ngưỡng sống, nơi đồng bào Chăm tổ chức lễ hội Katê linh thiêng vào mỗi mùa thu, rộn ràng tiếng trống Ginăng và điệu múa quạt uyển chuyển.', '["Được xây dựng vào cuối thế kỷ XIII, thời vua Chăm Po Klong Garai.","Là quần thể đền tháp Chăm còn nguyên vẹn nhất Việt Nam.","Là Di tích kiến trúc nghệ thuật quốc gia đặc biệt.","Nơi tổ chức lễ hội Katê của người Chăm hằng năm.","Bên trong tháp Chính thờ tượng vua dưới dạng linga - Mukhalinga."]', '["Ghé vào dịp lễ hội Katê (khoảng tháng 9-10) để xem nghi lễ đặc sắc.","Đi buổi chiều mát, ánh nắng nghiêng làm tháp gạch lên màu rất đẹp."]', 'Tháng 1 đến tháng 9, đẹp nhất mùa lễ Katê', '1 - 2 giờ', '20.000đ', '07:00 - 17:00', '["verified","festival","popular"]', '["temple","history","culture","photography"]', '[{"seed":"poklong-chinh","caption":"Tháp Chính trên đồi Trầu","ratio":"16/9"},{"seed":"poklong-kate","caption":"Lễ hội Katê của người Chăm","ratio":"4/3"},{"seed":"poklong-phudieu","caption":"Quần thể tháp gạch Chăm rêu phong trên đồi cỏ","ratio":"1/1"}]', '["ntn-vinh-vinh-hy"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ktm-nha-tho-go', 'nha-tho-go-kon-tum', 'kon-tum', 'Nhà thờ gỗ Kon Tum', 'Kon Tum Wooden Church', 'temple', 108.005, 14.3528, 'Nhà thờ Chính tòa hơn trăm tuổi làm hoàn toàn bằng gỗ, kết hợp tinh tế kiến trúc Roman và nhà sàn Tây Nguyên.', 'Nhà thờ gỗ Kon Tum là viên ngọc kiến trúc giữa lòng phố núi, được các linh mục người Pháp khởi dựng năm 1913 hoàn toàn bằng gỗ cà chít quý hiếm. Công trình là sự giao thoa độc đáo giữa phong cách Roman cổ kính của phương Tây và nét mộc mạc của nhà sàn đồng bào Ba Na bản địa. Toàn bộ khung gỗ được kết nối bằng mộng mà không dùng đến một cây đinh, trải qua hơn một thế kỷ vẫn vững chãi, vàng óng dưới nắng cao nguyên. Bước vào bên trong, ánh sáng len qua những ô cửa kính màu nhuộm không gian thành một dải lung linh huyền ảo. Sân nhà thờ rợp bóng cây, là nơi đồng bào các dân tộc tụ họp mỗi dịp lễ, lưu giữ trọn vẹn hồn cốt văn hóa Tây Nguyên trong từng thớ gỗ.', '["Được xây dựng năm 1913 bởi các linh mục người Pháp.","Làm hoàn toàn bằng gỗ cà chít, ghép mộng không dùng đinh.","Kết hợp kiến trúc Roman và phong cách nhà sàn Ba Na.","Là nhà thờ Chính tòa của giáo phận Kon Tum.","Khung gỗ và tường được kết dính bằng vữa trộn rơm truyền thống."]', '["Ghé buổi chiều khi nắng nghiêng làm thân gỗ và cửa kính lên màu đẹp.","Giữ yên tĩnh và trang phục lịch sự khi vào bên trong thánh đường."]', 'Tháng 11 đến tháng 4', '1 giờ', '', 'Cả ngày (lễ theo lịch nhà thờ)', '["popular","verified"]', '["temple","history","culture","city","photography"]', '[{"seed":"nhathogo-mattien","caption":"Mặt tiền nhà thờ gỗ trăm tuổi","ratio":"16/9"},{"seed":"nhathogo-noithat","caption":"Không gian gỗ và cửa kính màu bên trong","ratio":"4/3"},{"seed":"nhathogo-thapchuong","caption":"Tháp chuông vươn cao giữa phố núi","ratio":"1/1"}]', '["ktm-mang-den"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ktm-mang-den', 'khu-du-lich-mang-den', 'kon-tum', 'Khu du lịch Măng Đen', 'Mang Den Resort Area', 'mountain', 108.2853, 14.63, 'Đà Lạt thứ hai của Tây Nguyên với rừng thông bạt ngàn, thác nước, hồ trong và khí hậu se lạnh quanh năm.', 'Nằm ở độ cao hơn một nghìn hai trăm mét, Măng Đen được ví như ''Đà Lạt thứ hai'' của Tây Nguyên với rừng thông nguyên sinh bạt ngàn và khí hậu mát lạnh quanh năm. Buổi sớm, sương mù giăng kín những con dốc thông, không gian tĩnh lặng và trong lành đến lạ. Vùng đất này được thiên nhiên hào phóng ban tặng những hồ nước phẳng lặng, các con thác trắng xóa như thác Pa Sỹ, cùng những vườn hoa, đồi chè xanh mướt. Măng Đen còn linh thiêng với tượng Đức Mẹ giữa rừng thông, thu hút đông đảo khách hành hương. Người Mơ Nâm, Xơ Đăng bản địa vẫn giữ nếp sống mộc mạc, mến khách. Đến Măng Đen là tìm về chốn bình yên, để hít căng lồng ngực hương thông và quên đi mọi muộn phiền.', '["Nằm ở độ cao khoảng 1.200m, khí hậu mát mẻ quanh năm.","Được mệnh danh là ''Đà Lạt thứ hai'' của Tây Nguyên.","Có thác Pa Sỹ, hồ Đăk Ke và nhiều rừng thông đẹp.","Tượng Đức Mẹ Măng Đen là điểm hành hương nổi tiếng.","Thuộc huyện Kon Plông, cách thành phố Kon Tum khoảng 50 km."]', '["Mang theo áo ấm vì đêm và sáng sớm ở Măng Đen khá lạnh.","Thuê xe máy hoặc ô tô để di chuyển giữa các điểm tham quan cách xa nhau."]', 'Tháng 11 đến tháng 3, mùa hoa và sương mù', '2 ngày 1 đêm', '', 'Cả ngày', '["trending","new","ai-recommended"]', '["mountain","nature","photography","food"]', '[{"seed":"mangden-thong","caption":"Thác nước trắng xóa đổ xuống hồ xanh giữa rừng","ratio":"16/9"},{"seed":"mangden-pasy","caption":"Thác Pa Sỹ trắng xóa giữa rừng","ratio":"4/3"},{"seed":"mangden-ho","caption":"Hồ Đăk Ke phẳng lặng buổi sớm","ratio":"1/1"}]', '["ktm-nha-tho-go"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('gli-bien-ho-tnung', 'bien-ho-tnung', 'gia-lai', 'Biển Hồ T''Nưng', 'T''Nung Lake (Bien Ho)', 'lake', 108.01, 14.0581, 'Hồ nước ngọt mênh mông trên miệng núi lửa cổ, được ví như ''đôi mắt Pleiku'' xanh trong giữa đại ngàn.', 'Biển Hồ T''Nưng là viên ngọc bích giữa cao nguyên Pleiku, một hồ nước ngọt rộng lớn hình thành từ miệng núi lửa đã ngủ yên hàng triệu năm. Người ta gọi nơi đây là ''đôi mắt Pleiku'' bởi mặt hồ xanh thẳm, trong veo, phản chiếu mây trời và những hàng thông reo vi vu trong gió. Con đường dẫn ra hồ rợp bóng thông cổ thụ, dẫn tới một đài vọng cảnh nhô ra mặt nước, nơi du khách phóng tầm mắt ôm trọn không gian bao la, tĩnh lặng. Buổi bình minh, sương mỏng giăng trên mặt hồ, từng đàn chim ríu rít, khung cảnh đẹp như tranh thủy mặc. Biển Hồ gắn với những truyền thuyết bi thương của người Gia Rai, càng tô thêm vẻ huyền bí và thơ mộng cho thắng cảnh trứ danh của phố núi.', '["Hình thành từ miệng núi lửa cổ đã ngừng hoạt động.","Được mệnh danh là ''đôi mắt Pleiku'' và đi vào thơ ca, âm nhạc.","Là hồ nước ngọt tự nhiên lớn, cung cấp nước cho thành phố Pleiku.","Cách trung tâm Pleiku khoảng 7 km về phía bắc.","Gần đó có hàng thông trăm tuổi và đồi chè Biển Hồ nổi tiếng."]', '["Đến lúc bình minh hoặc hoàng hôn để ngắm mặt hồ đẹp nhất.","Kết hợp ghé hàng thông trăm tuổi và đồi chè gần Biển Hồ."]', 'Tháng 11 đến tháng 4', '2 - 3 giờ', '', 'Cả ngày', '["popular","verified","trending"]', '["lake","nature","photography"]', '[{"seed":"bienho-matho","caption":"Mặt hồ xanh thẳm giữa đại ngàn","ratio":"16/9"},{"seed":"bienho-vongcanh","caption":"Đài vọng cảnh nhô ra mặt nước","ratio":"4/3"},{"seed":"bienho-thong","caption":"Hàng thông cổ thụ dẫn ra hồ","ratio":"1/1"}]', '["gli-chua-minh-thanh"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('gli-chua-minh-thanh', 'chua-minh-thanh', 'gia-lai', 'Chùa Minh Thành', 'Minh Thanh Pagoda', 'temple', 107.9925, 13.965, 'Ngôi chùa lộng lẫy mang đậm phong cách kiến trúc Nhật Bản và Đài Loan, biểu tượng tâm linh của phố núi Pleiku.', 'Chùa Minh Thành nổi bật giữa phố núi Pleiku với lối kiến trúc độc đáo, gợi nhớ những ngôi chùa cổ kính của Nhật Bản và Đài Loan hơn là chùa Việt truyền thống. Điểm nhấn của chùa là bảo tháp xá lợi cao chín tầng vươn lên trời xanh, cùng chánh điện uy nghi với những đường mái cong vút, cột gỗ chạm trổ tinh xảo và tượng Phật dát vàng trang nghiêm. Khuôn viên chùa rộng rãi, thoáng đãng, điểm xuyết hồ nước, vườn cây và những bức tượng Phật, La Hán sống động. Mỗi góc nhỏ đều được chăm chút tỉ mỉ, hài hòa giữa thiên nhiên và kiến trúc tâm linh. Đến đây, lữ khách không chỉ chiêm bái mà còn đắm mình trong không gian tĩnh tại, an nhiên, bỏ lại sau lưng những bộn bề của cuộc sống thường nhật.', '["Mang phong cách kiến trúc Phật giáo Nhật Bản và Đài Loan.","Bảo tháp xá lợi cao 9 tầng là điểm nhấn nổi bật.","Khởi dựng từ năm 1964 và được trùng tu, mở rộng nhiều lần.","Cách trung tâm thành phố Pleiku khoảng 2 km.","Chánh điện có nhiều tượng Phật và La Hán được chạm khắc công phu."]', '["Mặc trang phục kín đáo, lịch sự khi vào khu vực chánh điện.","Đến buổi sáng để chụp ảnh chùa với ánh nắng đẹp và ít người."]', 'Tháng 11 đến tháng 4', '1 - 2 giờ', '', '06:00 - 20:00', '["popular","verified"]', '["temple","culture","city","photography"]', '[{"seed":"minhthanh-baothap","caption":"Bảo tháp xá lợi chín tầng","ratio":"16/9"},{"seed":"minhthanh-chanhdien","caption":"Chánh điện mái cong uy nghi","ratio":"4/3"},{"seed":"minhthanh-tuong","caption":"Tượng Phật dát vàng trong khuôn viên","ratio":"1/1"}]', '["gli-bien-ho-tnung"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dno-cong-vien-dia-chat', 'cong-vien-dia-chat-dak-nong', 'dak-nong', 'Công viên địa chất toàn cầu Đắk Nông', 'Dak Nong UNESCO Global Geopark', 'park', 107.69, 12.264, 'Công viên địa chất toàn cầu UNESCO với hệ thống hang động núi lửa dài nhất Đông Nam Á và cảnh quan núi lửa kỳ vĩ.', 'Công viên địa chất toàn cầu Đắk Nông được UNESCO công nhận năm 2020, là kho báu địa chất trải rộng trên sáu huyện với diện tích hơn bốn nghìn cây số vuông. Điểm độc đáo bậc nhất là hệ thống hang động núi lửa trong đá bazan dài và đẹp nhất Đông Nam Á, được hình thành từ những dòng dung nham phun trào cách đây hàng triệu năm. Bên cạnh đó là các miệng núi lửa cổ, thác nước hùng vĩ, hồ nước trong xanh và những cánh rừng nguyên sinh trù phú. Vùng đất này còn lưu giữ dấu tích của người tiền sử cùng kho tàng văn hóa đặc sắc của đồng bào M''Nông, Mạ với không gian văn hóa cồng chiêng Tây Nguyên. Đắk Nông là điểm đến lý tưởng cho những ai đam mê khám phá thiên nhiên và lịch sử kiến tạo của Trái Đất.', '["Được UNESCO công nhận là Công viên địa chất toàn cầu năm 2020.","Sở hữu hệ thống hang động núi lửa dài nhất Đông Nam Á.","Trải rộng trên 6 huyện với diện tích hơn 4.700 km².","Gắn với Không gian văn hóa cồng chiêng Tây Nguyên - di sản UNESCO.","Có 3 tuyến du lịch trải nghiệm với hàng chục điểm di sản."]', '["Thuê hướng dẫn viên địa phương khi khám phá hệ thống hang động núi lửa.","Mang đèn pin, giày bám tốt và mũ bảo hộ khi vào hang dung nham."]', 'Tháng 11 đến tháng 4, mùa khô', '2 - 3 ngày', 'Tùy điểm tham quan', '07:00 - 17:00', '["unesco","trending","verified","ai-recommended"]', '["park","nature","history","culture","mountain"]', '[{"seed":"daknong-hangnui","caption":"Hang động núi lửa trong đá bazan","ratio":"16/9"},{"seed":"daknong-miengnui","caption":"Miệng núi lửa cổ giữa rừng xanh","ratio":"4/3"},{"seed":"daknong-congchieng","caption":"Văn hóa cồng chiêng đồng bào M''Nông","ratio":"1/1"}]', '["dno-thac-dray-sap"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dno-thac-dray-sap', 'thac-dray-sap', 'dak-nong', 'Thác Dray Sáp', 'Dray Sap Waterfall', 'waterfall', 107.9483, 12.5394, 'Thác ''khói'' hùng vĩ giữa rừng nguyên sinh, dòng nước tung bọt trắng xóa tạo màn sương mờ ảo quanh năm.', 'Thác Dray Sáp, theo tiếng Ê Đê nghĩa là ''thác khói'', là một trong những ngọn thác đẹp và hùng vĩ nhất Tây Nguyên. Từ trên cao, dòng sông Sêrêpốk đổ xuống vách đá bazan rộng hàng trăm mét, nước tung bọt trắng xóa va vào ghềnh đá tạo nên màn hơi nước mịt mù như khói sương, vì thế mà thành tên. Bao quanh thác là cánh rừng nguyên sinh rậm rạp với những thân cây cổ thụ, dây leo chằng chịt và bầu không khí mát lạnh, trong lành. Đứng trước thác, tiếng nước gầm vang dội cả một vùng, khiến lữ khách choáng ngợp trước sức mạnh hoang dã của thiên nhiên. Dray Sáp gắn liền với truyền thuyết tình yêu đẹp mà buồn của đôi trai gái Ê Đê, làm say lòng bao người đặt chân đến chốn đại ngàn kỳ vĩ này.', '["Tên ''Dray Sáp'' theo tiếng Ê Đê nghĩa là ''thác khói''.","Nằm trên dòng sông Sêrêpốk chảy ngược về phía tây.","Là một trong những thác lớn và đẹp nhất Tây Nguyên.","Nằm trong cụm thác Dray Sáp - Gia Long - Dray Nur.","Thuộc Công viên địa chất toàn cầu Đắk Nông."]', '["Đến vào mùa mưa (tháng 7-10) để ngắm thác cuộn trào hùng vĩ nhất.","Mang giày chống trượt vì đường xuống chân thác khá trơn và ẩm."]', 'Tháng 7 đến tháng 11 thác nhiều nước nhất', 'Nửa ngày', '30.000đ', '07:00 - 17:00', '["popular","verified","hidden-gem"]', '["waterfall","nature","photography","mountain"]', '[{"seed":"draysap-thac","caption":"Thác Dray Sáp tung bọt trắng xóa","ratio":"16/9"},{"seed":"draysap-khoi","caption":"Màn sương khói quanh chân thác","ratio":"4/3"},{"seed":"draysap-rung","caption":"Rừng nguyên sinh bao quanh thác","ratio":"1/1"}]', '["dno-cong-vien-dia-chat"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vung-tau-bai-bien-tuong-chua', 'bai-bien-vung-tau-tuong-chua', 'ba-ria-vung-tau', 'Bãi biển Vũng Tàu & Tượng Chúa Kitô', 'Vung Tau Beach & Christ the King Statue', 'beach', 107.0843, 10.3349, 'Thành phố biển gần Sài Gòn với bãi tắm dài và tượng Chúa Kitô khổng lồ trên đỉnh Núi Nhỏ.', 'Vũng Tàu là thành phố biển thân quen của người Sài Gòn, chỉ cách trung tâm vài giờ xe. Bãi Sau trải dài cát vàng, sóng êm, đông vui mỗi cuối tuần; Bãi Trước lại lặng lẽ với hàng dừa nghiêng đón hoàng hôn. Trên đỉnh Núi Nhỏ, tượng Chúa Kitô cao 32 mét dang tay nhìn ra biển, du khách leo gần 800 bậc thang để lên tới chân tượng và phóng tầm mắt khắp thành phố. Hải sản tươi rói, gió biển mặn mòi và những con đường ven biển làm nên một Vũng Tàu hào sảng, phóng khoáng rất Nam Bộ.', '["Tượng Chúa Kitô Vũng Tàu cao 32 mét, hoàn thành năm 1994.","Bên trong tượng có cầu thang xoắn dẫn lên hai cánh tay dang rộng.","Bãi Sau (Thùy Vân) là bãi tắm chính, dài hơn 8 km.","Hải đăng Vũng Tàu xây từ năm 1862 là một trong những ngọn cổ nhất Việt Nam."]', '["Leo lên tượng Chúa vào sáng sớm để tránh nắng và đông người.","Thử bánh khọt Vũng Tàu, đặc sản trứ danh của thành phố."]', 'Tháng 11 đến tháng 4 (mùa khô, biển êm)', '1–2 ngày', '', 'Tượng Chúa: 07:00–17:00', '["popular","trending","verified"]', '["beach","city","nature","food","photography"]', '[{"seed":"vungtau-baisau","caption":"Bãi Sau cát vàng đông vui","ratio":"16/9"},{"seed":"vungtau-christ","caption":"Tượng Chúa Kitô trên Núi Nhỏ","ratio":"4/3"},{"seed":"vungtau-banhkhot","caption":"Bánh khọt giòn rụm đặc sản","ratio":"1/1"}]', '["con-dao"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('con-dao', 'con-dao', 'ba-ria-vung-tau', 'Côn Đảo', 'Con Dao Islands', 'island', 106.6062, 8.6831, 'Quần đảo hoang sơ giữa Biển Đông, nổi tiếng với bãi biển nguyên sơ, hệ sinh thái biển và di tích nhà tù lịch sử.', 'Côn Đảo là quần đảo gồm 16 hòn đảo lớn nhỏ nằm ngoài khơi Biển Đông, từng được mệnh danh là ''địa ngục trần gian'' với hệ thống nhà tù khắc nghiệt thời thực dân. Ngày nay, Côn Đảo hồi sinh thành điểm đến tâm linh và sinh thái bậc nhất: nghĩa trang Hàng Dương với mộ chị Võ Thị Sáu linh thiêng, những bãi biển nước trong vắt, rạn san hô và rùa biển lên đẻ trứng mỗi mùa. Vẻ đẹp tĩnh lặng, trầm mặc xen lẫn hoang sơ khiến Côn Đảo trở thành nơi vừa để chiêm nghiệm vừa để nghỉ dưỡng giữa thiên nhiên thuần khiết.', '["Vườn quốc gia Côn Đảo bảo tồn rùa biển và rạn san hô quý hiếm.","Nghĩa trang Hàng Dương là nơi an nghỉ của hàng nghìn tù nhân yêu nước.","Du khách thường viếng mộ chị Võ Thị Sáu vào lúc nửa đêm.","Côn Đảo từng được tạp chí du lịch quốc tế bình chọn là đảo bí ẩn nhất thế giới."]', '["Đặt vé máy bay hoặc tàu cao tốc sớm vì lượng khách giới hạn.","Mang theo đồ lễ giản dị nếu muốn viếng nghĩa trang Hàng Dương ban đêm."]', 'Tháng 3 đến tháng 9 (biển lặng, dễ ra đảo nhỏ)', '2–3 ngày', '', 'Cả ngày', '["hidden-gem","verified","ai-recommended"]', '["island","beach","nature","history","photography"]', '[{"seed":"condao-beach","caption":"Bãi biển nước trong nguyên sơ","ratio":"16/9"},{"seed":"condao-prison","caption":"Di tích nhà tù Côn Đảo","ratio":"4/3"},{"seed":"condao-hangduong","caption":"Nghĩa trang Hàng Dương linh thiêng","ratio":"1/1"}]', '["vung-tau-bai-bien-tuong-chua"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('cat-tien-national-park', 'vuon-quoc-gia-cat-tien', 'dong-nai', 'Vườn quốc gia Cát Tiên', 'Cat Tien National Park', 'park', 107.4286, 11.4231, 'Khu dự trữ sinh quyển rộng lớn với rừng nhiệt đới nguyên sinh, đa dạng động thực vật và khu cứu hộ gấu, voọc.', 'Vườn quốc gia Cát Tiên trải rộng trên ba tỉnh, là một trong những khu rừng nhiệt đới nguyên sinh quý giá nhất còn sót lại ở Nam Bộ. Đây là khu dự trữ sinh quyển được UNESCO công nhận, mái nhà của hàng trăm loài chim, thú quý như voi, bò tót, vượn đen má vàng. Du khách đạp xe xuyên rừng tới cây tung cổ thụ ngàn năm, chèo thuyền trên Bàu Sấu ngắm cá sấu hoang dã, hay ghé Trung tâm cứu hộ Linh trưởng và gấu. Đêm xuống, tour soi đèn tìm thú hoang mang lại cảm giác phiêu lưu giữa thiên nhiên hoang dã đậm chất rừng già.', '["Cát Tiên được UNESCO công nhận là khu dự trữ sinh quyển thế giới năm 2001.","Bàu Sấu là vùng đất ngập nước Ramsar quan trọng quốc tế.","Vườn là nơi cư trú của loài tê giác Java cuối cùng ở Việt Nam (đã tuyệt chủng năm 2010).","Cây tung cổ thụ trong rừng có bộ rễ bạnh khổng lồ nổi tiếng."]', '["Đặt tour soi thú đêm và chèo thuyền Bàu Sấu trước với ban quản lý vườn.","Mang giày leo núi, áo dài tay và thuốc chống vắt khi đi rừng sâu."]', 'Tháng 12 đến tháng 5 (mùa khô, dễ di chuyển trong rừng)', '1–2 ngày', '60.000đ', '07:00–17:00', '["unesco","verified","ai-recommended"]', '["park","nature","photography"]', '[{"seed":"cattien-forest","caption":"Rừng nguyên sinh xanh thẳm","ratio":"16/9"},{"seed":"cattien-bausau","caption":"Hoàng hôn vàng rực, thuyền nhỏ trôi trên mặt hồ","ratio":"4/3"},{"seed":"cattien-tung","caption":"Gà rừng kiếm ăn trên thảm lá khô","ratio":"1/1"}]', '["thac-giang-dien"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('thac-giang-dien', 'thac-giang-dien', 'dong-nai', 'Thác Giang Điền', 'Giang Dien Waterfall', 'waterfall', 107.0167, 10.9333, 'Khu du lịch sinh thái với thác nước trải rộng, vườn hoa và không gian xanh mát gần Biên Hòa.', 'Thác Giang Điền nằm giữa vùng quê Đồng Nai, là điểm đến quen thuộc cho những chuyến dã ngoại cuối tuần của người Sài Gòn và Biên Hòa. Dòng thác không quá hùng vĩ nhưng trải rộng, nước đổ qua các bậc đá tạo nên bức tranh êm dịu giữa rừng cây. Khu du lịch được quy hoạch thành những thảm cỏ xanh, vườn hoa rực rỡ, hồ nước và khu cắm trại lý tưởng cho gia đình. Vào mùa mưa, thác trở nên cuồn cuộn và đẹp nhất; mùa khô nước hiền hòa, thích hợp ngồi bên bờ nghe tiếng nước reo và tận hưởng không khí trong lành.', '["Thác Giang Điền cao khoảng 20 mét, trải rộng nhiều tầng đá.","Khu du lịch có dịch vụ cắm trại, picnic và teambuilding.","Mùa mưa (tháng 6–10) là lúc thác đẹp và nhiều nước nhất.","Nơi đây thường được chọn làm bối cảnh chụp ảnh cưới."]', '["Đi vào mùa mưa nếu muốn ngắm thác nhiều nước và hùng vĩ.","Mang theo đồ ăn để picnic trên các thảm cỏ trong khu du lịch."]', 'Tháng 6 đến tháng 10 (mùa mưa, thác nhiều nước)', 'Nửa ngày', '70.000đ', '07:00–17:30', '["popular","verified"]', '["waterfall","nature","photography"]', '[{"seed":"giangdien-thac","caption":"Thác nước trải rộng nhiều tầng","ratio":"16/9"},{"seed":"giangdien-vuonhoa","caption":"Vườn hoa rực rỡ trong khu","ratio":"4/3"},{"seed":"giangdien-camtrai","caption":"Bãi cỏ cắm trại xanh mát","ratio":"1/1"}]', '["cat-tien-national-park"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('chua-ba-thien-hau-binh-duong', 'chua-ba-thien-hau', 'binh-duong', 'Chùa Bà Thiên Hậu', 'Thien Hau Temple (Binh Duong)', 'temple', 106.6515, 10.9787, 'Ngôi miếu cổ thờ Bà Thiên Hậu, trung tâm lễ hội rước kiệu lớn nhất Bình Dương dịp rằm tháng Giêng.', 'Chùa Bà Thiên Hậu ở Thủ Dầu Một là ngôi miếu cổ do cộng đồng người Hoa lập nên để thờ Thiên Hậu Thánh Mẫu, vị thần bảo hộ cho người đi biển và cầu bình an. Kiến trúc đậm phong cách Hoa Nam với mái ngói âm dương, những hình rồng phượng tinh xảo và làn khói nhang nghi ngút quanh năm. Vào dịp rằm tháng Giêng, lễ rước kiệu Bà diễn ra tưng bừng, thu hút hàng vạn người từ khắp nơi đổ về, biến cả thành phố thành một biển người với cờ phướn, lân sư rồng rộn ràng. Đây là lễ hội văn hóa tâm linh lớn và đặc sắc bậc nhất miền Đông Nam Bộ.', '["Lễ rước kiệu Bà rằm tháng Giêng là lễ hội lớn nhất Bình Dương.","Miếu do bốn bang người Hoa ở Thủ Dầu Một cùng xây dựng.","Kiến trúc mang đậm phong cách đền miếu Hoa Nam truyền thống.","Người dân đến vay lộc đầu năm và trả lễ cuối năm tại miếu."]', '["Đến vào rằm tháng Giêng để xem lễ rước kiệu Bà hoành tráng.","Ăn mặc lịch sự, kín đáo khi vào dâng hương trong miếu."]', 'Rằm tháng Giêng âm lịch (mùa lễ hội)', '1–2 giờ', '', '05:00–18:00', '["festival","verified","popular"]', '["temple","culture","history","photography"]', '[{"seed":"thienhau-bd-mieu","caption":"Miếu cổ mái ngói âm dương","ratio":"4/3"},{"seed":"thienhau-bd-leruoc","caption":"Lễ rước kiệu Bà tưng bừng","ratio":"16/9"},{"seed":"thienhau-bd-nhang","caption":"Khói nhang nghi ngút trong miếu","ratio":"1/1"}]', '["dai-nam-binh-duong"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dai-nam-binh-duong', 'khu-du-lich-dai-nam', 'binh-duong', 'Khu du lịch Đại Nam', 'Dai Nam Tourist Park', 'park', 106.6219, 11.0331, 'Khu du lịch khổng lồ kết hợp đền thờ, vườn thú, biển nhân tạo và công viên giải trí bậc nhất miền Nam.', 'Khu du lịch Đại Nam (Lạc Cảnh Đại Nam Văn Hiến) là một trong những tổ hợp giải trí lớn nhất Việt Nam, trải rộng hàng trăm hecta giữa Bình Dương. Nơi đây quy tụ đủ mọi sắc thái: đền thờ Đại Nam Quốc Tự nguy nga dát vàng, dãy núi Ngũ Hành Sơn nhân tạo, vườn thú safari với cả nghìn loài, biển nhân tạo nhân tạo rộng nhất nước và khu trò chơi cảm giác mạnh. Một ngày ở Đại Nam có thể vừa chiêm bái tâm linh, vừa cho trẻ con vui chơi, vừa tắm biển nhân tạo, khiến đây thành điểm đến gia đình lý tưởng dịp cuối tuần và lễ tết.', '["Đại Nam là một trong những khu du lịch có diện tích lớn nhất Việt Nam.","Biển nhân tạo tại đây từng được ghi nhận là lớn nhất nước.","Đền Đại Nam Quốc Tự được dát vàng và xây bằng vật liệu quý.","Vườn thú safari nuôi nhiều loài quý hiếm trong môi trường bán hoang dã."]', '["Mua vé combo trọn gói để tiết kiệm khi chơi nhiều khu.","Đi sớm và mang đồ bơi nếu muốn trải nghiệm khu biển nhân tạo."]', 'Tháng 11 đến tháng 4 (mùa khô, trời mát)', '1 ngày', '150.000đ', '08:00–17:00', '["popular","trending"]', '["park","culture","city"]', '[{"seed":"dainam-den","caption":"Đền Đại Nam Quốc Tự dát vàng","ratio":"16/9"},{"seed":"dainam-bien","caption":"Biển nhân tạo rộng lớn","ratio":"4/3"},{"seed":"dainam-safari","caption":"Vườn thú safari bán hoang dã","ratio":"1/1"}]', '["chua-ba-thien-hau-binh-duong"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bu-gia-map-national-park', 'vuon-quoc-gia-bu-gia-map', 'binh-phuoc', 'Vườn quốc gia Bù Gia Mập', 'Bu Gia Map National Park', 'park', 107.1833, 12.1833, 'Khu rừng nguyên sinh giáp biên giới Campuchia, giàu đa dạng sinh học với thác nước, suối ngầm và văn hóa người S''tiêng.', 'Vườn quốc gia Bù Gia Mập nằm ở vùng cực bắc Bình Phước, giáp biên giới Campuchia, là vạt rừng nguyên sinh hiếm hoi còn giữ được vẻ hoang sơ của Đông Nam Bộ. Rừng ở đây xanh thẫm quanh năm, ẩn chứa nhiều loài thú quý, chim, bướm và cây gỗ cổ thụ. Du khách ưa khám phá có thể trekking xuyên rừng, lội suối, ngắm những thác nước và hang ngầm còn nguyên nét thiên nhiên. Vùng đệm là nơi cư trú của đồng bào S''tiêng và M''nông với văn hóa cồng chiêng, rượu cần độc đáo. Bù Gia Mập là điểm đến cho ai khao khát một chuyến đi thực sự gần gũi với rừng già.', '["Bù Gia Mập giáp biên giới Campuchia và tỉnh Đắk Nông.","Vườn bảo tồn nhiều loài linh trưởng và chim quý hiếm.","Vùng đệm là địa bàn sinh sống của người S''tiêng và M''nông.","Rừng còn giữ nhiều cây gỗ quý cổ thụ hàng trăm năm tuổi."]', '["Liên hệ ban quản lý vườn để có kiểm lâm dẫn đường trekking.","Chuẩn bị đồ chống vắt, nước uống và giày lội suối chắc chắn."]', 'Tháng 11 đến tháng 4 (mùa khô, an toàn khi đi rừng)', '1–2 ngày', '', '07:00–16:30', '["hidden-gem","verified","new"]', '["park","nature","culture","photography"]', '[{"seed":"bugiamap-rung","caption":"Rừng nguyên sinh xanh thẳm","ratio":"16/9"},{"seed":"bugiamap-suoi","caption":"Suối trong giữa rừng già","ratio":"4/3"},{"seed":"bugiamap-stieng","caption":"Văn hóa cồng chiêng S''tiêng","ratio":"1/1"}]', '["trang-co-bu-lach"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('trang-co-bu-lach', 'trang-co-bu-lach', 'binh-phuoc', 'Trảng cỏ Bù Lạch', 'Bu Lach Grasslands', 'village', 107.1167, 11.8833, 'Quần thể trảng cỏ rộng mênh mông giữa rừng, gắn với đời sống và truyền thuyết của đồng bào M''nông ở Bình Phước.', 'Trảng cỏ Bù Lạch là một quần thể gồm khoảng hai mươi trảng cỏ lớn nhỏ nằm xen giữa những cánh rừng ở huyện Bù Đăng, Bình Phước. Điều kỳ lạ là giữa rừng già lại trải ra những thảm cỏ xanh mượt phẳng lì như sân golf tự nhiên, ôm lấy hồ nước trong vắt soi bóng mây trời. Người M''nông bản địa lưu truyền nhiều truyền thuyết về sự hình thành huyền bí của các trảng cỏ này. Du khách đến đây để cắm trại, dã ngoại, ngắm hoàng hôn buông trên thảo nguyên thu nhỏ và trải nghiệm nét văn hóa mộc mạc của buôn làng M''nông quanh vùng.', '["Bù Lạch gồm khoảng 20 trảng cỏ lớn nhỏ nối nhau giữa rừng.","Giữa trảng cỏ có hồ nước tự nhiên trong vắt quanh năm.","Người M''nông gắn nhiều truyền thuyết với sự hình thành trảng cỏ.","Cỏ ở đây xanh mượt, phẳng lì như thảo nguyên tự nhiên."]', '["Mang lều và đồ ăn để cắm trại, ngắm hoàng hôn trên trảng cỏ.","Thuê người địa phương dẫn đường vì lối vào khá hoang sơ."]', 'Tháng 11 đến tháng 3 (cỏ xanh, trời mát)', 'Nửa ngày đến 1 ngày', '', 'Cả ngày', '["hidden-gem","new","ai-recommended"]', '["nature","culture","photography"]', '[{"seed":"bulach-trangco","caption":"Thảm cỏ xanh mượt giữa rừng","ratio":"16/9"},{"seed":"bulach-ho","caption":"Hồ nước trong soi bóng mây","ratio":"4/3"},{"seed":"bulach-hoanghon","caption":"Hoàng hôn buông trên trảng cỏ","ratio":"1/1"}]', '["bu-gia-map-national-park"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('nui-ba-den-tay-ninh', 'nui-ba-den', 'tay-ninh', 'Núi Bà Đen', 'Ba Den Mountain', 'mountain', 106.1719, 11.3833, 'Ngọn núi cao nhất Nam Bộ, ''nóc nhà'' miền Đông với hệ thống chùa linh thiêng, cáp treo hiện đại và biển mây huyền ảo.', 'Núi Bà Đen cao 986 mét, là đỉnh núi cao nhất Nam Bộ và được mệnh danh là ''nóc nhà'' của vùng đất này. Núi gắn với truyền thuyết về nàng Lý Thị Thiên Hương (Bà Đen) trinh tiết, linh thiêng, nên sườn núi là nơi quần tụ nhiều ngôi chùa cổ thu hút hành hương quanh năm. Ngày nay, hệ thống cáp treo hiện đại đưa du khách lên tận đỉnh, nơi đặt tượng Phật Bà Tây Bổ Đà Sơn bằng đồng cao nhất châu Á và quảng trường rộng lớn. Những sớm mai, biển mây trắng cuồn cuộn dưới chân khiến đỉnh Bà Đen như chốn bồng lai giữa miền Đông nắng gió.', '["Núi Bà Đen cao 986 mét, là đỉnh cao nhất Nam Bộ.","Tượng Phật Bà Tây Bổ Đà Sơn trên đỉnh là tượng Phật bằng đồng cao nhất châu Á.","Hệ thống cáp treo tại đây từng lập nhiều kỷ lục thế giới.","Hội xuân Núi Bà Đen diễn ra suốt tháng Giêng âm lịch."]', '["Lên đỉnh vào sáng sớm để có cơ hội ngắm biển mây tuyệt đẹp.","Mua vé cáp treo khứ hồi và mang áo khoác vì đỉnh núi se lạnh."]', 'Tháng 11 đến tháng 4 và mùa lễ hội tháng Giêng', 'Nửa ngày đến 1 ngày', '350.000đ (cáp treo)', '06:00–22:00', '["festival","trending","popular","verified"]', '["mountain","temple","culture","nature","photography"]', '[{"seed":"badennui-bienmay","caption":"Núi Bà Đen in bóng tím dưới hoàng hôn ven hồ","ratio":"16/9"},{"seed":"badennui-phatba","caption":"Tượng Phật Bà trên đỉnh núi","ratio":"4/3"},{"seed":"badennui-captreo","caption":"Tượng Phật Bà vươn lên giữa biển mây trắng","ratio":"1/1"}]', '["toa-thanh-cao-dai-tay-ninh"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('toa-thanh-cao-dai-tay-ninh', 'toa-thanh-cao-dai', 'tay-ninh', 'Tòa Thánh Cao Đài Tây Ninh', 'Cao Dai Holy See (Tay Ninh)', 'temple', 106.1281, 11.3036, 'Thánh địa trung tâm của đạo Cao Đài, công trình tôn giáo rực rỡ với kiến trúc giao thoa Đông – Tây độc nhất vô nhị.', 'Tòa Thánh Cao Đài Tây Ninh là trung tâm tôn giáo của đạo Cao Đài, một tôn giáo bản địa ra đời tại Việt Nam đầu thế kỷ 20. Công trình đồ sộ với hai tháp chuông cao vút, mái ngói uốn lượn, sắc màu rực rỡ và những hoa văn rồng, hoa sen, Thiên Nhãn phủ khắp nội thất. Đặc biệt, kiến trúc giao thoa độc đáo giữa đền chùa Á Đông và nhà thờ phương Tây, mang vẻ đẹp huyền ảo khó nơi nào sánh được. Mỗi ngày bốn buổi, các tín đồ áo dài trắng cùng làm lễ trang nghiêm trong tiếng nhạc lễ, tạo nên khung cảnh thiêng liêng thu hút đông đảo du khách tới chiêm ngưỡng.', '["Đạo Cao Đài là tôn giáo bản địa lớn của Việt Nam, lập năm 1926.","Tòa Thánh khởi công năm 1933 và hoàn thành sau nhiều năm xây dựng.","Biểu tượng Thiên Nhãn (con mắt) xuất hiện khắp công trình.","Lễ đại đàn diễn ra bốn lần mỗi ngày với nghi thức trang nghiêm."]', '["Đến dự lễ trưa (12:00) để xem nghi thức cúng đông tín đồ nhất.","Ăn mặc lịch sự, tháo giày và giữ trật tự khi vào bên trong điện."]', 'Quanh năm, đẹp nhất mùa khô tháng 11–4', '1–2 giờ', '', '06:00–18:00', '["verified","popular","ai-recommended"]', '["temple","culture","history","photography"]', '[{"seed":"caodai-toathanh","caption":"Tòa Thánh Cao Đài rực rỡ sắc màu","ratio":"16/9"},{"seed":"caodai-thiennhan","caption":"Biểu tượng Thiên Nhãn linh thiêng","ratio":"4/3"},{"seed":"caodai-lehoi","caption":"Tín đồ áo trắng làm lễ trang nghiêm","ratio":"1/1"}]', '["nui-ba-den-tay-ninh"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('long-an-lang-noi-tan-lap', 'lang-noi-tan-lap', 'long-an', 'Làng nổi Tân Lập', 'Tan Lap Floating Village', 'park', 105.8214, 10.7689, 'Rừng tràm xanh ngút ngàn của Đồng Tháp Mười, với con đường xuyên rừng và tháp ngắm cảnh trên vùng đất ngập nước.', 'Nằm giữa lòng Đồng Tháp Mười, Làng nổi Tân Lập là khu sinh thái rừng tràm rộng hơn 600 hecta. Du khách đi bộ trên con đường bê tông dài gần năm cây số luồn lách giữa hai hàng tràm xanh mát, ánh nắng len qua tán lá tạo nên khung cảnh huyền ảo. Một chuyến xuồng nhỏ len lỏi qua những rạch nước phủ kín bèo, tiếng chim ríu rít hòa cùng hương tràm thoang thoảng. Lên đỉnh tháp quan sát cao gần ba mươi mét, cả vùng đất ngập nước mênh mông hiện ra như một tấm thảm xanh trải dài tới chân trời. Đây là nơi lý tưởng để cảm nhận nhịp sống chậm rãi của miền Tây sông nước.', '["Khu rừng tràm rộng khoảng 635 hecta thuộc vùng Đồng Tháp Mười.","Con đường xuyên rừng dài gần 5 km được đổ bê tông giữa rừng tràm.","Tháp quan sát cao gần 30 mét cho tầm nhìn toàn cảnh vùng đất ngập nước.","Là điểm quay nhiều bộ phim và MV nhờ cảnh rừng tràm thơ mộng."]', '["Mang theo nón, áo chống nắng và thuốc chống côn trùng khi đi sâu vào rừng.","Đi sớm buổi sáng để có ánh sáng đẹp và tránh nắng gắt giữa trưa."]', 'Tháng 9 đến tháng 11, mùa nước nổi rừng tràm xanh tốt nhất', 'Nửa ngày', '60.000đ', '07:00 - 17:00 hằng ngày', '["popular","verified","hidden-gem"]', '["nature","park","photography"]', '[{"seed":"tanlap-tram-road","caption":"Con đường bê tông xuyên rừng tràm","ratio":"16/9"},{"seed":"tanlap-watchtower","caption":"Tháp quan sát giữa vùng đất ngập nước","ratio":"4/3"},{"seed":"tanlap-boat","caption":"Xuồng nhỏ len qua rạch nước phủ bèo","ratio":"1/1"}]', '["long-an-lang-sen"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('long-an-lang-sen', 'lang-sen', 'long-an', 'Khu bảo tồn đất ngập nước Láng Sen', 'Lang Sen Wetland Reserve', 'park', 105.7333, 10.7667, 'Vùng lõi Đồng Tháp Mười với hệ sinh thái đất ngập nước phong phú, nơi trú ngụ của nhiều loài chim nước quý hiếm.', 'Khu bảo tồn đất ngập nước Láng Sen được ví như một Đồng Tháp Mười thu nhỏ, lưu giữ gần như nguyên vẹn hệ sinh thái ngập nước đặc trưng của miền Tây. Trên diện tích hơn năm nghìn hecta, nơi đây là mái nhà của hàng trăm loài thực vật, cá nước ngọt và nhiều loài chim quý như cò, vạc, điên điển. Vào mùa nước nổi, những cánh đồng sen, súng và lúa ma trải dài bất tận, từng đàn chim bay rợp trời lúc chiều buông. Đi xuồng giữa kênh rạch yên ả, du khách có thể quan sát đời sống hoang dã nguyên sơ và lắng nghe thiên nhiên thở nhẹ giữa vùng đồng bưng.', '["Diện tích bảo tồn rộng hơn 5.000 hecta thuộc vùng lõi Đồng Tháp Mười.","Được công nhận là khu Ramsar - vùng đất ngập nước có tầm quan trọng quốc tế.","Là nơi trú ngụ của nhiều loài chim nước và cá nước ngọt quý hiếm.","Cảnh quan sen, súng và lúa ma đặc trưng cho hệ sinh thái đồng bưng."]', '["Liên hệ trước với ban quản lý để được bố trí xuồng và hướng dẫn.","Mang ống nhòm nếu muốn quan sát chim, đẹp nhất lúc bình minh và hoàng hôn."]', 'Tháng 8 đến tháng 11 mùa nước nổi, nhiều chim về trú ngụ', 'Nửa ngày', '', '07:00 - 17:00 hằng ngày', '["verified","hidden-gem","ai-recommended"]', '["nature","park","photography"]', '[{"seed":"langsen-birds","caption":"Lạch nước lặng lờ len giữa bụi cây ngập nước","ratio":"16/9"},{"seed":"langsen-lotus","caption":"Đồng cỏ ngập nước xanh trải tới chân trời","ratio":"4/3"},{"seed":"langsen-canal","caption":"Xuồng len giữa kênh rạch yên ả","ratio":"1/1"}]', '["long-an-lang-noi-tan-lap"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tien-giang-cu-lao-thoi-son', 'cu-lao-thoi-son', 'tien-giang', 'Cù lao Thới Sơn', 'Thoi Son Islet', 'village', 106.3636, 10.3389, 'Cù lao xanh mát giữa sông Tiền nổi tiếng với vườn cây trái, mật ong và những điệu đờn ca tài tử ngọt ngào.', 'Cù lao Thới Sơn, hay còn gọi là cồn Lân, là một trong tứ linh nổi giữa dòng sông Tiền hiền hòa. Đặt chân lên cù lao, du khách lạc vào miệt vườn sum suê nhãn, sầu riêng và bưởi da xanh. Người dân mời khách thưởng trà mật ong pha tắc, nếm trái cây hái tận vườn và nghe các nghệ nhân ngân nga đờn ca tài tử, di sản văn hóa của vùng Nam Bộ. Thú vị nhất là ngồi xuồng ba lá để các cô gái mặc áo bà ba chèo len lỏi qua những con rạch nhỏ rợp bóng dừa nước. Một ngày ở Thới Sơn gói trọn hồn quê miền Tây chân chất và mến khách.', '["Là một trong bốn cù lao mang tên tứ linh Long, Lân, Quy, Phụng trên sông Tiền.","Nổi tiếng với nghề nuôi ong lấy mật và các vườn cây ăn trái sum suê.","Đờn ca tài tử Nam Bộ thường được biểu diễn phục vụ du khách tại đây.","Trải nghiệm chèo xuồng ba lá qua rạch dừa nước là đặc trưng không thể bỏ qua."]', '["Đi tàu từ bến Mỹ Tho để ngắm cảnh sông Tiền trên đường ra cù lao.","Nên đi theo tour ghép để trải nghiệm trọn gói vườn trái cây và đờn ca tài tử."]', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', 'Nửa ngày', '150.000đ trọn gói tour', '08:00 - 17:00 hằng ngày', '["popular","verified","trending"]', '["village","culture","nature","food"]', '[{"seed":"thoison-sampan","caption":"Chèo xuồng ba lá qua rạch dừa nước","ratio":"16/9"},{"seed":"thoison-honey","caption":"Thưởng trà mật ong và trái cây miệt vườn","ratio":"4/3"},{"seed":"thoison-music","caption":"Nghệ nhân biểu diễn đờn ca tài tử","ratio":"1/1"}]', '["tien-giang-cho-noi-cai-be"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tien-giang-cho-noi-cai-be', 'cho-noi-cai-be', 'tien-giang', 'Chợ nổi Cái Bè', 'Cai Be Floating Market', 'market', 105.9486, 10.3556, 'Chợ nổi lâu đời trên sông Tiền, nơi ghe thuyền tấp nập buôn bán trái cây và đặc sản miền Tây từ tinh mơ.', 'Chợ nổi Cái Bè từng là một trong những chợ nổi sầm uất nhất đồng bằng sông Cửu Long, nằm ở ngã ba sông giáp ranh Tiền Giang, Vĩnh Long và Bến Tre. Từ lúc trời còn nhập nhoạng, hàng trăm ghe thuyền chở đầy trái cây, rau củ đã tụ về, mỗi ghe treo một cây bẹo cắm hàng hóa lủng lẳng để rao bán. Tiếng máy nổ, tiếng cười nói và mùi hủ tiếu nóng hổi từ ghe hàng rong tạo nên một bức tranh sông nước sống động. Du khách ngồi trên thuyền nhỏ luồn giữa chợ, mua trái cây tươi rói và cảm nhận nhịp giao thương đậm chất miền Tây vẫn còn được gìn giữ qua bao thế hệ.', '["Nằm ở ngã ba sông giáp ranh ba tỉnh Tiền Giang, Vĩnh Long và Bến Tre.","Các ghe dùng cây bẹo treo hàng hóa để giới thiệu mặt hàng đang bán.","Là một trong những chợ nổi hình thành sớm nhất ở miền Tây Nam Bộ.","Chuyên buôn bán sỉ trái cây, rau củ và đặc sản vùng đồng bằng."]', '["Đi từ 5h đến 7h sáng để thấy chợ nổi nhộn nhịp nhất.","Kết hợp tham quan lò kẹo dừa và làng nghề thủ công ven sông gần đó."]', 'Quanh năm, sáng sớm là thời điểm chợ đông nhất', '2-3 giờ', '', 'Họp chợ từ 04:00 - 08:00 hằng ngày', '["popular","verified"]', '["market","culture","food","photography"]', '[{"seed":"caibe-floating","caption":"Ghe thuyền tấp nập họp chợ trên sông","ratio":"16/9"},{"seed":"caibe-beo","caption":"Người chèo ghe nón lá qua sông dưới chân cầu","ratio":"4/3"},{"seed":"caibe-fruits","caption":"Trái cây tươi chất đầy ghe","ratio":"1/1"}]', '["tien-giang-cu-lao-thoi-son"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ben-tre-con-phung', 'con-phung-xu-dua', 'ben-tre', 'Cồn Phụng - xứ dừa', 'Con Phung - Coconut Land', 'village', 106.3756, 10.3303, 'Cù lao trên sông Tiền nổi tiếng với di tích đạo Dừa, làng nghề thủ công từ dừa và đặc sản kẹo dừa Bến Tre.', 'Cồn Phụng là một cù lao xanh mướt giữa sông Tiền, gắn liền với câu chuyện kỳ lạ về ông Đạo Dừa và những công trình kiến trúc độc đáo còn sót lại. Đến đây, du khách được dạo qua khu di tích với tháp Hòa bình chạm khắc rồng phượng cầu kỳ, rồi lạc vào không gian xứ dừa đặc sệt của Bến Tre. Khắp nơi là tiếng máy ép kẹo dừa thơm lừng, những bàn tay khéo léo đan giỏ, làm đồ mỹ nghệ từ thân và xơ dừa. Khách có thể nhâm nhi nước dừa mát lạnh, xem nuôi ong lấy mật và đi xuồng qua rạch dừa nước rợp bóng. Cồn Phụng là nơi cảm nhận trọn vẹn hồn cốt của quê hương xứ dừa.', '["Gắn với di tích đạo Dừa do ông Nguyễn Thành Nam lập nên từ giữa thế kỷ 20.","Tháp Hòa bình với hoa văn rồng phượng là công trình biểu tượng của cồn.","Bến Tre được mệnh danh là xứ dừa với hàng loạt làng nghề thủ công từ dừa.","Kẹo dừa Bến Tre là đặc sản nổi tiếng được sản xuất ngay tại các lò trên cồn."]', '["Mua kẹo dừa và đồ mỹ nghệ làm quà ngay tại các lò sản xuất trên cồn.","Kết hợp đi tour 4 cù lao Long Lân Quy Phụng để khám phá trọn vùng sông Tiền."]', 'Tháng 11 đến tháng 4, mùa khô mát mẻ thuận tiện đi lại', 'Nửa ngày', '20.000đ tham quan di tích', '07:30 - 17:00 hằng ngày', '["popular","verified","trending"]', '["village","culture","history","food"]', '[{"seed":"conphung-tower","caption":"Tháp Hòa bình của di tích đạo Dừa","ratio":"16/9"},{"seed":"conphung-candy","caption":"Lò làm kẹo dừa thơm lừng","ratio":"4/3"},{"seed":"conphung-handicraft","caption":"Đồ thủ công mỹ nghệ từ dừa","ratio":"1/1"}]', '["tien-giang-cu-lao-thoi-son"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tra-vinh-ao-ba-om', 'ao-ba-om', 'tra-vinh', 'Ao Bà Om', 'Ba Om Pond', 'lake', 106.3186, 9.9183, 'Hồ nước cổ linh thiêng của người Khmer, bao quanh bởi rừng cây cổ thụ với bộ rễ trồi lên kỳ vĩ.', 'Ao Bà Om là thắng cảnh nổi tiếng nhất của Trà Vinh, gắn liền với truyền thuyết về cuộc thi đào ao giữa phe nam và phe nữ để phân định việc cưới hỏi. Hồ nước hình chữ nhật rộng lớn quanh năm trong xanh, soi bóng những hàng sao, dầu cổ thụ hàng trăm năm tuổi. Điều kỳ lạ khiến du khách trầm trồ là bộ rễ khổng lồ của các cây cổ thụ trồi hẳn lên khỏi mặt đất, uốn lượn tạo nên những hình thù độc đáo như tác phẩm điêu khắc của thiên nhiên. Bên cạnh ao là ngôi chùa Khmer cổ kính và bảo tàng văn hóa dân tộc, nơi lưu giữ hồn cốt của cộng đồng Khmer Nam Bộ giữa lòng Trà Vinh thanh bình.', '["Hồ nước cổ gắn với truyền thuyết cuộc thi đào ao giữa phe nam và phe nữ.","Bao quanh là rừng cây sao, dầu cổ thụ hàng trăm năm tuổi.","Bộ rễ cây trồi lên mặt đất tạo hình thù độc đáo là điểm nhấn nổi tiếng.","Gắn liền với văn hóa Khmer Nam Bộ và chùa Âng cổ kính bên cạnh."]', '["Ghé chùa Âng và bảo tàng văn hóa Khmer ngay cạnh ao để hiểu thêm văn hóa địa phương.","Đến vào dịp lễ Ok Om Bok để hòa mình vào không khí lễ hội của người Khmer."]', 'Tháng 11 đến tháng 1, dịp lễ Ok Om Bok của người Khmer', '1-2 giờ', '', 'Cả ngày', '["verified","hidden-gem","festival"]', '["lake","culture","nature","photography"]', '[{"seed":"baom-roots","caption":"Bộ rễ cây cổ thụ trồi lên kỳ vĩ","ratio":"16/9"},{"seed":"baom-pond","caption":"Hồ nước trong xanh soi bóng cây","ratio":"4/3"},{"seed":"baom-khmer","caption":"Chùa Khmer cổ kính bên ao","ratio":"1/1"}]', '["tra-vinh-chua-vam-ray"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('tra-vinh-chua-vam-ray', 'chua-vam-ray', 'tra-vinh', 'Chùa Vàm Ray', 'Vam Ray Pagoda', 'temple', 106.2461, 9.7547, 'Ngôi chùa Khmer dát vàng lộng lẫy, được xem là một trong những chùa Khmer lớn và đẹp bậc nhất Việt Nam.', 'Chùa Vàm Ray tọa lạc tại huyện Trà Cú, là ngôi chùa Khmer mang vẻ đẹp tráng lệ hiếm có ở miền Tây. Toàn bộ ngôi chùa được sơn son thếp vàng rực rỡ, lấp lánh dưới ánh nắng với kiến trúc Angkor đặc trưng, mái nhọn nhiều tầng và những phù điêu chạm khắc tinh xảo. Bên trong chính điện là tượng Phật nằm dài hơn năm mươi mét uy nghi, một trong những tượng Phật nằm lớn nhất Việt Nam. Khắp khuôn viên là tượng tiên nữ Kẽn nair, thần rắn Naga và những hoa văn dát vàng cầu kỳ. Đến đây, du khách không chỉ chiêm bái mà còn được chiêm ngưỡng đỉnh cao nghệ thuật kiến trúc và điêu khắc của văn hóa Phật giáo Nam tông Khmer.', '["Mang kiến trúc Angkor đặc trưng với mái nhọn nhiều tầng dát vàng rực rỡ.","Tượng Phật nằm trong chùa dài hơn 50 mét, thuộc loại lớn nhất Việt Nam.","Khuôn viên trang trí tượng tiên nữ Kẽn nair và thần rắn Naga tinh xảo.","Là chùa Phật giáo Nam tông Khmer tiêu biểu của tỉnh Trà Vinh."]', '["Ăn mặc kín đáo, lịch sự khi vào tham quan và chiêm bái trong chính điện.","Đến vào buổi sáng để ánh nắng làm nổi bật vẻ lộng lẫy dát vàng của chùa."]', 'Quanh năm, đẹp nhất vào mùa khô tháng 11 đến tháng 4', '1-2 giờ', '', '06:00 - 18:00 hằng ngày', '["verified","hidden-gem"]', '["temple","culture","history","photography"]', '[{"seed":"vamray-golden","caption":"Kiến trúc Angkor dát vàng rực rỡ","ratio":"16/9"},{"seed":"vamray-buddha","caption":"Tượng Phật nằm uy nghi trong chính điện","ratio":"4/3"},{"seed":"vamray-naga","caption":"Phù điêu thần rắn Naga tinh xảo","ratio":"1/1"}]', '["tra-vinh-ao-ba-om"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vinh-long-cu-lao-an-binh', 'cu-lao-an-binh', 'vinh-long', 'Cù lao An Bình', 'An Binh Islet', 'village', 106, 10.2667, 'Cù lao trù phú giữa sông Tiền và sông Cổ Chiên, thiên đường miệt vườn với homestay sinh thái và trái cây bốn mùa.', 'Cù lao An Bình nằm giữa hai dòng sông Tiền và Cổ Chiên, là vùng đất phù sa màu mỡ với những vườn cây trái sai trĩu quanh năm. Đây là điểm đến lý tưởng cho ai muốn trải nghiệm cuộc sống miệt vườn đích thực: ngủ homestay nhà sàn ven sông, đạp xe qua những con đường làng rợp bóng cây, hái chôm chôm, nhãn, bòn bon ngay trong vườn. Buổi tối, khách quây quần thưởng thức cá tai tượng chiên xù, cá lóc nướng trui và nghe đờn ca tài tử bên ánh đèn dầu. Sáng sớm, một chuyến xuồng len qua rạch nhỏ đưa du khách ra chợ nổi Trà Ôn gần đó. An Bình là nơi nhịp sống miền Tây chậm rãi và đong đầy tình người.', '["Nằm giữa sông Tiền và sông Cổ Chiên, đối diện thành phố Vĩnh Long.","Nổi tiếng với mô hình du lịch homestay miệt vườn đầu tiên ở miền Tây.","Vườn trái cây cho thu hoạch chôm chôm, nhãn, bòn bon quanh năm.","Là điểm trải nghiệm đờn ca tài tử và ẩm thực sông nước đặc trưng."]', '["Đặt homestay trước để có trải nghiệm ngủ lại nhà vườn ven sông trọn vẹn.","Thuê xe đạp dạo quanh cù lao và hái trái cây tại vườn vào buổi sáng."]', 'Tháng 5 đến tháng 8, mùa trái cây chín rộ', '1-2 ngày', '', 'Cả ngày', '["popular","verified","trending"]', '["village","nature","food","culture"]', '[{"seed":"anbinh-orchard","caption":"Vườn trái cây sai trĩu quả","ratio":"16/9"},{"seed":"anbinh-homestay","caption":"Homestay nhà sàn ven sông","ratio":"4/3"},{"seed":"anbinh-bike","caption":"Đạp xe qua con đường làng rợp bóng cây","ratio":"1/1"}]', '["vinh-long-lo-gach-mang-thit"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('vinh-long-lo-gach-mang-thit', 'lo-gach-mang-thit', 'vinh-long', 'Lò gạch Mang Thít', 'Mang Thit Brick Kilns', 'village', 106.0639, 10.1414, 'Vương quốc lò gạch gốm trăm năm tuổi ven sông Cổ Chiên, với những tháp lò màu gạch đỏ cam đẹp như cổ tích.', 'Làng nghề gạch gốm Mang Thít được mệnh danh là vương quốc lò gạch của miền Tây, hình thành cách đây hơn một thế kỷ ven dòng sông Cổ Chiên. Hàng nghìn lò nung hình tròn cao vút bằng gạch đỏ cam nằm san sát nhau, soi bóng xuống mặt nước, tạo nên một khung cảnh vừa hoài niệm vừa siêu thực. Những lò gạch hình củ tỏi cũ kỹ rêu phong này từng đỏ lửa ngày đêm, làm ra loại gạch và gốm đỏ nức tiếng khắp Nam Bộ. Ngày nay, dù nhiều lò đã ngưng hoạt động, khung cảnh kỳ vĩ ấy lại trở thành điểm check-in được giới trẻ săn đón, đồng thời được tỉnh quy hoạch thành di sản đương đại để gìn giữ hồn nghề cho mai sau.', '["Làng nghề gạch gốm hình thành hơn 100 năm bên sông Cổ Chiên.","Từng có hàng nghìn lò nung hình tròn nằm san sát thành vương quốc lò gạch.","Gạch và gốm đỏ Mang Thít nổi tiếng khắp vùng Nam Bộ một thời.","Đang được quy hoạch thành di sản đương đại gắn với phát triển du lịch."]', '["Đi xuồng dọc sông Cổ Chiên để ngắm toàn cảnh những hàng lò gạch ven nước.","Đến lúc hoàng hôn khi ánh nắng nhuộm vàng cam các tháp lò để chụp ảnh đẹp nhất."]', 'Tháng 11 đến tháng 4, mùa khô thuận tiện tham quan', '2-3 giờ', '', 'Cả ngày', '["hidden-gem","trending","verified"]', '["village","culture","history","photography"]', '[{"seed":"mangthit-kilns","caption":"Hàng lò gạch đỏ cam ven sông","ratio":"16/9"},{"seed":"mangthit-sunset","caption":"Tháp lò nhuộm vàng lúc hoàng hôn","ratio":"4/3"},{"seed":"mangthit-old","caption":"Lò nung cũ kỹ rêu phong","ratio":"1/1"}]', '["vinh-long-cu-lao-an-binh"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dong-thap-tram-chim', 'vuon-quoc-gia-tram-chim', 'dong-thap', 'Vườn quốc gia Tràm Chim', 'Tram Chim National Park', 'park', 105.5, 10.7167, 'Khu Ramsar tái hiện thu nhỏ Đồng Tháp Mười, thiên đường của sếu đầu đỏ và hàng trăm loài chim nước quý.', 'Vườn quốc gia Tràm Chim là vùng đất ngập nước nổi tiếng nhất Đồng Tháp, được công nhận là khu Ramsar quan trọng của thế giới. Trên diện tích hơn bảy nghìn hecta, nơi đây tái hiện sinh động hệ sinh thái Đồng Tháp Mười nguyên thủy với rừng tràm, đồng cỏ năng, lúa ma và sen súng bạt ngàn. Tràm Chim là ngôi nhà của hơn hai trăm loài chim, trong đó quý giá nhất là sếu đầu đỏ, loài chim trong sách đỏ thường về đây tìm ăn vào mùa khô. Ngồi tắc ráng lướt trên kênh nước, du khách được ngắm những đàn cò, vạc, điên điển bay rợp trời và đắm mình giữa thiên nhiên hoang dã thuần khiết của miền Tây sông nước.', '["Diện tích hơn 7.300 hecta, được công nhận là khu Ramsar thứ tư của Việt Nam.","Là nơi trú ngụ của hơn 200 loài chim, nổi bật là sếu đầu đỏ quý hiếm.","Tái hiện hệ sinh thái Đồng Tháp Mười nguyên thủy với rừng tràm và đồng năng.","Mùa nước nổi và mùa sen nở là hai mùa cảnh quan đẹp nhất trong năm."]', '["Đi tắc ráng vào sáng sớm để ngắm chim và tránh nắng gắt buổi trưa.","Mùa sếu về thường từ tháng 12 đến tháng 4, cần liên hệ trước để quan sát."]', 'Tháng 12 đến tháng 4 mùa sếu về, hoặc tháng 9-11 mùa nước nổi', 'Nửa ngày', '10.000đ vé vào, thuê tắc ráng riêng', '07:00 - 17:00 hằng ngày', '["unesco","verified","popular","ai-recommended"]', '["nature","park","photography"]', '[{"seed":"tramchim-crane","caption":"Sếu đầu đỏ về tìm ăn mùa khô","ratio":"16/9"},{"seed":"tramchim-lotus","caption":"Cánh đồng sen súng bạt ngàn","ratio":"4/3"},{"seed":"tramchim-boat","caption":"Tháp canh gỗ giữa đầm sen ngày mưa","ratio":"1/1"}]', '["dong-thap-lang-hoa-sa-dec"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('dong-thap-lang-hoa-sa-dec', 'lang-hoa-sa-dec', 'dong-thap', 'Làng hoa Sa Đéc', 'Sa Dec Flower Village', 'village', 105.7556, 10.3, 'Làng hoa trăm năm tuổi rực rỡ sắc màu, một trong những vựa hoa kiểng lớn nhất miền Tây Nam Bộ.', 'Làng hoa Sa Đéc, hay làng hoa Tân Quy Đông, là một trong những vựa hoa kiểng lâu đời và lớn nhất đồng bằng sông Cửu Long, đã có hơn một trăm năm tuổi. Trải dài bên dòng sông Sa Giang, hàng trăm hecta vườn hoa khoe sắc quanh năm với cúc mâm xôi, hồng, vạn thọ, cát tường và vô số loại kiểng quý. Điều độc đáo là người dân trồng hoa trên những giàn cao để tránh ngập nước, tạo nên khung cảnh hoa nở lơ lửng trên mặt nước rất riêng. Vào dịp giáp Tết, cả làng rộn ràng nhộn nhịp, ghe thuyền chở hoa tỏa đi khắp miền Nam. Dạo bước giữa biển hoa muôn màu, du khách như lạc vào một khu vườn cổ tích rực rỡ và đầy hương sắc.', '["Làng nghề trồng hoa kiểng có lịch sử hơn 100 năm bên sông Sa Giang.","Là một trong những vựa hoa lớn nhất miền Tây, cung cấp hoa cho cả miền Nam.","Người dân trồng hoa trên giàn cao để tránh ngập nước, tạo cảnh quan độc đáo.","Sa Đéc còn gắn với bối cảnh tiểu thuyết Người Tình của Marguerite Duras."]', '["Đến vào dịp giáp Tết để thấy làng hoa rực rỡ và nhộn nhịp nhất.","Ghé nhà cổ Huỳnh Thủy Lê gần đó để tìm hiểu câu chuyện Người Tình nổi tiếng."]', 'Tháng 12 đến tháng 1, dịp giáp Tết hoa nở rộ', '2-3 giờ', '', 'Cả ngày', '["popular","verified","festival"]', '["village","nature","culture","photography"]', '[{"seed":"sadec-flowers","caption":"Biển hoa muôn màu rực rỡ","ratio":"16/9"},{"seed":"sadec-racks","caption":"Hoa trồng trên giàn cao tránh ngập","ratio":"4/3"},{"seed":"sadec-boat","caption":"Ghe thuyền chở hoa trên sông","ratio":"1/1"}]', '["dong-thap-tram-chim"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hau-giang-cho-noi-nga-bay', 'cho-noi-nga-bay', 'hau-giang', 'Chợ nổi Ngã Bảy', 'Nga Bay Floating Market', 'market', 105.8175, 9.8156, 'Chợ nổi huyền thoại nơi bảy nhánh sông gặp nhau, từng là chợ nổi sầm uất và nổi tiếng bậc nhất miền Tây.', 'Chợ nổi Ngã Bảy, còn gọi là chợ nổi Phụng Hiệp, là một biểu tượng văn hóa sông nước của Hậu Giang, hình thành từ đầu thế kỷ hai mươi tại nơi bảy con sông tụ về một điểm. Đây từng là chợ nổi lớn và sầm uất nhất miền Tây, đi vào câu hát Tình anh bán chiếu nổi tiếng của soạn giả Viễn Châu. Sáng sớm, hàng trăm ghe thuyền chở đầy nông sản, trái cây, đồ gia dụng tấp nập mua bán, mỗi ghe treo cây bẹo rao hàng đặc trưng. Du khách ngồi thuyền len giữa chợ, thưởng thức tô bún riêu nóng hổi ngay trên sông và cảm nhận nhịp sống thương hồ phóng khoáng, nghĩa tình của người dân miền Tây sông nước.', '["Hình thành đầu thế kỷ 20 tại nơi bảy nhánh sông gặp nhau ở Phụng Hiệp.","Từng là chợ nổi lớn và sầm uất bậc nhất đồng bằng sông Cửu Long.","Đi vào bài vọng cổ Tình anh bán chiếu nổi tiếng của soạn giả Viễn Châu.","Các ghe dùng cây bẹo treo hàng hóa làm dấu hiệu rao bán trên sông."]', '["Đi từ 5h đến 7h sáng để bắt trọn không khí chợ nổi đông đúc nhất.","Thử ăn sáng ngay trên thuyền với bún riêu, hủ tiếu để trải nghiệm trọn vẹn."]', 'Quanh năm, sáng sớm là lúc chợ nhộn nhịp nhất', '2-3 giờ', '', 'Họp chợ từ 05:00 - 08:00 hằng ngày', '["popular","verified","festival"]', '["market","culture","food","photography"]', '[{"seed":"ngabay-market","caption":"Ghe thuyền tấp nập nơi bảy sông gặp nhau","ratio":"16/9"},{"seed":"ngabay-beo","caption":"Cây bẹo treo hàng hóa rao bán","ratio":"4/3"},{"seed":"ngabay-noodle","caption":"Ăn sáng bún riêu ngay trên thuyền","ratio":"1/1"}]', '["hau-giang-lung-ngoc-hoang"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('hau-giang-lung-ngoc-hoang', 'lung-ngoc-hoang', 'hau-giang', 'Khu bảo tồn Lung Ngọc Hoàng', 'Lung Ngoc Hoang Nature Reserve', 'park', 105.6539, 9.7197, 'Lá phổi xanh của Hậu Giang với hệ sinh thái đất ngập nước nguyên sinh, được ví như Đồng Tháp Mười thu nhỏ.', 'Khu bảo tồn thiên nhiên Lung Ngọc Hoàng được mệnh danh là lá phổi xanh của vùng Tây sông Hậu, lưu giữ một trong những mảng đất ngập nước nguyên sinh hiếm hoi còn sót lại ở đồng bằng. Trải rộng trên hơn hai nghìn tám trăm hecta, nơi đây là vùng trũng tự nhiên với rừng tràm, đồng năng, lung bàu chằng chịt và thảm thực vật phong phú. Lung Ngọc Hoàng là mái nhà của hàng trăm loài động thực vật, trong đó có nhiều loài chim, cá và bò sát quý hiếm. Đi xuồng len lỏi giữa rừng tràm tĩnh lặng, du khách được hòa mình vào thiên nhiên hoang sơ, lắng nghe tiếng chim gọi bầy và cảm nhận sự trong lành nguyên thủy của vùng đồng bưng Nam Bộ.', '["Diện tích hơn 2.800 hecta, là khu bảo tồn thiên nhiên trọng điểm của Hậu Giang.","Được ví như Đồng Tháp Mười thu nhỏ với hệ sinh thái đất ngập nước nguyên sinh.","Là nơi trú ngụ của hàng trăm loài động thực vật, nhiều loài quý hiếm.","Lung là tên gọi địa phương chỉ những vùng trũng ngập nước tự nhiên."]', '["Liên hệ ban quản lý trước để được sắp xếp xuồng và hướng dẫn tham quan.","Mang giày chống trơn và đồ chống muỗi khi đi sâu vào rừng tràm."]', 'Tháng 8 đến tháng 11, mùa nước nổi cảnh quan đẹp nhất', 'Nửa ngày', '', '07:00 - 17:00 hằng ngày', '["verified","hidden-gem","ai-recommended"]', '["nature","park","photography"]', '[{"seed":"lungngochoang-tram","caption":"Rừng tràm nguyên sinh tĩnh lặng","ratio":"16/9"},{"seed":"lungngochoang-canal","caption":"Xuồng len giữa lung bàu chằng chịt","ratio":"4/3"},{"seed":"lungngochoang-birds","caption":"Cầu tre len giữa rừng tràm dưới trời xanh","ratio":"1/1"}]', '["hau-giang-cho-noi-nga-bay"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('soc-trang-chua-doi', 'chua-doi', 'soc-trang', 'Chùa Dơi', 'Bat Pagoda', 'temple', 105.9869, 9.5908, 'Ngôi chùa Khmer cổ kính nổi tiếng với hàng nghìn con dơi quạ treo mình trên những tán cây cổ thụ.', 'Chùa Dơi, tên Khmer là Mahatup, là một trong những ngôi chùa Khmer cổ và linh thiêng nhất Sóc Trăng, có lịch sử hơn bốn trăm năm. Chùa mang kiến trúc Phật giáo Nam tông đặc trưng với mái cong nhiều tầng, cột chạm tiên nữ và những hoa văn rực rỡ. Điều khiến nơi đây nổi tiếng khắp cả nước là hàng nghìn con dơi quạ khổng lồ treo mình lủng lẳng trên các tán sao, dầu cổ thụ trong khuôn viên chùa. Mỗi chiều, đàn dơi đồng loạt thức giấc, bay rợp trời đi kiếm ăn tạo nên cảnh tượng kỳ thú. Người dân tin rằng đàn dơi là điềm lành, được nhà chùa che chở qua bao thế kỷ. Chùa Dơi là điểm đến giao hòa giữa tâm linh, văn hóa Khmer và thiên nhiên kỳ diệu.', '["Tên Khmer là chùa Mahatup, có lịch sử hơn 400 năm tại Sóc Trăng.","Hàng nghìn con dơi quạ khổng lồ treo mình trên cây cổ thụ trong khuôn viên.","Mang kiến trúc Phật giáo Nam tông Khmer với mái cong nhiều tầng đặc trưng.","Người dân xem đàn dơi là điềm lành và được nhà chùa bảo vệ qua nhiều thế kỷ."]', '["Đến lúc chiều tà để xem đàn dơi đồng loạt bay đi kiếm ăn rợp trời.","Ăn mặc lịch sự và giữ yên tĩnh khi tham quan khuôn viên chùa."]', 'Quanh năm, dịp lễ Khmer và buổi chiều là thời điểm đẹp nhất', '1-2 giờ', '5.000đ', '07:00 - 18:00 hằng ngày', '["popular","verified","trending"]', '["temple","culture","history","nature"]', '[{"seed":"chuadoi-bats","caption":"Đàn dơi quạ treo mình trên cây cổ thụ","ratio":"16/9"},{"seed":"chuadoi-temple","caption":"Kiến trúc Khmer mái cong nhiều tầng","ratio":"4/3"},{"seed":"chuadoi-flight","caption":"Dơi bay rợp trời lúc chiều tà","ratio":"1/1"}]', '["soc-trang-chua-dat-set"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('soc-trang-chua-dat-set', 'chua-dat-set', 'soc-trang', 'Chùa Đất Sét', 'Clay Pagoda', 'temple', 105.9764, 9.6022, 'Ngôi chùa độc đáo với hàng nghìn tượng nặn từ đất sét và những cây nến khổng lồ cháy suốt hàng chục năm.', 'Chùa Đất Sét, tên chính thức là Bửu Sơn Tự, là ngôi chùa có một không hai ở Sóc Trăng và cả Việt Nam. Suốt mấy chục năm ròng, một người trong dòng họ cai quản chùa đã miệt mài nặn nên hàng nghìn pho tượng Phật, linh thú, tháp và đồ thờ hoàn toàn bằng đất sét pha bột nhang, tô màu tỉ mỉ. Nổi bật là tháp Đa Bảo và bảo tòa Liên Hoa đồ sộ với hàng nghìn cánh sen đất sét. Chùa còn lưu giữ những cây nến khổng lồ nặng hàng trăm ký, có cây thắp liên tục đã mấy chục năm vẫn chưa cháy hết, cùng những cây hương cao vút. Mỗi chi tiết đều là kết tinh của lòng thành kính và sự kiên nhẫn phi thường, khiến du khách không khỏi thán phục khi ghé thăm.', '["Tên chính thức là Bửu Sơn Tự, nổi tiếng với tượng nặn hoàn toàn từ đất sét.","Có hàng nghìn pho tượng Phật, linh thú và tháp được nặn thủ công tỉ mỉ.","Lưu giữ những cây nến khổng lồ nặng hàng trăm ký, cháy liên tục hàng chục năm.","Tháp Đa Bảo và bảo tòa Liên Hoa là hai công trình đất sét tiêu biểu của chùa."]', '["Quan sát kỹ các cây nến và cây hương khổng lồ, điểm độc đáo nhất của chùa.","Kết hợp tham quan cùng Chùa Dơi gần đó trong một buổi khám phá Sóc Trăng."]', 'Quanh năm, mát mẻ nhất vào mùa khô tháng 11 đến tháng 4', '1 giờ', '', '07:00 - 18:00 hằng ngày', '["verified","hidden-gem"]', '["temple","culture","history"]', '[{"seed":"datset-statues","caption":"Tượng Phật nặn từ đất sét tỉ mỉ","ratio":"16/9"},{"seed":"datset-candles","caption":"Cây nến khổng lồ cháy hàng chục năm","ratio":"4/3"},{"seed":"datset-tower","caption":"Bảo tòa Liên Hoa bằng đất sét","ratio":"1/1"}]', '["soc-trang-chua-doi"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bac-lieu-canh-dong-dien-gio', 'canh-dong-dien-gio', 'bac-lieu', 'Cánh đồng điện gió Bạc Liêu', 'Bac Lieu Wind Farm', 'park', 105.7842, 9.1986, 'Cánh đồng quạt gió khổng lồ vươn ra biển, biểu tượng năng lượng xanh và điểm check-in mê hoặc của Bạc Liêu.', 'Cánh đồng điện gió Bạc Liêu là một trong những nhà máy điện gió ven biển đầu tiên và lớn nhất Việt Nam, nằm trên vùng bãi bồi ven biển huyện Hòa Bình. Hàng chục tua bin gió khổng lồ cao hơn tám mươi mét sừng sững vươn lên giữa mênh mông trời nước, những cánh quạt trắng quay đều trong gió biển tạo nên khung cảnh vừa hùng vĩ vừa nên thơ. Du khách đi trên con đường dẫn ra giữa cánh đồng quạt gió, phóng tầm mắt ra biển và đắm mình trong làn gió mặn mòi. Đây không chỉ là biểu tượng cho khát vọng phát triển năng lượng sạch của miền Tây, mà còn trở thành điểm check-in cực kỳ ấn tượng, nhất là khi hoàng hôn buông xuống nhuộm đỏ cả chân trời.', '["Là một trong những nhà máy điện gió ven biển đầu tiên và lớn của Việt Nam.","Hàng chục tua bin gió cao hơn 80 mét đặt trên vùng bãi bồi ven biển.","Biểu tượng cho phát triển năng lượng sạch của tỉnh Bạc Liêu.","Trở thành điểm check-in nổi tiếng, đẹp nhất vào lúc hoàng hôn."]', '["Đến vào cuối chiều để ngắm hoàng hôn tuyệt đẹp giữa cánh đồng quạt gió.","Mang theo áo khoác mỏng vì gió biển khá mạnh, nhất là buổi chiều tối."]', 'Tháng 11 đến tháng 4, mùa khô trời trong gió đẹp', '1-2 giờ', '60.000đ tham quan', '07:00 - 18:00 hằng ngày', '["trending","verified","popular"]', '["nature","photography","city"]', '[{"seed":"baclieu-turbines","caption":"Tua bin gió vươn ra biển","ratio":"16/9"},{"seed":"baclieu-path","caption":"Con đường dẫn ra giữa cánh đồng quạt gió","ratio":"4/3"},{"seed":"baclieu-sunset","caption":"Hàng tuabin điện gió mọc sau rặng cây xanh","ratio":"1/1"}]', '["bac-lieu-nha-cong-tu"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('bac-lieu-nha-cong-tu', 'nha-cong-tu-bac-lieu', 'bac-lieu', 'Nhà Công tử Bạc Liêu', 'House of Bac Lieu''s Prince', 'museum', 105.7244, 9.2853, 'Dinh thự cổ bề thế của Công tử Bạc Liêu, lưu giữ giai thoại ăn chơi lừng lẫy một thời của giới điền chủ Nam Bộ.', 'Nhà Công tử Bạc Liêu là một dinh thự cổ tráng lệ tọa lạc bên dòng sông Bạc Liêu, gắn liền với giai thoại nổi tiếng về Trần Trinh Huy, vị công tử ăn chơi khét tiếng nhất Nam Bộ đầu thế kỷ hai mươi. Ngôi nhà được xây dựng theo lối kiến trúc phương Tây sang trọng với vật liệu nhập từ Pháp, nội thất gỗ quý chạm trổ tinh xảo, đèn chùm pha lê lộng lẫy. Bên trong còn lưu giữ nhiều kỷ vật quý như bộ bàn ghế cẩn xà cừ, chiếc giường nóng lạnh và những món đồ cổ giá trị. Câu chuyện về vị công tử đốt tiền nấu trứng, lái máy bay riêng đi thăm ruộng đã trở thành huyền thoại. Tham quan nơi đây, du khách như ngược dòng thời gian về thời vàng son của tầng lớp đại điền chủ miền Tây.', '["Gắn với giai thoại về Trần Trinh Huy, công tử ăn chơi nổi tiếng nhất Nam Bộ.","Dinh thự xây theo kiến trúc phương Tây với vật liệu nhập khẩu từ Pháp.","Lưu giữ nhiều cổ vật quý như bàn ghế cẩn xà cừ, đèn chùm pha lê.","Giai thoại đốt tiền nấu trứng và sở hữu máy bay riêng đã thành huyền thoại."]', '["Thuê hướng dẫn viên tại chỗ để nghe trọn vẹn các giai thoại thú vị về công tử.","Có thể nghỉ lại khách sạn trong khuôn viên để trải nghiệm không gian xưa."]', 'Quanh năm, mát mẻ nhất vào mùa khô tháng 11 đến tháng 4', '1 giờ', '30.000đ', '07:00 - 17:30 hằng ngày', '["popular","verified"]', '["museum","history","culture","city"]', '[{"seed":"congtu-mansion","caption":"Dinh thự cổ kiến trúc phương Tây","ratio":"16/9"},{"seed":"congtu-interior","caption":"Nội thất gỗ quý chạm trổ tinh xảo","ratio":"4/3"},{"seed":"congtu-antiques","caption":"Cổ vật cẩn xà cừ giá trị","ratio":"1/1"}]', '["bac-lieu-canh-dong-dien-gio"]', 0);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ca-mau-mui-ca-mau', 'mui-ca-mau', 'ca-mau', 'Mũi Cà Mau', 'Ca Mau Cape', 'park', 104.7233, 8.6, 'Điểm cực Nam thiêng liêng của Tổ quốc, nơi đất rừng ngập mặn lấn biển và mặt trời mọc lặn cùng nhìn thấy.', 'Mũi Cà Mau là vùng đất cực Nam thiêng liêng của Tổ quốc, điểm mà mỗi người Việt đều mong một lần đặt chân tới. Nằm trong vườn quốc gia Mũi Cà Mau, khu Ramsar và dự trữ sinh quyển thế giới, nơi đây là vùng đất bãi bồi liên tục lấn ra biển nhờ phù sa, với rừng đước, rừng mắm ngập mặn xanh thẳm. Du khách check-in bên cột mốc tọa độ quốc gia hình con tàu, đứng trên đài quan sát phóng tầm mắt ra biển Đông và vịnh Thái Lan, nơi hiếm hoi có thể ngắm cả bình minh lẫn hoàng hôn trên biển. Đi cano xuyên rừng ngập mặn, thưởng thức cua, ba khía, ốc len tươi rói, du khách cảm nhận trọn vẹn vẻ hoang sơ và niềm tự hào nơi chót mũi đất nước.', '["Là điểm cực Nam trên đất liền của Việt Nam, thuộc vườn quốc gia Mũi Cà Mau.","Được công nhận là khu Ramsar và khu dự trữ sinh quyển thế giới.","Vùng bãi bồi liên tục lấn ra biển nhờ phù sa, mỗi năm thêm vài chục mét.","Nơi hiếm hoi có thể ngắm cả mặt trời mọc và lặn trên biển trong cùng một ngày."]', '["Check-in cột mốc tọa độ quốc gia và biểu tượng con tàu Mũi Cà Mau.","Đi cano xuyên rừng ngập mặn và thưởng thức hải sản tươi như cua, ba khía."]', 'Tháng 12 đến tháng 4, mùa khô biển êm thuận tiện đi lại', 'Nửa ngày', '50.000đ vào khu du lịch', '07:00 - 17:00 hằng ngày', '["unesco","verified","popular","trending"]', '["park","nature","photography","island"]', '[{"seed":"muicamau-landmark","caption":"Cột mốc tọa độ quốc gia cực Nam","ratio":"16/9"},{"seed":"muicamau-mangrove","caption":"Rừng đước ngập mặn xanh thẳm","ratio":"4/3"},{"seed":"muicamau-ship","caption":"Biểu tượng con tàu nơi chót mũi","ratio":"1/1"}]', '["ca-mau-rung-u-minh-ha"]', 1);
INSERT OR REPLACE INTO destinations (id, slug, province_slug, name, name_en, type, lng, lat, summary, story, facts, travel_tips, best_time, visit_duration, ticket, opening_hours, badges, tags, gallery, nearby, featured) VALUES ('ca-mau-rung-u-minh-ha', 'rung-u-minh-ha', 'ca-mau', 'Rừng U Minh Hạ', 'U Minh Ha Forest', 'park', 104.9667, 9.3167, 'Rừng tràm nguyên sinh trên đất than bùn nổi tiếng với mật ong rừng, cá đồng và hệ sinh thái độc đáo.', 'Rừng U Minh Hạ là cánh rừng tràm ngập nước nổi tiếng của Cà Mau, được công nhận là vườn quốc gia và nằm trong khu dự trữ sinh quyển thế giới. Đặc trưng của U Minh Hạ là lớp đất than bùn dày, nước có màu đỏ nâu như nước trà, nuôi dưỡng rừng tràm bạt ngàn cùng hệ động thực vật phong phú. Đây là vùng đất gắn với nghề gác kèo ong lấy mật truyền thống, với những giọt mật vàng óng thơm lừng nức tiếng. Du khách đi xuồng len qua rừng tràm tĩnh lặng, ngắm chim, câu cá đồng và thưởng thức đặc sản dân dã như cá lóc nướng trui, lươn um, mật ong rừng. U Minh Hạ là nơi cảm nhận trọn vẹn vẻ đẹp hoang sơ và đời sống mộc mạc của vùng đất phương Nam.', '["Vườn quốc gia rừng tràm trên đất than bùn, thuộc khu dự trữ sinh quyển thế giới.","Nước rừng có màu đỏ nâu như nước trà do ngấm chất từ lớp than bùn.","Nổi tiếng với nghề gác kèo ong lấy mật truyền thống lâu đời.","Hệ sinh thái phong phú với nhiều loài chim, cá đồng và động vật quý hiếm."]', '["Thử trải nghiệm ăn ong rừng và mua mật ong nguyên chất làm quà.","Đi xuồng xuyên rừng vào mùa khô để câu cá và thưởng thức ẩm thực đồng quê."]', 'Tháng 12 đến tháng 4, mùa khô thuận tiện đi rừng và bắt cá', 'Nửa ngày', '30.000đ', '07:00 - 17:00 hằng ngày', '["verified","hidden-gem","ai-recommended"]', '["park","nature","food","photography"]', '[{"seed":"uminh-tram","caption":"Rừng tràm nguyên sinh trên đất than bùn","ratio":"16/9"},{"seed":"uminh-honey","caption":"Nghề gác kèo ong lấy mật truyền thống","ratio":"4/3"},{"seed":"uminh-fishing","caption":"Câu cá đồng giữa rừng tràm","ratio":"1/1"}]', '["ca-mau-mui-ca-mau"]', 0);
PRAGMA foreign_keys = ON;
